@dataclass(frozen=True, slots=True)
class _SystemLogicLayout:
    frame: pygame.Rect
    content: pygame.Rect
    top_pane: pygame.Rect
    bottom_pane: pygame.Rect
    index_panel: pygame.Rect
    question_strip: pygame.Rect
    answer_rects: tuple[pygame.Rect, ...]


def _auditory_guide_lane(index: int) -> float:
    idx = int(index) % len(_AUDITORY_GUIDE_LANES)
    return float(_AUDITORY_GUIDE_LANES[idx])


class Screen(Protocol):
    def handle_event(self, event: pygame.event.Event) -> None: ...
    def render(self, surface: pygame.Surface) -> None: ...


class CognitiveEngine(Protocol):
    def snapshot(self) -> TestSnapshot: ...
    def can_exit(self) -> bool: ...
    def start_practice(self) -> None: ...
    def start_scored(self) -> None: ...
    def submit_answer(self, raw: str) -> bool: ...
    def update(self) -> None: ...


@dataclass(frozen=True, slots=True)
class MenuItem:
    label: str
    action: Callable[[], None]


@dataclass(slots=True)
class _ActiveActivitySession:
    activity_session_id: int
