class _OfflineTtsSpeaker:
    """Best-effort offline TTS via isolated subprocesses.

    The old in-process pyttsx3 path could hard-crash the app. This wrapper
    keeps TTS out-of-process while preserving spoken commands/chatter behavior.
    """

    _max_queue = 24
    _max_utterance_s = 12.0

    def __init__(
        self,
        *,
        rate_wpm: int = 150,
        volume: float = 0.95,
        backend_preference: tuple[str, ...] | None = None,
    ) -> None:
        self._enabled = False
        self._backends: list[str] = []
        self._backend: str | None = None
        self._pending: list[str] = []
        self._active_proc: subprocess.Popen[bytes] | None = None
        self._active_started_s = 0.0
        self._rate_wpm = max(90, min(320, int(rate_wpm)))
        self._volume = max(0.10, min(1.00, float(volume)))
        self._backend_preference = backend_preference

        if os.environ.get("CFAST_DISABLE_TTS", "0") == "1":
            return
        if os.environ.get("SDL_AUDIODRIVER", "").strip().lower() == "dummy":
            # Keep automated/headless runs silent and stable.
            return

        self._backends = self._resolve_backends()
        self._backend = self._backends[0] if self._backends else None
        self._enabled = self._backend is not None

    @property
    def enabled(self) -> bool:
        return bool(self._enabled)

    @property
    def pending_count(self) -> int:
        active = 1 if self._active_proc is not None else 0
        return active + len(self._pending)

    def set_rate_wpm(self, rate_wpm: int) -> None:
        self._rate_wpm = max(90, min(320, int(rate_wpm)))

    def speak(self, text: str) -> None:
        if not self._enabled:
            return
        phrase = " ".join(str(text).strip().split())
        if phrase == "":
            return
        if self._pending and self._pending[-1] == phrase:
            return
        self._pending.append(phrase)
        if len(self._pending) > self._max_queue:
            del self._pending[: len(self._pending) - self._max_queue]

    def update(self) -> None:
        if not self._enabled:
            return

        proc = self._active_proc
        if proc is not None:
            if proc.poll() is None:
                if (time.monotonic() - self._active_started_s) > self._max_utterance_s:
                    self._terminate_process(proc)
                    self._active_proc = None
            else:
                self._active_proc = None

        if self._active_proc is not None:
            return
        if not self._pending:
            return

        while self._pending and self._enabled:
            next_text = self._pending[0]
            launched = self._launch_process(next_text)
            if launched is not None:
                del self._pending[0]
                self._active_proc = launched
                self._active_started_s = time.monotonic()
                return
            self._drop_current_backend()

        if not self._enabled:
            self._pending.clear()

    def stop(self) -> None:
        self._pending.clear()
        proc = self._active_proc
        self._active_proc = None
        if proc is not None:
            self._terminate_process(proc)

    @staticmethod
    def _terminate_process(proc: subprocess.Popen[bytes]) -> None:
        try:
            proc.terminate()
        except Exception:
            return
        try:
            proc.wait(timeout=0.5)
        except Exception:
            try:
                proc.kill()
            except Exception:
                pass

    def _resolve_backends(self) -> list[str]:
        supported = ("pyttsx3-subprocess", "say", "powershell", "espeak")
        forced = os.environ.get("CFAST_TTS_BACKEND", "").strip().lower()
        if forced in supported and self._backend_available(forced):
            return [forced]

        candidates: list[str]
        if self._backend_preference is not None and len(self._backend_preference) > 0:
            candidates = [name for name in self._backend_preference if name in supported]
        else:
            candidates = []
            if sys.platform == "darwin":
                candidates.append("say")
            if os.name == "nt":
                candidates.append("powershell")
            candidates.extend(("pyttsx3-subprocess", "espeak"))

        seen: set[str] = set()
        resolved: list[str] = []
        for name in candidates:
            if name in seen:
                continue
            seen.add(name)
            if self._backend_available(name):
                resolved.append(name)
        return resolved

    @staticmethod
    def _backend_available(name: str) -> bool:
        if name == "say":
            return (shutil.which("say") is not None) or Path("/usr/bin/say").exists()
        if name == "powershell":
            return (shutil.which("powershell") is not None) or (shutil.which("pwsh") is not None)
        if name == "pyttsx3-subprocess":
            return importlib.util.find_spec("pyttsx3") is not None
        if name == "espeak":
            return shutil.which("espeak") is not None
        return False

    def _drop_current_backend(self) -> None:
        backend = self._backend
        if backend is None:
            self._enabled = False
            return
        self._backends = [name for name in self._backends if name != backend]
        self._backend = self._backends[0] if self._backends else None
        self._enabled = self._backend is not None

    def _launch_process(self, text: str) -> subprocess.Popen[bytes] | None:
        backend = self._backend
        if backend is None:
            return None

        try:
            if backend == "pyttsx3-subprocess":
                script = (
                    "import sys\n"
                    "txt=' '.join(sys.argv[1:]).strip()\n"
                    "import pyttsx3\n"
                    "e=pyttsx3.init()\n"
                    f"e.setProperty('rate', {self._rate_wpm})\n"
                    f"e.setProperty('volume', {self._volume:.3f})\n"
                    "e.say(txt)\n"
                    "e.runAndWait()\n"
                )
                return subprocess.Popen(
                    [sys.executable, "-c", script, text],
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                )

            if backend == "say":
                return subprocess.Popen(
                    [shutil.which("say") or "/usr/bin/say", "-r", str(self._rate_wpm), text],
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                )

            if backend == "powershell":
                ps_bin = shutil.which("powershell") or shutil.which("pwsh")
                if ps_bin is None:
                    return None
                script = (
                    "Add-Type -AssemblyName System.Speech; "
                    "$s=New-Object System.Speech.Synthesis.SpeechSynthesizer; "
                    "$s.Rate=1; "
                    f"$s.Volume={int(max(0, min(100, round(self._volume * 100))))}; "
                    "$txt=($args -join ' '); "
                    "$s.Speak($txt);"
                )
                return subprocess.Popen(
                    [ps_bin, "-NoProfile", "-NonInteractive", "-Command", script, text],
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                )

            if backend == "espeak":
                return subprocess.Popen(
                    [
                        "espeak",
                        "-s",
                        str(self._rate_wpm),
                        "-a",
                        str(int(max(10, min(200, round(self._volume * 100))))),
                        text,
                    ],
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                )
        except Exception:
            return None
        return None


class _AuditoryCapacityAudioAdapter:
    """Pygame audio adapter for Auditory Capacity cues/background.

    This stays outside deterministic core logic. It reacts to payload state
    transitions and emits local sounds only.
    """

    _sample_rate = 22050
    _amp = 32767
    _ambient_asset_manifest: tuple[tuple[str, float, float, float], ...] = (
        ("background_noise_1.wav", 0.22, 1.35, 0.10),
        ("background_noise_2.wav", 0.21, 1.20, 0.12),
        ("background_noise_3.wav", 0.21, 1.10, 0.10),
        ("background_noise_4.wav", 0.23, 1.25, 0.16),
        ("background_noise_5.wav", 0.22, 1.05, 0.18),
        ("background_noise_6.wav", 0.20, 0.98, 0.16),
        ("mature_1.wav", 0.18, 0.35, 0.85),
        ("mature_2.wav", 0.18, 0.32, 0.95),
    )
    _interrupt_asset_manifest: tuple[str, ...] = (
        "mature_distraction_1.wav",
        "mature_distraction_2.wav",
        "mature_distraction_3.wav",
        "mature_distraction_4.wav",
        "mature_distraction_5.wav",
        "mature_distraction_6.wav",
        "mature_distraction_7.wav",
        "mature_distraction_8.wav",
        "mature_distraction_9.wav",
    )
    _instructor_voice_choices: tuple[str, ...] = ("Samantha", "Alex")
    _fallback_distractor_voice = "Karen"
    _ambient_snippet_variant_count = 2
    _ambient_file_snippet_duration_s = 8.0
    _ambient_mature_snippet_duration_s = 7.5
    _ambient_noise_snippet_duration_s = 6.0

    @classmethod
    def available_noise_sources(cls) -> tuple[str, ...]:
        return tuple(filename for filename, *_rest in cls._ambient_asset_manifest)

    @staticmethod
    def format_noise_source_label(key: str | None) -> str:
        if key is None or str(key).strip() == "":
            return "Auto"
        label = str(key).strip()
        if label.endswith(".wav"):
            label = label[:-4]
        if label.startswith("bg_"):
            label = label[3:]
        if label.endswith("_loop"):
            label = label[:-5]
        return label.replace("_", " ").title()

    def __init__(self, *, session_seed: int = 0) -> None:
        self._available = False
        self._callsign_cache: dict[str, pygame.mixer.Sound] = {}
        self._sequence_cache: dict[str, pygame.mixer.Sound] = {}
        self._interrupt_sounds: list[pygame.mixer.Sound] = []
        self._session_seed = int(session_seed)
        self._interrupt_rng = random.Random(self._rng_seed("interrupt-bootstrap"))

        self._noise_sound: pygame.mixer.Sound | None = None
        self._mixer_channels = 1
        self._ambient_tracks: dict[str, _AmbientTrack] = {}
        self._ambient_snippet_bank: dict[str, tuple[pygame.mixer.Sound, ...]] = {}
        self._ambient_snippet_variant_index: dict[str, int] = {}
        self._ambient_cache_ready = False
        self._ambient_slots: list[str | None] = [None, None, None]
        self._ambient_active_sounds: list[pygame.mixer.Sound | None] = [None, None, None]
        self._ambient_recent_keys: list[str] = []
        self._ambient_target_layers = 0
        self._ambient_started_at_s = 0.0
        self._next_ambient_change_at_s = 0.0
        self._last_mature_clip_at_s = -10_000.0
        self._next_interrupt_at_s = 0.0
        self._ambient_assets_dir = (
            Path(__file__).resolve().parents[1] / "assets" / "audio" / "auditory_capacity"
        )
        self._beep_sound: pygame.mixer.Sound | None = None
        self._color_sounds: dict[str, pygame.mixer.Sound] = {}
        self._speech_cache_root = Path(tempfile.gettempdir()) / "cfast_auditory_speech"
        self._speech_sound_cache: dict[tuple[str, int, str, int, int], pygame.mixer.Sound] = {}
        self._speech_pcm_cache: dict[tuple[str, int, str], array[int]] = {}
        self._speech_phrase_cache: dict[
            tuple[str, int, tuple[str, ...], int, int], pygame.mixer.Sound
        ] = {}
        self._prepared_speech_phases: set[tuple[Phase, tuple[str, ...], str, int]] = set()
        self._instructor_voice: str = self._instructor_voice_choices[0]
        self._distractor_voice: str = self._fallback_distractor_voice
        self._instructor_cached_base_rate_wpm = 182
        self._callsign_base_rate_wpm = 168
        self._commands_base_rate_wpm = 172
        self._story_base_rate_wpm = 160
        self._instructor_rate_wpm = self._instructor_cached_base_rate_wpm
        self._instructor_noise_level = 0.0
        self._instructor_distortion_level = 0.0
        self._last_instruction_callsign: str | None = None
        self._voice_queue: list[pygame.mixer.Sound] = []
        self._speech_enabled = (
            sys.platform == "darwin"
            and ((shutil.which("say") is not None) or Path("/usr/bin/say").exists())
            and ((shutil.which("afconvert") is not None) or Path("/usr/bin/afconvert").exists())
        )

        self._bg_channel: pygame.mixer.Channel | None = None
        self._dist_channel: pygame.mixer.Channel | None = None
        self._cue_channel: pygame.mixer.Channel | None = None
        self._alert_channel: pygame.mixer.Channel | None = None
        self._fx_channel: pygame.mixer.Channel | None = None
        self._voice_channel: pygame.mixer.Channel | None = None
        self._interrupt_channel: pygame.mixer.Channel | None = None
        self._ambient_aux_channel: pygame.mixer.Channel | None = None

        self._last_callsign_cue: str | None = None
        self._last_color_command: str | None = None
        self._last_beep_active = False
        self._last_sequence_display: str | None = None
        self._last_instruction_uid: int | None = None
        self._last_assigned_callsigns: tuple[str, ...] = ()
        self._last_phase: Phase | None = None
        self._active_noise_source: str | None = None
        self._tts_callsign = _OfflineTtsSpeaker(
            rate_wpm=168,
            volume=0.22,
            backend_preference=("pyttsx3-subprocess", "say", "espeak", "powershell"),
        )
        self._tts_commands = _OfflineTtsSpeaker(rate_wpm=172, volume=0.30)
        self._tts_story = _OfflineTtsSpeaker(
            rate_wpm=160,
            volume=0.22,
            backend_preference=("pyttsx3-subprocess", "say", "espeak", "powershell"),
        )
        self._voice_rng = random.Random(self._rng_seed("voice-bootstrap"))
        self._next_chatter_at_s = 0.0
        self._story_index = -1
        self._story_segments: tuple[str, ...] = ()

        try:
            if pygame.mixer.get_init() is None:
                pygame.mixer.init(frequency=self._sample_rate, size=-16, channels=1, buffer=512)
            mix_state = pygame.mixer.get_init()
            if mix_state is not None:
                self._sample_rate = int(mix_state[0])
                self._mixer_channels = max(1, int(mix_state[2]))
            pygame.mixer.set_num_channels(max(10, int(pygame.mixer.get_num_channels())))

            self._noise_sound = self._build_noise_sound(
                duration_s=1.30,
                seed=self._rng_seed("noise-bootstrap"),
                gain=0.35,
            )
            self._ambient_tracks = self._load_ambient_tracks()
            self._prepare_ambient_snippet_bank()
            if not self._ambient_cache_ready:
                raise RuntimeError(
                    "Auditory Capacity ambient audio assets are missing or could not be loaded."
                )
            self._interrupt_sounds = self._load_interrupt_sounds()
            self._beep_sound = self._build_tone_sound(1120.0, 0.11, gain=0.42)
            self._color_sounds = {
                "RED": self._build_tone_sound(380.0, 0.14, gain=0.30),
                "GREEN": self._build_tone_sound(510.0, 0.14, gain=0.30),
                "BLUE": self._build_tone_sound(640.0, 0.14, gain=0.30),
                "YELLOW": self._build_tone_sound(780.0, 0.14, gain=0.30),
            }

            self._bg_channel = pygame.mixer.Channel(0)
            self._dist_channel = pygame.mixer.Channel(1)
            self._cue_channel = pygame.mixer.Channel(2)
            self._alert_channel = pygame.mixer.Channel(3)
            self._fx_channel = pygame.mixer.Channel(4)
            self._voice_channel = pygame.mixer.Channel(5)
            self._interrupt_channel = pygame.mixer.Channel(6)
            self._ambient_aux_channel = pygame.mixer.Channel(7)

            self._available = True
        except Exception as exc:
            self._available = False
            raise RuntimeError(
                f"Auditory Capacity audio initialization failed: {type(exc).__name__}: {exc}"
            ) from exc

    def _rng_seed(self, tag: str) -> int:
        total = int(self._session_seed) & 0xFFFFFFFF
        for ch in str(tag):
            total = ((total * 33) + ord(ch)) & 0xFFFFFFFF
        return total or 1

    def _reset_phase_rngs(self, *, phase: Phase) -> None:
        phase_key = phase.value
        self._voice_rng = random.Random(self._rng_seed(f"voice:{phase_key}"))
        self._interrupt_rng = random.Random(self._rng_seed(f"interrupt:{phase_key}"))

    def sync(self, *, phase: Phase, payload: AuditoryCapacityPayload | None) -> None:
        if payload is None or phase not in (Phase.PRACTICE, Phase.SCORED):
            self.stop()
            return

        self._sync_phase_speech_profile(phase=phase, payload=payload)
        self._drain_instructor_queue()
        self._sync_assigned_callsigns(payload=payload)
        if self._available:
            self._sync_background_layers(payload=payload)
            self._sync_distortion_layer(payload=payload)
            self._sync_interrupt_distractors(payload=payload)
        self._sync_beep_cue(payload=payload)
        self._sync_instruction_cue(payload=payload)
        if not self._speech_enabled:
            self._tts_callsign.update()
            self._tts_commands.update()

    def stop(self) -> None:
        channels = (
            self._bg_channel,
            self._dist_channel,
            self._cue_channel,
            self._alert_channel,
            self._fx_channel,
            self._voice_channel,
            self._interrupt_channel,
            self._ambient_aux_channel,
        )
        for channel in channels:
            if channel is not None:
                try:
                    channel.stop()
                except Exception:
                    pass
        self._tts_callsign.stop()
        self._tts_commands.stop()
        self._tts_story.stop()
        self._last_callsign_cue = None
        self._last_color_command = None
        self._last_beep_active = False
        self._last_sequence_display = None
        self._last_instruction_uid = None
        self._last_assigned_callsigns = ()
        self._last_phase = None
        self._last_instruction_callsign = None
        self._next_chatter_at_s = 0.0
        self._story_index = -1
        self._voice_queue = []
        self._ambient_slots = [None, None, None]
        self._ambient_active_sounds = [None, None, None]
        self._ambient_recent_keys = []
        self._ambient_snippet_variant_index = {
            key: 0 for key in self._ambient_snippet_bank
        }
        self._ambient_target_layers = 0
        self._ambient_started_at_s = 0.0
        self._next_ambient_change_at_s = 0.0
        self._last_mature_clip_at_s = -10_000.0
        self._next_interrupt_at_s = 0.0
        self._active_noise_source = None

    def debug_state(self, *, payload: AuditoryCapacityPayload | None = None) -> dict[str, object]:
        def _slot_label(key: str | None) -> str:
            if key is None or key.strip() == "":
                return "—"
            label = key
            if label.endswith(".wav"):
                label = label[:-4]
            if label.startswith("bg_"):
                label = label[3:]
            if label.endswith("_loop"):
                label = label[:-5]
            return label

        bg_busy = False
        dist_busy = False
        cue_busy = False
        alert_busy = False
        fx_busy = False
        try:
            bg_busy = bool(self._bg_channel.get_busy()) if self._bg_channel is not None else False
            dist_busy = (
                bool(self._dist_channel.get_busy()) if self._dist_channel is not None else False
            )
            cue_busy = (
                bool(self._cue_channel.get_busy()) if self._cue_channel is not None else False
            )
            alert_busy = (
                bool(self._alert_channel.get_busy()) if self._alert_channel is not None else False
            )
            fx_busy = bool(self._fx_channel.get_busy()) if self._fx_channel is not None else False
        except Exception:
            bg_busy = False
            dist_busy = False
            cue_busy = False
            alert_busy = False
            fx_busy = False

        ambient_slots = tuple(_slot_label(v) for v in self._ambient_slots)
        noise_level = None if payload is None else float(payload.background_noise_level)
        background_distortion_level = (
            None if payload is None else float(payload.background_distortion_level)
        )
        distortion_level = None if payload is None else float(payload.distortion_level)
        instructor_noise_level = (
            None if payload is None else float(payload.instructor_noise_level)
        )
        instructor_distortion_level = (
            None if payload is None else float(payload.instructor_distortion_level)
        )
        instructor_rate_wpm = None if payload is None else int(payload.instructor_rate_wpm)
        noise_source = None if payload is None else payload.background_noise_source

        return {
            "audio_available": bool(self._available),
            "session_seed": int(self._session_seed),
            "ambient_cache_ready": bool(self._ambient_cache_ready),
            "ambient_cached_tracks": int(len(self._ambient_snippet_bank)),
            "ambient_layers_target": int(self._ambient_target_layers),
            "ambient_slots": ambient_slots,
            "noise_source": self.format_noise_source_label(
                noise_source if noise_source is not None else self._active_noise_source
            ),
            "ambient_recent": tuple(_slot_label(v) for v in self._ambient_recent_keys[-3:]),
            "channels_busy": {
                "bg": bg_busy,
                "dist": dist_busy,
                "cue": cue_busy,
                "alert": alert_busy,
                "fx": fx_busy,
            },
            "cue_state": {
                "callsign": self._last_callsign_cue,
                "color": self._last_color_command,
                "beep_active": bool(self._last_beep_active),
                "sequence": self._last_sequence_display,
            },
            "tts_pending": {
                "callsign": int(self._tts_callsign.pending_count),
                "commands": int(self._tts_commands.pending_count),
                "story": int(self._tts_story.pending_count),
            },
            "noise_level": noise_level,
            "background_distortion_level": background_distortion_level,
            "distortion_level": distortion_level,
            "instructor_noise_level": instructor_noise_level,
            "instructor_distortion_level": instructor_distortion_level,
            "instructor_rate_wpm": instructor_rate_wpm,
            "speech_enabled": bool(self._speech_enabled),
            "instructor_voice": self._instructor_voice,
        }

    def _sync_phase_speech_profile(
        self,
        *,
        phase: Phase,
        payload: AuditoryCapacityPayload,
    ) -> None:
        assigned = tuple(str(v) for v in payload.assigned_callsigns)
        self._instructor_rate_wpm = max(
            90,
            min(
                320,
                int(
                    getattr(
                        payload,
                        "instructor_rate_wpm",
                        self._instructor_cached_base_rate_wpm,
                    )
                ),
            ),
        )
        self._instructor_noise_level = max(
            0.0,
            min(1.0, float(getattr(payload, "instructor_noise_level", 0.0))),
        )
        self._instructor_distortion_level = max(
            0.0,
            min(1.0, float(getattr(payload, "instructor_distortion_level", 0.0))),
        )
        rate_ratio = self._instructor_rate_wpm / float(self._instructor_cached_base_rate_wpm)
        self._tts_callsign.set_rate_wpm(int(round(self._callsign_base_rate_wpm * rate_ratio)))
        self._tts_commands.set_rate_wpm(int(round(self._commands_base_rate_wpm * rate_ratio)))
        self._tts_story.set_rate_wpm(int(round(self._story_base_rate_wpm * rate_ratio)))
        if phase != self._last_phase:
            self._reset_phase_rngs(phase=phase)
            self._instructor_voice = (
                self._instructor_voice_choices[0]
                if self._voice_rng.random() < 0.5
                else self._instructor_voice_choices[1]
            )
            self._distractor_voice = (
                self._instructor_voice_choices[1]
                if self._instructor_voice == self._instructor_voice_choices[0]
                else self._instructor_voice_choices[0]
            )
            self._last_phase = phase
            self._last_instruction_callsign = None
        self._prepare_phase_speech_cache(phase=phase, assigned_callsigns=assigned)

    def _prepare_phase_speech_cache(
        self,
        *,
        phase: Phase,
        assigned_callsigns: tuple[str, ...],
    ) -> None:
        key = (
            phase,
            assigned_callsigns,
            self._instructor_voice,
            int(self._instructor_rate_wpm),
        )
        if key in self._prepared_speech_phases:
            return
        self._prepared_speech_phases.add(key)
        if not self._speech_enabled:
            return

        callsigns = ", ".join(assigned_callsigns) if assigned_callsigns else "—"
        full_phrases = (
            f"Your call signs are {callsigns}. Respond only to those call signs.",
            "Use Q W E R for colour, keypad numbers for the ball, and type digit sequences with Enter.",
            "Press trigger or Space on the beep. Gate instructions apply to the next matching gate.",
        )
        for text in full_phrases:
            self._load_profiled_speech_sound(
                text=text,
                voice=self._instructor_voice,
                rate_wpm=self._instructor_rate_wpm,
                noise_level=self._instructor_noise_level,
                distortion_level=self._instructor_distortion_level,
            )

        token_bank = {
            "Change colour to",
            "Set number",
            "Remember digits",
            "Take the next",
            "Avoid the next",
            "gate",
            "Beep cue",
            "Press trigger or Space now",
        }
        token_bank.update(assigned_callsigns)
        token_bank.update(str(value) for value in range(10))
        token_bank.update(("RED", "GREEN", "BLUE", "YELLOW", "CIRCLE", "TRIANGLE", "SQUARE"))
        for token in sorted(token_bank):
            self._load_speech_pcm(
                text=token,
                voice=self._instructor_voice,
                rate_wpm=self._instructor_rate_wpm,
            )

    def _load_interrupt_sounds(self) -> list[pygame.mixer.Sound]:
        sounds: list[pygame.mixer.Sound] = []
        for filename in self._interrupt_asset_manifest:
            path = self._ambient_assets_dir / filename
            if not path.exists():
                continue
            try:
                sounds.append(pygame.mixer.Sound(str(path)))
            except Exception:
                continue
        return sounds

    def _sync_interrupt_distractors(self, *, payload: AuditoryCapacityPayload) -> None:
        channel = self._interrupt_channel
        if channel is None:
            return
        if payload.briefing_active or payload.background_noise_level <= 0.08 or not self._interrupt_sounds:
            if channel.get_busy():
                channel.stop()
            return

        now_s = max(0.0, float(payload.phase_elapsed_s))
        if self._next_interrupt_at_s <= 0.0:
            self._next_interrupt_at_s = now_s + 5.0
            return
        if channel.get_busy() or now_s < self._next_interrupt_at_s:
            return

        sound = self._interrupt_rng.choice(self._interrupt_sounds)
        channel.set_volume(0.18 + (0.08 * float(payload.background_noise_level)))
        channel.play(sound)
        self._next_interrupt_at_s = now_s + self._interrupt_rng.uniform(
            max(2.6, 8.4 - (4.8 * float(payload.background_noise_level))),
            max(4.0, 14.0 - (5.0 * float(payload.background_noise_level))),
        )

    @staticmethod
    def _speech_profile_buckets(
        *, noise_level: float, distortion_level: float
    ) -> tuple[int, int]:
        return (
            max(0, min(100, int(round(float(noise_level) * 100.0)))),
            max(0, min(100, int(round(float(distortion_level) * 100.0)))),
        )

    def _apply_voice_profile_to_pcm(
        self,
        *,
        samples: array[int],
        noise_level: float,
        distortion_level: float,
        seed: int,
    ) -> array[int]:
        noise_level = max(0.0, min(1.0, float(noise_level)))
        distortion_level = max(0.0, min(1.0, float(distortion_level)))
        if len(samples) == 0 or (noise_level <= 0.001 and distortion_level <= 0.001):
            return array("h", samples)

        processed = array("h", samples)
        if distortion_level > 0.001:
            crush_step = max(1, int(round(1 + (distortion_level * 28.0))))
            drive = 1.0 + (0.85 * distortion_level)
            clip_limit = int(round(32767.0 * (0.82 - (0.18 * distortion_level))))
            for idx, value in enumerate(processed):
                driven = int(round(float(value) * drive))
                if driven > clip_limit:
                    driven = clip_limit
                elif driven < -clip_limit:
                    driven = -clip_limit
                processed[idx] = int(round(driven / crush_step)) * crush_step

        if noise_level > 0.001:
            duration_s = len(processed) / float(max(1, self._sample_rate))
            noise_pcm = self._render_noise_pcm(
                duration_s=duration_s,
                seed=seed,
                gain=0.08 + (0.24 * noise_level),
            )
            if len(noise_pcm) != len(processed):
                noise_pcm = self._resample_pcm(
                    samples=noise_pcm,
                    src_rate=self._sample_rate,
                    dst_rate=self._sample_rate,
                )
            mix = 0.16 + (0.20 * noise_level)
            count = min(len(processed), len(noise_pcm))
            for idx in range(count):
                value = int(round(processed[idx] + (noise_pcm[idx] * mix)))
                processed[idx] = max(-32768, min(32767, value))

        return processed

    def _speech_wav_path(self, *, text: str, voice: str, rate_wpm: int) -> Path:
        key = f"{voice}|{int(rate_wpm)}|{text}".encode("utf-8")
        digest = hashlib.sha1(key).hexdigest()
        filename = f"{voice.lower()}-{digest}.wav"
        target = self._speech_cache_root / filename
        if target.exists():
            return target

        self._speech_cache_root.mkdir(parents=True, exist_ok=True)
        aiff_path = target.with_suffix(".aiff")
        say_bin = shutil.which("say") or "/usr/bin/say"
        afconvert_bin = shutil.which("afconvert") or "/usr/bin/afconvert"
        subprocess.run(
            [say_bin, "-v", voice, "-r", str(int(rate_wpm)), "-o", str(aiff_path), text],
            check=True,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
        )
        try:
            subprocess.run(
                [
                    afconvert_bin,
                    "-f",
                    "WAVE",
                    "-d",
                    "LEI16@22050",
                    "-c",
                    "1",
                    str(aiff_path),
                    str(target),
                ],
                check=True,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
            )
        finally:
            try:
                aiff_path.unlink()
            except FileNotFoundError:
                pass
        return target

    def _load_profiled_speech_sound(
        self,
        *,
        text: str,
        voice: str,
        rate_wpm: int,
        noise_level: float,
        distortion_level: float,
    ) -> pygame.mixer.Sound:
        noise_bucket, distortion_bucket = self._speech_profile_buckets(
            noise_level=noise_level,
            distortion_level=distortion_level,
        )
        key = (voice, int(rate_wpm), text, noise_bucket, distortion_bucket)
        cached = self._speech_sound_cache.get(key)
        if cached is not None:
            return cached

        pcm = self._load_speech_pcm(text=text, voice=voice, rate_wpm=rate_wpm)
        pcm = self._apply_voice_profile_to_pcm(
            samples=pcm,
            noise_level=noise_bucket / 100.0,
            distortion_level=distortion_bucket / 100.0,
            seed=self._rng_seed(f"speech:{voice}:{rate_wpm}:{text}"),
        )
        sound = self._sound_from_pcm(pcm) if len(pcm) > 0 else self._build_tone_sound(420.0, 0.08, gain=0.18)
        self._speech_sound_cache[key] = sound
        return sound

    def _load_speech_pcm(self, *, text: str, voice: str, rate_wpm: int) -> array[int]:
        key = (voice, int(rate_wpm), text)
        cached = self._speech_pcm_cache.get(key)
        if cached is not None:
            return array("h", cached)
        wav_path = self._speech_wav_path(text=text, voice=voice, rate_wpm=rate_wpm)
        meta = self._probe_wav_metadata(wav_path)
        if meta is None:
            return array("h")
        sample_rate, channels, frame_count = meta
        pcm = self._read_wav_segment_pcm(
            path=wav_path,
            channels=channels,
            start_frame=0,
            frame_count=frame_count,
        )
        if pcm is None:
            return array("h")
        if sample_rate != self._sample_rate:
            pcm = self._resample_pcm(samples=pcm, src_rate=sample_rate, dst_rate=self._sample_rate)
        self._speech_pcm_cache[key] = array("h", pcm)
        return array("h", pcm)

    def _build_phrase_sound_from_tokens(
        self,
        *,
        tokens: tuple[str, ...],
        voice: str,
        rate_wpm: int,
        noise_level: float,
        distortion_level: float,
    ) -> pygame.mixer.Sound:
        noise_bucket, distortion_bucket = self._speech_profile_buckets(
            noise_level=noise_level,
            distortion_level=distortion_level,
        )
        cache_key = (voice, int(rate_wpm), tokens, noise_bucket, distortion_bucket)
        cached = self._speech_phrase_cache.get(cache_key)
        if cached is not None:
            return cached
        parts: list[array[int]] = []
        for idx, token in enumerate(tokens):
            pcm = self._load_speech_pcm(text=token, voice=voice, rate_wpm=rate_wpm)
            if len(pcm) > 0:
                parts.append(pcm)
            if idx < len(tokens) - 1:
                parts.append(self._render_silence_pcm(0.045))
        if not parts:
            sound = self._build_tone_sound(420.0, 0.08, gain=0.18)
        else:
            pcm = self._apply_voice_profile_to_pcm(
                samples=self._concat_pcm(tuple(parts)),
                noise_level=noise_bucket / 100.0,
                distortion_level=distortion_bucket / 100.0,
                seed=self._rng_seed(
                    f"phrase:{voice}:{rate_wpm}:{'|'.join(tokens)}:{noise_bucket}:{distortion_bucket}"
                ),
            )
            sound = self._sound_from_pcm(pcm)
        self._speech_phrase_cache[cache_key] = sound
        return sound

    def _instruction_sound(
        self,
        *,
        payload: AuditoryCapacityPayload,
        omit_callsign: bool,
    ) -> pygame.mixer.Sound | None:
        instruction = payload.active_instruction
        if instruction is None:
            return None
        text = (payload.instruction_text or "").strip()
        if text == "":
            return None
        command = (payload.instruction_command_type or "").strip().lower()
        voice = self._instructor_voice
        rate_wpm = int(getattr(payload, "instructor_rate_wpm", self._instructor_rate_wpm))
        noise_level = float(getattr(payload, "instructor_noise_level", self._instructor_noise_level))
        distortion_level = float(
            getattr(payload, "instructor_distortion_level", self._instructor_distortion_level)
        )
        callsign = str(instruction.addressed_call_sign)
        if command == AuditoryCapacityCommandType.NO_OP_DISTRACTOR.value:
            return self._load_profiled_speech_sound(
                text=text,
                voice=voice,
                rate_wpm=rate_wpm,
                noise_level=noise_level,
                distortion_level=distortion_level,
            )
        if command == AuditoryCapacityCommandType.CHANGE_COLOUR.value:
            tokens = tuple(
                part
                for part in (
                    None if omit_callsign else callsign,
                    "Change colour to",
                    str(instruction.payload),
                )
                if part
            )
            return self._build_phrase_sound_from_tokens(
                tokens=tokens,
                voice=voice,
                rate_wpm=rate_wpm,
                noise_level=noise_level,
                distortion_level=distortion_level,
            )
        if command == AuditoryCapacityCommandType.CHANGE_NUMBER.value:
            tokens = tuple(
                part
                for part in (
                    None if omit_callsign else callsign,
                    "Set number",
                    str(instruction.payload),
                )
                if part
            )
            return self._build_phrase_sound_from_tokens(
                tokens=tokens,
                voice=voice,
                rate_wpm=rate_wpm,
                noise_level=noise_level,
                distortion_level=distortion_level,
            )
        if command == AuditoryCapacityCommandType.GATE_DIRECTIVE.value:
            directive = instruction.payload
            if not isinstance(directive, AuditoryCapacityGateDirective):
                return self._load_profiled_speech_sound(
                    text=text,
                    voice=voice,
                    rate_wpm=rate_wpm,
                    noise_level=noise_level,
                    distortion_level=distortion_level,
                )
            parts: list[str] = []
            if not omit_callsign:
                parts.append(callsign)
            if str(directive.action).upper() == "AVOID":
                parts.extend(("Avoid the next", str(directive.match_value), "gate"))
                return self._build_phrase_sound_from_tokens(
                    tokens=tuple(parts),
                    voice=voice,
                    rate_wpm=rate_wpm,
                    noise_level=noise_level,
                    distortion_level=distortion_level,
                )
            parts.extend(("Take the next", str(directive.match_value), "gate"))
            return self._build_phrase_sound_from_tokens(
                tokens=tuple(parts),
                voice=voice,
                rate_wpm=rate_wpm,
                noise_level=noise_level,
                distortion_level=distortion_level,
            )
        if command == AuditoryCapacityCommandType.DIGIT_SEQUENCE.value:
            digits = [ch for ch in str(instruction.payload) if ch.isdigit()]
            parts = []
            if not omit_callsign:
                parts.append(callsign)
            parts.append("Remember digits")
            parts.extend(digits)
            return self._build_phrase_sound_from_tokens(
                tokens=tuple(parts),
                voice=voice,
                rate_wpm=rate_wpm,
                noise_level=noise_level,
                distortion_level=distortion_level,
            )
        return self._load_profiled_speech_sound(
            text=text,
            voice=voice,
            rate_wpm=rate_wpm,
            noise_level=noise_level,
            distortion_level=distortion_level,
        )

    def _play_instructor_sound(self, sound: pygame.mixer.Sound) -> None:
        self._play_instructor_sound_queued(sound)

    def _play_instructor_sound_queued(
        self,
        sound: pygame.mixer.Sound,
        *,
        replace_pending: bool = False,
    ) -> None:
        if not self._available or self._voice_channel is None:
            return
        if replace_pending:
            self._voice_queue.clear()
        self._voice_queue.append(sound)
        self._drain_instructor_queue()

    def _drain_instructor_queue(self) -> None:
        if not self._available or self._voice_channel is None:
            return
        if self._voice_channel.get_busy() or not self._voice_queue:
            return
        sound = self._voice_queue.pop(0)
        self._voice_channel.set_volume(0.32)
        self._voice_channel.play(sound)

    def _sync_background_layers(self, *, payload: AuditoryCapacityPayload) -> None:
        assert self._bg_channel is not None
        assert self._dist_channel is not None
        if not self._ambient_tracks or not self._ambient_snippet_bank:
            return
        channels = tuple(
            channel
            for channel in (
                self._bg_channel,
                self._dist_channel,
                self._ambient_aux_channel,
            )
            if channel is not None
        )
        if payload.briefing_active or float(payload.background_noise_level) <= 0.001:
            for idx, channel in enumerate(channels):
                if idx < len(self._ambient_slots):
                    self._ambient_slots[idx] = None
                    self._ambient_active_sounds[idx] = None
                channel.set_volume(0.0)
                if channel.get_busy():
                    channel.stop()
            for idx in range(len(channels), len(self._ambient_slots)):
                self._ambient_slots[idx] = None
                self._ambient_active_sounds[idx] = None
            self._ambient_target_layers = 0
            return

        now_s = max(0.0, float(payload.phase_elapsed_s))
        if self._ambient_started_at_s <= 0.0:
            self._ambient_started_at_s = now_s

        replanned = False
        if self._next_ambient_change_at_s <= 0.0 or now_s >= self._next_ambient_change_at_s:
            self._replan_ambient_mix(now_s=now_s, payload=payload)
            replanned = True

        noise_level = max(0.0, min(1.0, float(payload.background_noise_level)))
        elapsed_ratio = max(0.0, min(1.0, (now_s - self._ambient_started_at_s) / 240.0))

        for idx, channel in enumerate(channels):
            active_key = self._ambient_slots[idx]
            should_play = (idx < self._ambient_target_layers) or channel.get_busy()
            if not should_play:
                self._ambient_slots[idx] = None
                self._ambient_active_sounds[idx] = None
                channel.set_volume(0.0)
                if channel.get_busy():
                    channel.stop()
                continue

            if idx >= self._ambient_target_layers:
                if active_key is None:
                    self._ambient_active_sounds[idx] = None
                    channel.set_volume(0.0)
                    if channel.get_busy():
                        channel.stop()
                    continue
            elif replanned:
                self._ambient_slots[idx] = None
                self._ambient_active_sounds[idx] = None
                active_key = None
                if channel.get_busy():
                    channel.stop()

            if active_key is not None and (
                active_key not in self._ambient_tracks or active_key not in self._ambient_snippet_bank
            ):
                self._ambient_slots[idx] = None
                self._ambient_active_sounds[idx] = None
                active_key = None
                if channel.get_busy():
                    channel.stop()

            if idx < self._ambient_target_layers and active_key is None:
                exclude = tuple(
                    str(slot_key)
                    for slot_idx, slot_key in enumerate(self._ambient_slots[: len(channels)])
                    if slot_idx != idx and slot_key is not None
                )
                next_key = self._pick_ambient_key(
                    elapsed_ratio=elapsed_ratio,
                    now_s=now_s,
                    exclude=exclude,
                    forced_source=payload.background_noise_source,
                )
                if next_key is None or next_key not in self._ambient_snippet_bank:
                    self._ambient_slots[idx] = None
                    self._ambient_active_sounds[idx] = None
                    channel.set_volume(0.0)
                    if channel.get_busy():
                        channel.stop()
                    continue

                self._ambient_slots[idx] = next_key
                active_key = next_key
                self._ambient_recent_keys.append(next_key)
                if len(self._ambient_recent_keys) > 6:
                    del self._ambient_recent_keys[:-6]
                if "mature" in next_key.lower():
                    self._last_mature_clip_at_s = now_s

            if active_key is None:
                self._ambient_active_sounds[idx] = None
                if channel.get_busy():
                    channel.stop()
                continue

            if not channel.get_busy():
                snippet_sound = self._next_cached_ambient_sound(active_key)
                if snippet_sound is None:
                    self._ambient_slots[idx] = None
                    self._ambient_active_sounds[idx] = None
                    channel.set_volume(0.0)
                    continue
                self._ambient_active_sounds[idx] = snippet_sound
                channel.play(snippet_sound)
            self._active_noise_source = active_key

            item = self._ambient_tracks.get(active_key)
            if item is None:
                self._ambient_slots[idx] = None
                self._ambient_active_sounds[idx] = None
                if channel.get_busy():
                    channel.stop()
                continue

            base_volume = float(item.base_volume)
            # Keep early-phase ambience noticeably quieter and ramp toward full intensity.
            intensity = 0.30 + (0.70 * noise_level)
            layer_gain = intensity
            volume = max(0.0, min(1.0, base_volume * layer_gain))
            channel.set_volume(volume)

        for idx in range(len(channels), len(self._ambient_slots)):
            self._ambient_slots[idx] = None
            self._ambient_active_sounds[idx] = None

    def _sync_distortion_layer(self, *, payload: AuditoryCapacityPayload) -> None:
        if self._fx_channel is None or self._noise_sound is None:
            return
        distortion_level = max(
            0.0,
            min(1.0, float(getattr(payload, "background_distortion_level", payload.distortion_level))),
        )
        if distortion_level <= 0.001:
            if self._fx_channel.get_busy():
                self._fx_channel.stop()
            return
        if not self._fx_channel.get_busy():
            self._fx_channel.play(self._noise_sound, loops=-1)
        self._fx_channel.set_volume(0.05 + (0.28 * distortion_level))

    def _load_ambient_tracks(self) -> dict[str, _AmbientTrack]:
        tracks: dict[str, _AmbientTrack] = {}

        for filename, base_volume, base_weight, late_weight in self._ambient_asset_manifest:
            path = self._ambient_assets_dir / filename
            meta = self._probe_wav_metadata(path)
            if meta is None:
                continue
            sample_rate, channels, frame_count = meta
            tracks[filename] = _AmbientTrack(
                path=path,
                base_volume=float(base_volume),
                base_weight=float(base_weight),
                late_weight=float(late_weight),
                sample_rate=sample_rate,
                channels=channels,
                frame_count=frame_count,
                is_generated_noise=False,
            )

        return tracks

    def _build_generated_noise_ambient_track(self) -> _AmbientTrack:
        return _AmbientTrack(
            path=None,
            base_volume=0.22,
            base_weight=1.00,
            late_weight=0.00,
            sample_rate=self._sample_rate,
            channels=1,
            frame_count=max(
                1, int(self._sample_rate * self._ambient_noise_snippet_duration_s)
            ),
            is_generated_noise=True,
        )

    def _ambient_snippet_duration_for_key(self, key: str, *, track: _AmbientTrack) -> float:
        if track.is_generated_noise:
            return float(self._ambient_noise_snippet_duration_s)
        if "mature" in key.lower():
            return float(self._ambient_mature_snippet_duration_s)
        return float(self._ambient_file_snippet_duration_s)

    def _prepare_ambient_snippet_bank(self) -> None:
        prepared_tracks: dict[str, _AmbientTrack] = {}
        prepared_bank: dict[str, tuple[pygame.mixer.Sound, ...]] = {}

        for key, track in self._ambient_tracks.items():
            duration_s = self._ambient_snippet_duration_for_key(key, track=track)
            variants: list[pygame.mixer.Sound] = []
            for _ in range(self._ambient_snippet_variant_count):
                sound = self._build_ambient_snippet_sound(
                    key,
                    elapsed_ratio=0.0,
                    duration_s=duration_s,
                )
                if sound is None:
                    variants = []
                    break
                variants.append(sound)
            if variants:
                prepared_tracks[key] = track
                prepared_bank[key] = tuple(variants)

        self._ambient_tracks = prepared_tracks
        self._ambient_snippet_bank = prepared_bank
        self._ambient_snippet_variant_index = {
            key: 0 for key in self._ambient_snippet_bank
        }
        self._ambient_cache_ready = bool(self._ambient_snippet_bank)

    def _next_cached_ambient_sound(self, key: str) -> pygame.mixer.Sound | None:
        bank = self._ambient_snippet_bank.get(key)
        if not bank:
            return None
        next_index = int(self._ambient_snippet_variant_index.get(key, 0))
        sound = bank[next_index % len(bank)]
        self._ambient_snippet_variant_index[key] = (next_index + 1) % len(bank)
        return sound

    @staticmethod
    def _probe_wav_metadata(path: Path) -> tuple[int, int, int] | None:
        if not path.exists():
            return None
        try:
            with wave.open(str(path), "rb") as wav_file:
                channels = int(wav_file.getnchannels())
                sample_width = int(wav_file.getsampwidth())
                sample_rate = int(wav_file.getframerate())
                frame_count = int(wav_file.getnframes())
        except Exception:
            return None
        if sample_width != 2 or channels <= 0 or frame_count <= 0 or sample_rate <= 0:
            return None
        return sample_rate, channels, frame_count

    @staticmethod
    def _resample_pcm(*, samples: array[int], src_rate: int, dst_rate: int) -> array[int]:
        if src_rate <= 0 or dst_rate <= 0 or len(samples) == 0:
            return array("h")
        if src_rate == dst_rate:
            return array("h", samples)

        out_count = max(1, int(round((len(samples) * dst_rate) / float(src_rate))))
        out = array("h")
        max_src = len(samples) - 1
        for idx in range(out_count):
            src_idx = int((idx * src_rate) / float(dst_rate))
            if src_idx < 0:
                src_idx = 0
            if src_idx > max_src:
                src_idx = max_src
            out.append(int(samples[src_idx]))
        return out

    def _replan_ambient_mix(self, *, now_s: float, payload: AuditoryCapacityPayload) -> None:
        if not self._ambient_tracks:
            self._next_ambient_change_at_s = now_s + 5.0
            return

        available_channels = sum(
            1
            for channel in (
                self._bg_channel,
                self._dist_channel,
                self._ambient_aux_channel,
            )
            if channel is not None
        )
        elapsed_s = max(0.0, now_s - self._ambient_started_at_s)
        elapsed_ratio = max(0.0, min(1.0, elapsed_s / 240.0))
        noise_level = max(0.0, min(1.0, float(payload.background_noise_level)))
        if payload.briefing_active or noise_level <= 0.001:
            self._ambient_target_layers = 0
            self._next_ambient_change_at_s = now_s + 2.0
            return
        forced_source = str(payload.background_noise_source or "").strip()
        desired_layers = max(0, int(getattr(payload, "ambient_layer_target", 1)))
        desired_layers = min(desired_layers, len(self._ambient_tracks), available_channels)
        if forced_source:
            self._ambient_target_layers = 0 if noise_level <= 0.001 else min(1, desired_layers)
            self._next_ambient_change_at_s = now_s + 12.0
            return

        roll = self._voice_rng.random()
        if desired_layers <= 1:
            silence_prob = max(0.01, 0.12 - (0.05 * elapsed_ratio) - (0.04 * noise_level))
            target_count = 0 if roll < silence_prob else 1
        elif desired_layers == 2:
            silence_prob = max(0.01, 0.08 - (0.03 * elapsed_ratio) - (0.03 * noise_level))
            two_prob = min(0.88, 0.20 + (0.26 * elapsed_ratio) + (0.42 * noise_level))
            one_prob = max(0.0, 1.0 - silence_prob - two_prob)
            if roll < silence_prob:
                target_count = 0
            elif roll < (silence_prob + one_prob):
                target_count = 1
            else:
                target_count = 2
        else:
            silence_prob = max(0.01, 0.05 - (0.02 * elapsed_ratio) - (0.02 * noise_level))
            three_prob = min(0.78, 0.28 + (0.26 * elapsed_ratio) + (0.34 * noise_level))
            two_prob = min(0.45, 0.22 + (0.10 * elapsed_ratio) + (0.14 * noise_level))
            one_prob = max(0.0, 1.0 - silence_prob - two_prob - three_prob)
            if roll < silence_prob:
                target_count = 0
            elif roll < (silence_prob + one_prob):
                target_count = 1
            elif roll < (silence_prob + one_prob + two_prob):
                target_count = 2
            else:
                target_count = 3
        self._ambient_target_layers = min(target_count, len(self._ambient_tracks), available_channels)

        if self._ambient_target_layers == 0:
            window_s = self._voice_rng.uniform(8.0, 22.0)
        elif self._ambient_target_layers == 1:
            window_s = self._voice_rng.uniform(70.0, 150.0) - (10.0 * noise_level)
        elif self._ambient_target_layers == 2:
            window_s = self._voice_rng.uniform(55.0, 120.0) - (8.0 * noise_level)
        else:
            window_s = self._voice_rng.uniform(38.0, 90.0) - (6.0 * noise_level)
        self._next_ambient_change_at_s = now_s + max(6.0, float(window_s))

    def _pick_ambient_key(
        self,
        *,
        elapsed_ratio: float,
        now_s: float,
        exclude: tuple[str, ...] | str | None = None,
        forced_source: str | None = None,
    ) -> str | None:
        excluded = (
            {str(exclude)}
            if isinstance(exclude, str)
            else {str(value) for value in exclude or () if str(value).strip() != ""}
        )
        forced = str(forced_source or "").strip()
        if forced:
            if forced in self._ambient_tracks and forced not in excluded:
                return forced
            if forced in self._ambient_tracks:
                return forced
        keys = [k for k in self._ambient_tracks if k not in excluded]
        if self._ambient_recent_keys:
            filtered = [k for k in keys if k not in self._ambient_recent_keys]
            if filtered:
                keys = filtered
        if not keys:
            keys = list(self._ambient_tracks.keys())
        if not keys:
            return None

        total_weight = 0.0
        weighted: list[tuple[str, float]] = []
        for key in keys:
            track = self._ambient_tracks[key]
            base_weight = float(track.base_weight)
            late_weight = float(track.late_weight)
            weight = max(0.001, base_weight + (late_weight * elapsed_ratio))
            weighted.append((key, weight))
            total_weight += weight

        pick = self._voice_rng.uniform(0.0, total_weight)
        running = 0.0
        for key, weight in weighted:
            running += weight
            if running >= pick:
                return key
        return weighted[-1][0]

    def _build_ambient_snippet_sound(
        self,
        key: str,
        *,
        elapsed_ratio: float,
        duration_s: float | None = None,
    ) -> pygame.mixer.Sound | None:
        track = self._ambient_tracks.get(key)
        if track is None:
            return None
        _ = elapsed_ratio
        if duration_s is None:
            duration_s = self._ambient_snippet_duration_for_key(key, track=track)
        length_s = max(0.25, float(duration_s))
        target_take_samples = max(256, int(length_s * self._sample_rate))
        if track.is_generated_noise:
            seed = self._voice_rng.randint(0, 2_147_483_647)
            segment = self._render_noise_pcm(duration_s=length_s, seed=seed, gain=0.34)
            if len(segment) > target_take_samples:
                segment = array("h", segment[:target_take_samples])
        else:
            if track.path is None or track.frame_count <= 1:
                return None

            source_take_frames = min(
                track.frame_count,
                max(64, int(length_s * track.sample_rate)),
            )
            start_limit = max(0, track.frame_count - source_take_frames)
            start_frame = 0 if start_limit <= 0 else self._voice_rng.randint(0, start_limit)

            source_pcm = self._read_wav_segment_pcm(
                path=track.path,
                channels=track.channels,
                start_frame=start_frame,
                frame_count=source_take_frames,
            )
            if source_pcm is None or len(source_pcm) <= 32:
                return None

            segment = source_pcm
            if track.sample_rate != self._sample_rate:
                segment = self._resample_pcm(
                    samples=segment,
                    src_rate=track.sample_rate,
                    dst_rate=self._sample_rate,
                )
            if len(segment) <= 32:
                return None
            if len(segment) > target_take_samples:
                segment = array("h", segment[:target_take_samples])

        self._apply_edge_fade(segment, fade_s=0.012)
        self._normalize_segment_level(segment, target_rms=5600.0, peak_ceiling=0.88)
        if len(segment) <= 0:
            return None
        try:
            return self._sound_from_pcm(segment)
        except Exception:
            return None

    def _extend_segment_with_variation(
        self,
        *,
        source: array[int],
        target_count: int,
        source_key: str,
        elapsed_ratio: float,
    ) -> array[int]:
        if len(source) <= 0 or target_count <= 0:
            return array("h")
        if len(source) >= target_count:
            return array("h", source[:target_count])

        out = array("h")
        source_n = len(source)
        min_chunk = max(128, int(self._sample_rate * 0.35))
        max_chunk = max(min_chunk + 64, int(self._sample_rate * 1.40))

        while len(out) < target_count:
            remaining = target_count - len(out)
            chunk_n = min(remaining, self._voice_rng.randint(min_chunk, max_chunk))

            donor = None
            if self._voice_rng.random() < 0.38:
                donor = self._sample_donor_chunk(
                    source_key=source_key,
                    target_samples=chunk_n,
                    elapsed_ratio=elapsed_ratio,
                )

            if donor is not None and len(donor) > 0:
                frag = donor
            else:
                if source_n <= chunk_n:
                    start = 0
                    frag = array("h", source)
                else:
                    start = self._voice_rng.randint(0, source_n - chunk_n)
                    frag = array("h", source[start : start + chunk_n])

            if self._voice_rng.random() < 0.20:
                frag.reverse()

            gain = self._voice_rng.uniform(0.90, 1.08)
            for idx, value in enumerate(frag):
                scaled = int(round(float(value) * gain))
                frag[idx] = max(-32768, min(32767, scaled))

            self._apply_edge_fade(frag, fade_s=0.006)
            out.extend(frag[:remaining])

        return out

    def _sample_donor_chunk(
        self,
        *,
        source_key: str,
        target_samples: int,
        elapsed_ratio: float,
    ) -> array[int] | None:
        candidate_keys = [k for k in self._ambient_tracks if k != source_key]
        if not candidate_keys:
            return None

        if self._ambient_recent_keys:
            filtered = [k for k in candidate_keys if k not in self._ambient_recent_keys]
            if filtered:
                candidate_keys = filtered

        key = self._voice_rng.choice(candidate_keys)
        track = self._ambient_tracks.get(key)
        if track is None:
            return None

        if track.is_generated_noise:
            seed = self._voice_rng.randint(0, 2_147_483_647)
            return self._render_noise_pcm(
                duration_s=max(0.10, target_samples / float(self._sample_rate)),
                seed=seed,
                gain=0.30,
            )

        if track.path is None or track.frame_count <= 1:
            return None

        desired_frames = max(
            32, int((target_samples / float(self._sample_rate)) * track.sample_rate)
        )
        desired_frames = min(desired_frames, track.frame_count)
        if desired_frames <= 0:
            return None

        if desired_frames >= track.frame_count:
            start_frame = 0
        else:
            start_frame = self._voice_rng.randint(0, track.frame_count - desired_frames)

        pcm = self._read_wav_segment_pcm(
            path=track.path,
            channels=track.channels,
            start_frame=start_frame,
            frame_count=desired_frames,
        )
        if pcm is None or len(pcm) <= 0:
            return None

        if track.sample_rate != self._sample_rate:
            pcm = self._resample_pcm(
                samples=pcm, src_rate=track.sample_rate, dst_rate=self._sample_rate
            )
        if len(pcm) <= 0:
            return None
        if len(pcm) > target_samples:
            return array("h", pcm[:target_samples])
        return pcm

    @staticmethod
    def _read_wav_segment_pcm(
        *,
        path: Path,
        channels: int,
        start_frame: int,
        frame_count: int,
    ) -> array[int] | None:
        try:
            with wave.open(str(path), "rb") as wav_file:
                wav_file.setpos(max(0, int(start_frame)))
                raw = wav_file.readframes(max(1, int(frame_count)))
        except Exception:
            return None

        if not raw:
            return None

        samples = array("h")
        samples.frombytes(raw)
        if len(samples) <= 0:
            return None

        if channels <= 1:
            return samples

        mono = array("h")
        step = max(1, int(channels))
        for idx in range(0, len(samples), step):
            acc = 0
            used = 0
            for c in range(step):
                pos = idx + c
                if pos >= len(samples):
                    break
                acc += int(samples[pos])
                used += 1
            if used > 0:
                mono.append(int(acc / used))
        return mono if len(mono) > 0 else None

    def _apply_edge_fade(self, samples: array[int], *, fade_s: float) -> None:
        if len(samples) <= 2:
            return
        fade_n = max(1, int(self._sample_rate * max(0.001, float(fade_s))))
        fade_n = min(fade_n, len(samples) // 2)
        if fade_n <= 0:
            return
        for idx in range(fade_n):
            gain = idx / float(fade_n)
            head = int(samples[idx] * gain)
            tail_idx = len(samples) - idx - 1
            tail = int(samples[tail_idx] * gain)
            samples[idx] = max(-32768, min(32767, head))
            samples[tail_idx] = max(-32768, min(32767, tail))

    @staticmethod
    def _normalize_segment_level(
        samples: array[int], *, target_rms: float, peak_ceiling: float
    ) -> None:
        if len(samples) <= 0:
            return
        peak = 0
        energy = 0.0
        for value in samples:
            v = abs(int(value))
            if v > peak:
                peak = v
            energy += float(value) * float(value)
        if peak <= 0:
            return

        rms = math.sqrt(energy / float(len(samples)))
        if rms <= 1e-6:
            return

        desired_gain = float(target_rms) / rms
        peak_limit = max(0.05, min(0.99, float(peak_ceiling))) * 32767.0
        max_gain = peak_limit / float(peak)
        gain = max(0.05, min(desired_gain, max_gain))

        for idx, value in enumerate(samples):
            out = int(round(float(value) * gain))
            samples[idx] = max(-32768, min(32767, out))

    def _sync_assigned_callsigns(self, *, payload: AuditoryCapacityPayload) -> None:
        assigned = tuple(str(v) for v in payload.assigned_callsigns)
        if assigned != self._last_assigned_callsigns and assigned:
            if not payload.briefing_active:
                joined = ", ".join(assigned)
                text = f"Assigned call signs. {joined}."
                if self._speech_enabled:
                    self._play_instructor_sound(
                        self._load_profiled_speech_sound(
                            text=text,
                            voice=self._instructor_voice,
                            rate_wpm=self._instructor_rate_wpm,
                            noise_level=self._instructor_noise_level,
                            distortion_level=self._instructor_distortion_level,
                        )
                    )
                else:
                    self._tts_callsign.speak(text)
            self._last_assigned_callsigns = assigned

    def _sync_callsign_cue(self, *, payload: AuditoryCapacityPayload) -> None:
        _ = payload
        self._last_callsign_cue = None

    def _sync_beep_cue(self, *, payload: AuditoryCapacityPayload) -> None:
        active = bool(payload.beep_active)
        if active and not self._last_beep_active and self._beep_sound is not None:
            assert self._alert_channel is not None
            self._alert_channel.set_volume(0.58)
            self._alert_channel.play(self._beep_sound)
        self._last_beep_active = active

    def _sync_color_cue(self, *, payload: AuditoryCapacityPayload) -> None:
        _ = payload
        self._last_color_command = None

    def _sync_sequence_cue(self, *, payload: AuditoryCapacityPayload) -> None:
        _ = payload
        self._last_sequence_display = None

    def _sync_instruction_cue(self, *, payload: AuditoryCapacityPayload) -> None:
        uid = payload.instruction_uid
        text = payload.instruction_text
        cmd = (payload.instruction_command_type or "").strip().lower()
        if uid is None or not text:
            self._last_instruction_uid = None
            return
        if uid == self._last_instruction_uid:
            return
        if cmd == AuditoryCapacityCommandType.PRESS_TRIGGER.value:
            self._last_instruction_uid = uid
            return
        if self._speech_enabled:
            instruction = payload.active_instruction
            callsign = None if instruction is None else str(instruction.addressed_call_sign)
            omit_callsign = bool(callsign) and callsign == self._last_instruction_callsign
            try:
                sound = self._instruction_sound(payload=payload, omit_callsign=omit_callsign)
            except Exception:
                sound = None
            if sound is not None:
                self._play_instructor_sound_queued(
                    sound,
                    replace_pending=not bool(payload.briefing_active),
                )
                self._last_instruction_callsign = callsign
            else:
                self._tts_commands.speak(text)
        else:
            self._tts_commands.speak(text)
        self._last_instruction_uid = uid

    def _play_cue(self, sound: pygame.mixer.Sound, *, volume: float) -> None:
        if not self._available:
            return
        assert self._cue_channel is not None
        self._cue_channel.set_volume(max(0.0, min(1.0, volume)))
        self._cue_channel.play(sound)

    def _build_callsign_sound(self, callsign: str) -> pygame.mixer.Sound:
        code = sum(ord(ch) for ch in callsign)
        freq_a = 290.0 + (code % 380)
        freq_b = 430.0 + ((code // 3) % 440)
        pcm = self._concat_pcm(
            (
                self._render_tone_pcm(freq_a, 0.10, gain=0.35),
                self._render_silence_pcm(0.030),
                self._render_tone_pcm(freq_b, 0.15, gain=0.33),
            )
        )
        return self._sound_from_pcm(pcm)

    def _build_sequence_sound(self, sequence: str) -> pygame.mixer.Sound:
        dtmf = {
            "0": 330.0,
            "1": 350.0,
            "2": 390.0,
            "3": 430.0,
            "4": 470.0,
            "5": 510.0,
            "6": 560.0,
            "7": 610.0,
            "8": 670.0,
            "9": 730.0,
        }
        parts: list[array[int]] = []
        digits = [ch for ch in str(sequence) if ch.isdigit()]
        for digit in digits:
            freq = dtmf.get(digit, 420.0)
            parts.append(self._render_tone_pcm(freq, 0.075, gain=0.32))
            parts.append(self._render_silence_pcm(0.020))
        if not parts:
            parts.append(self._render_tone_pcm(420.0, 0.08, gain=0.28))
        pcm = self._concat_pcm(tuple(parts))
        return self._sound_from_pcm(pcm)

    def _build_noise_sound(
        self,
        *,
        duration_s: float,
        seed: int,
        gain: float,
    ) -> pygame.mixer.Sound:
        pcm = self._render_noise_pcm(duration_s=duration_s, seed=seed, gain=gain)
        return self._sound_from_pcm(pcm)

    def _render_noise_pcm(self, *, duration_s: float, seed: int, gain: float) -> array[int]:
        rng = random.Random(int(seed))
        sample_count = max(1, int(self._sample_rate * duration_s))
        out = array("h")
        smooth = 0.0
        for _ in range(sample_count):
            raw = rng.uniform(-1.0, 1.0)
            smooth = (smooth * 0.86) + (raw * 0.14)
            sample = int(max(-1.0, min(1.0, smooth * gain)) * self._amp)
            out.append(sample)
        return out

    def _build_tone_sound(
        self, frequency_hz: float, duration_s: float, *, gain: float
    ) -> pygame.mixer.Sound:
        pcm = self._render_tone_pcm(frequency_hz, duration_s, gain=gain)
        return self._sound_from_pcm(pcm)

    def _render_tone_pcm(
        self, frequency_hz: float, duration_s: float, *, gain: float
    ) -> array[int]:
        sample_count = max(1, int(self._sample_rate * duration_s))
        fade_n = max(1, int(self._sample_rate * 0.008))
        out = array("h")
        for idx in range(sample_count):
            envelope = 1.0
            if idx < fade_n:
                envelope = idx / float(fade_n)
            tail = sample_count - idx - 1
            if tail < fade_n:
                envelope = min(envelope, tail / float(fade_n))
            phase = (2.0 * math.pi * float(frequency_hz) * idx) / float(self._sample_rate)
            sample = math.sin(phase) * gain * max(0.0, envelope)
            out.append(int(max(-1.0, min(1.0, sample)) * self._amp))
        return out

    def _render_silence_pcm(self, duration_s: float) -> array[int]:
        sample_count = max(1, int(self._sample_rate * duration_s))
        return array("h", [0] * sample_count)

    @staticmethod
    def _concat_pcm(parts: tuple[array[int], ...]) -> array[int]:
        out = array("h")
        for part in parts:
            out.extend(part)
        return out

    def _sound_from_pcm(self, mono_pcm: array[int]) -> pygame.mixer.Sound:
        pcm = self._to_mixer_channels(mono_pcm)
        return pygame.mixer.Sound(buffer=pcm.tobytes())

    def _to_mixer_channels(self, mono_pcm: array[int]) -> array[int]:
        channels = max(1, int(self._mixer_channels))
        if channels == 1:
            return mono_pcm

        interleaved = array("h")
        for sample in mono_pcm:
            val = int(sample)
            for _ in range(channels):
                interleaved.append(val)
        return interleaved


WINDOW_SIZE = (960, 540)
TARGET_FPS = 60


_AuditoryGlScene = AuditoryGlScene


class _OpenGLSceneRenderer:
    """Optional OpenGL renderer for the Auditory Capacity tube scene.

    This keeps deterministic engine logic unchanged and only replaces the tube viewport
    draw path when OpenGL is available.
    """

    def __init__(self, *, window_size: tuple[int, int]) -> None:
        from OpenGL import GL as gl  # type: ignore[import-not-found]

        self._gl = gl
        self._win_w = max(1, int(window_size[0]))
        self._win_h = max(1, int(window_size[1]))

        tex = gl.glGenTextures(1)
        if isinstance(tex, (tuple, list)):
            tex = tex[0]
        self._ui_texture_id = int(tex)
        self._ui_tex_size: tuple[int, int] = (0, 0)
        self._vortex_texture_id = self._create_texture_id()
        self._vortex_tex_size: tuple[int, int] = (0, 0)
        self._vortex_rgba: bytes = b""
        self._last_scene_debug: dict[str, object] = {
            "kind": "none",
            "entity_count": 0,
            "viewport": (self._win_w, self._win_h),
        }
        self._init_vortex_texture(size=640)

        gl.glDisable(gl.GL_CULL_FACE)
        gl.glDisable(gl.GL_LIGHTING)
        gl.glEnable(gl.GL_BLEND)
        gl.glBlendFunc(gl.GL_SRC_ALPHA, gl.GL_ONE_MINUS_SRC_ALPHA)
        gl.glEnable(gl.GL_LINE_SMOOTH)
        if hasattr(gl, "GL_LINE_SMOOTH_HINT") and hasattr(gl, "GL_NICEST"):
            gl.glHint(gl.GL_LINE_SMOOTH_HINT, gl.GL_NICEST)
        if hasattr(gl, "GL_MULTISAMPLE"):
            gl.glEnable(gl.GL_MULTISAMPLE)
        gl.glLineWidth(1.0)

    def _create_texture_id(self) -> int:
        tex = self._gl.glGenTextures(1)
        if isinstance(tex, (tuple, list)):
            tex = tex[0]
        return int(tex)

    def _init_vortex_texture(self, *, size: int) -> None:
        gl = self._gl
        tex_size = max(64, int(size))
        self._vortex_rgba = self._build_vortex_rgba(size=tex_size)
        self._vortex_tex_size = (tex_size, tex_size)

        gl.glBindTexture(gl.GL_TEXTURE_2D, self._vortex_texture_id)
        gl.glTexParameteri(gl.GL_TEXTURE_2D, gl.GL_TEXTURE_MIN_FILTER, gl.GL_LINEAR)
        gl.glTexParameteri(gl.GL_TEXTURE_2D, gl.GL_TEXTURE_MAG_FILTER, gl.GL_LINEAR)
        gl.glTexParameteri(gl.GL_TEXTURE_2D, gl.GL_TEXTURE_WRAP_S, gl.GL_REPEAT)
        gl.glTexParameteri(gl.GL_TEXTURE_2D, gl.GL_TEXTURE_WRAP_T, gl.GL_REPEAT)
        gl.glTexImage2D(
            gl.GL_TEXTURE_2D,
            0,
            gl.GL_RGBA,
            tex_size,
            tex_size,
            0,
            gl.GL_RGBA,
            gl.GL_UNSIGNED_BYTE,
            self._vortex_rgba,
        )

    @staticmethod
    def _build_vortex_rgba(*, size: int) -> bytes:
        n = max(64, int(size))
        cx = (n - 1) * 0.5
        cy = (n - 1) * 0.5
        inv = 1.0 / max(1.0, float(n - 1))
        out = bytearray(n * n * 4)

        for y in range(n):
            ny = ((float(y) - cy) * 2.0) * inv
            for x in range(n):
                nx = ((float(x) - cx) * 2.0) * inv
                r = math.sqrt((nx * nx) + (ny * ny))
                a = math.atan2(ny, nx)
                # Deterministic swirl field.
                swirl = (
                    math.sin((r * 23.0) - (a * 5.6))
                    + math.cos((r * 31.0) + (a * 7.3))
                    + math.sin((nx * 17.0) - (ny * 13.0))
                )
                swirl_n = (swirl + 3.0) / 6.0
                falloff = max(0.0, min(1.0, 1.25 - (r * 0.95)))
                grain = math.sin((x * 0.173) + (y * 0.217)) * 0.09
                lum = max(0.0, min(1.0, (swirl_n * 0.64) + (falloff * 0.30) + grain))

                red = int(round(16 + (lum * 38)))
                green = int(round(36 + (lum * 84)))
                blue = int(round(68 + (lum * 146)))
                alpha = 255

                i = ((y * n) + x) * 4
                out[i] = max(0, min(255, red))
                out[i + 1] = max(0, min(255, green))
                out[i + 2] = max(0, min(255, blue))
                out[i + 3] = alpha

        return bytes(out)

    def resize(self, *, window_size: tuple[int, int]) -> None:
        self._win_w = max(1, int(window_size[0]))
        self._win_h = max(1, int(window_size[1]))

    def render_frame(
        self,
        *,
        ui_surface: pygame.Surface,
        scene: GlScene | None,
    ) -> None:
        gl = self._gl

        gl.glViewport(0, 0, self._win_w, self._win_h)
        gl.glClearColor(0.01, 0.02, 0.06, 1.0)
        gl.glClear(gl.GL_COLOR_BUFFER_BIT | gl.GL_DEPTH_BUFFER_BIT)

        if scene is not None:
            self._draw_scene(scene=scene)
        else:
            self._last_scene_debug = {
                "kind": "none",
                "entity_count": 0,
                "viewport": (self._win_w, self._win_h),
            }

        self._draw_ui_surface(ui_surface=ui_surface)

    def debug_last_scene(self) -> dict[str, object]:
        return dict(self._last_scene_debug)

    def _draw_scene(self, *, scene: GlScene) -> None:
        kind = gl_scene_name(scene)
        entity_count = 0
        if isinstance(scene, AuditoryGlScene):
            entity_count = self._draw_auditory_scene(scene=scene)
        elif isinstance(scene, RapidTrackingGlScene):
            entity_count = self._draw_rapid_tracking_scene(scene=scene)
        elif isinstance(scene, SpatialIntegrationGlScene):
            entity_count = self._draw_spatial_integration_scene(scene=scene)
        elif isinstance(scene, TraceTest1GlScene):
            entity_count = self._draw_trace_test_1_scene(scene=scene)
        else:
            entity_count = self._draw_trace_test_2_scene(scene=scene)
        self._last_scene_debug = {
            "kind": kind,
            "entity_count": int(entity_count),
            "viewport": (self._win_w, self._win_h),
        }

    def _draw_auditory_scene(self, *, scene: AuditoryGlScene) -> int:
        gl = self._gl
        rect = scene.world
        payload = scene.payload
        time_fill_ratio = scene.time_fill_ratio

        vw = max(1, int(rect.w))
        vh = max(1, int(rect.h))
        vx = int(rect.x)
        vy = int(self._win_h - rect.bottom)

        gl.glEnable(gl.GL_SCISSOR_TEST)
        gl.glScissor(vx, vy, vw, vh)
        gl.glClearColor(0.03, 0.06, 0.15, 1.0)
        gl.glClear(gl.GL_COLOR_BUFFER_BIT | gl.GL_DEPTH_BUFFER_BIT)
        gl.glDisable(gl.GL_SCISSOR_TEST)

        gl.glViewport(vx, vy, vw, vh)
        self._set_ortho_2d(width=vw, height=vh)
        gl.glDisable(gl.GL_DEPTH_TEST)
        gl.glEnable(gl.GL_TEXTURE_2D)
        gl.glBindTexture(gl.GL_TEXTURE_2D, self._vortex_texture_id)
        gl.glColor4f(1.0, 1.0, 1.0, 1.0)
        gl.glBegin(gl.GL_QUADS)
        gl.glTexCoord2f(0.0, 0.0)
        gl.glVertex2f(0.0, 0.0)
        gl.glTexCoord2f(1.0, 0.0)
        gl.glVertex2f(float(vw), 0.0)
        gl.glTexCoord2f(1.0, 1.0)
        gl.glVertex2f(float(vw), float(vh))
        gl.glTexCoord2f(0.0, 1.0)
        gl.glVertex2f(0.0, float(vh))
        gl.glEnd()
        gl.glDisable(gl.GL_TEXTURE_2D)

        cx = float(vw) * 0.50
        cy = float(vh) * 0.50
        max_r = min(vw, vh) * 0.54
        rings_2d = 20
        for idx in range(rings_2d):
            t = idx / float(max(1, rings_2d - 1))
            r = max_r * (0.10 + (0.90 * t))
            alpha = 0.12 * (1.0 - t)
            gl.glColor4f(0.10, 0.18, 0.38, alpha)
            gl.glBegin(gl.GL_LINE_LOOP)
            seg = 48
            for n in range(seg):
                a = (n / float(seg)) * math.tau
                gl.glVertex2f(cx + (math.cos(a) * r), cy + (math.sin(a) * r * 0.94))
            gl.glEnd()

        gl.glBegin(gl.GL_TRIANGLE_FAN)
        gl.glColor4f(0.04, 0.10, 0.28, 0.04)
        gl.glVertex2f(cx, cy)
        seg = 64
        for n in range(seg + 1):
            a = (n / float(seg)) * math.tau
            gl.glColor4f(0.01, 0.02, 0.08, 0.34)
            gl.glVertex2f(cx + (math.cos(a) * max_r), cy + (math.sin(a) * max_r * 0.92))
        gl.glEnd()

        self._set_perspective(
            fovy_deg=46.0,
            aspect=max(0.20, vw / float(vh)),
            z_near=0.10,
            z_far=80.0,
        )
        gl.glEnable(gl.GL_DEPTH_TEST)

        tube_rx = 0.88
        tube_ry = 0.54
        z_near = 2.0
        z_far = 26.0
        ring_steps = 28
        ring_count = 24

        ring_centers: list[tuple[float, float, float, float]] = []
        for idx in range(ring_count):
            t = idx / float(max(1, ring_count - 1))
            z = self._auditory_depth_to_scene_z(t, z_near=z_near, z_far=z_far)
            off_x, off_y = self._tube_offset_at_depth(z=z, z_near=z_near, z_far=z_far)
            ring_centers.append((z, off_x, off_y, t))
            lum = 0.76 - (0.54 * t)
            gl.glColor4f(0.10 * lum, 0.38 * lum, 0.90 * lum, 0.84)
            gl.glBegin(gl.GL_LINE_LOOP)
            for n in range(ring_steps):
                a = (n / float(ring_steps)) * math.tau
                gl.glVertex3f(
                    off_x + (math.cos(a) * tube_rx),
                    off_y + (math.sin(a) * tube_ry),
                    z,
                )
            gl.glEnd()

        wall_segments = 24
        for idx in range(len(ring_centers) - 1):
            z0, off_x0, off_y0, t0 = ring_centers[idx]
            z1, off_x1, off_y1, t1 = ring_centers[idx + 1]
            depth_mix = (t0 + t1) * 0.5
            alpha = 0.07 + (0.08 * (1.0 - depth_mix))
            gl.glBegin(gl.GL_QUAD_STRIP)
            for n in range(wall_segments + 1):
                a = (n / float(wall_segments)) * math.tau
                pulse = 0.62 + (0.38 * math.cos((a * 2.0) - (depth_mix * math.tau * 1.15)))
                gl.glColor4f(0.05 * pulse, 0.16 * pulse, 0.34 + (0.22 * pulse), alpha)
                gl.glVertex3f(
                    off_x0 + (math.cos(a) * tube_rx),
                    off_y0 + (math.sin(a) * tube_ry),
                    z0,
                )
                gl.glColor4f(
                    0.05 * pulse,
                    0.15 * pulse,
                    0.30 + (0.18 * pulse),
                    alpha * 0.94,
                )
                gl.glVertex3f(
                    off_x1 + (math.cos(a) * tube_rx),
                    off_y1 + (math.sin(a) * tube_ry),
                    z1,
                )
            gl.glEnd()

        for a in (0.0, math.pi * 0.5, math.pi, math.pi * 1.5):
            gl.glColor4f(0.16, 0.24, 0.46, 0.74)
            gl.glBegin(gl.GL_LINE_STRIP)
            for z, off_x, off_y, _ in ring_centers:
                gl.glVertex3f(
                    off_x + (math.cos(a) * tube_rx),
                    off_y + (math.sin(a) * tube_ry),
                    z,
                )
            gl.glEnd()

        base_cross_x, base_cross_y = self._tube_offset_at_depth(
            z=-3.1,
            z_near=z_near,
            z_far=z_far,
        )
        cross_x = 0.0
        cross_y = 0.0
        cross_z = -3.1

        if payload is not None:
            y_half_span = max(0.08, float(payload.tube_half_height))
            x_half_span = max(0.08, float(payload.tube_half_width))
            travel_distance = float(payload.presentation_travel_distance)

            gates: list[tuple[float, AuditoryCapacityGate, float, float, float, int]] = []
            visible_gates: list[tuple[float, AuditoryCapacityGate]] = []
            for gate in payload.gates:
                distance = gate_distance_from_x_norm(
                    float(gate.x_norm),
                    travel_distance=travel_distance,
                    spawn_x_norm=float(AUDITORY_GATE_SPAWN_X_NORM),
                    player_x_norm=float(AUDITORY_GATE_PLAYER_X_NORM),
                    retire_x_norm=float(AUDITORY_GATE_RETIRE_X_NORM),
                )
                if distance < (travel_distance + AUDITORY_GATE_BEHIND_DISTANCE):
                    continue
                visible_gates.append((distance, gate))
            visible_gates.sort(key=lambda item: float(item[0]), reverse=True)
            for visible_idx, (distance, gate) in enumerate(visible_gates[:6]):
                depth_norm = self._auditory_gate_depth_norm_from_distance(
                    distance=distance,
                    travel_distance=travel_distance,
                )
                z = self._auditory_depth_to_scene_z(depth_norm, z_near=z_near, z_far=z_far)
                if z > -0.8:
                    continue
                gate_off_x, gate_off_y = self._tube_offset_at_depth(
                    z=z,
                    z_near=z_near,
                    z_far=z_far,
                )
                gy = max(-1.0, min(1.0, gate.y_norm / y_half_span)) * (tube_ry * 0.92)
                gx = gate_off_x
                gy = gate_off_y + gy
                radius = 0.11 + (max(0.06, min(0.36, gate.aperture_norm)) * 1.10)
                gates.append((z, gate, gx, gy, radius, visible_idx))

            for z, gate, gx, gy, radius, _visible_idx in sorted(gates, key=lambda g: g[0]):
                color = self._auditory_gate_visual_rgbf(gate)
                dz = 0.30
                gl.glColor4f(color[0] * 0.36, color[1] * 0.42, color[2] * 0.48, 0.24)
                self._draw_gate_shape_filled_3d(
                    shape=gate.shape,
                    x=gx,
                    y=gy,
                    z=z + (dz * 0.5),
                    radius=radius * 0.95,
                )
                gl.glColor4f(color[0], color[1], color[2], 0.95)
                self._draw_gate_shape_wire_3d(shape=gate.shape, x=gx, y=gy, z=z + dz, radius=radius)
                self._draw_gate_shape_wire_3d(shape=gate.shape, x=gx, y=gy, z=z, radius=radius)
                gl.glColor4f(
                    min(1.0, color[0] + 0.24),
                    min(1.0, color[1] + 0.24),
                    min(1.0, color[2] + 0.24),
                    0.72,
                )
                self._draw_gate_shape_wire_3d(
                    shape=gate.shape,
                    x=gx,
                    y=gy,
                    z=z + (dz * 0.38),
                    radius=radius * 0.92,
                )
                gl.glColor4f(color[0] * 0.78, color[1] * 0.78, color[2] * 0.78, 0.72)
                gl.glBegin(gl.GL_LINES)
                gl.glVertex3f(gx - radius, gy, z)
                gl.glVertex3f(gx - radius, gy, z + dz)
                gl.glVertex3f(gx + radius, gy, z)
                gl.glVertex3f(gx + radius, gy, z + dz)
                gl.glVertex3f(gx, gy - radius, z)
                gl.glVertex3f(gx, gy - radius, z + dz)
                gl.glVertex3f(gx, gy + radius, z)
                gl.glVertex3f(gx, gy + radius, z + dz)
                gl.glEnd()

            bx = max(-1.0, min(1.0, payload.ball_x / x_half_span)) * (tube_rx * 0.90)
            by = max(-1.0, min(1.0, payload.ball_y / y_half_span)) * (tube_ry * 0.90)
            ball_depth_norm = float(BALL_FORWARD_IDLE_NORM)
            ball_z = self._auditory_depth_to_scene_z(ball_depth_norm, z_near=z_near, z_far=z_far)
            ball_r = 0.10
            ball_off_x, ball_off_y = self._tube_offset_at_depth(
                z=ball_z,
                z_near=z_near,
                z_far=z_far,
            )
            cross_z = ball_z + 0.002

            ball_contact = float(payload.ball_contact_ratio)
            if ball_contact >= 1.0:
                ball_fill = (0.95, 0.35, 0.38)
                ball_edge = (0.95, 0.35, 0.38, 0.98)
            else:
                flash_color = self._gate_color(payload.ball_visual_color)
                ball_fill = self._mix_rgb3(
                    (0.92, 0.95, 1.0),
                    flash_color,
                    mix=float(payload.ball_visual_strength),
                )
                ball_edge_rgb = self._mix_rgb3(ball_fill, (1.0, 1.0, 1.0), mix=0.18)
                ball_edge = (ball_edge_rgb[0], ball_edge_rgb[1], ball_edge_rgb[2], 0.98)

            gl.glColor4f(0.56, 0.60, 0.70, 0.78)
            self._draw_filled_disc_3d(
                x=bx + (ball_r * 0.20),
                y=by - (ball_r * 0.25),
                z=ball_z - 0.05,
                radius=ball_r * 0.92,
            )
            gl.glColor4f(ball_fill[0], ball_fill[1], ball_fill[2], 0.98)
            self._draw_filled_disc_3d(x=bx, y=by, z=ball_z, radius=ball_r)
            gl.glColor4f(ball_edge[0], ball_edge[1], ball_edge[2], ball_edge[3])
            self._draw_disc_outline_3d(x=bx, y=by, z=ball_z, radius=ball_r)
            gl.glColor4f(1.0, 1.0, 1.0, 0.90)
            self._draw_filled_disc_3d(
                x=bx - (ball_r * 0.33),
                y=by + (ball_r * 0.32),
                z=ball_z + 0.001,
                radius=ball_r * 0.28,
            )

            if ball_contact >= 1.0:
                contact_strength = min(1.0, 0.35 + ((ball_contact - 1.0) * 4.2))
                local_x = max(-1.0, min(1.0, payload.ball_x / x_half_span))
                local_y = max(-1.0, min(1.0, payload.ball_y / y_half_span))
                local_norm = math.hypot(local_x, local_y)
                if local_norm > 1e-4:
                    hit_x = ball_off_x + ((local_x / local_norm) * tube_rx)
                    hit_y = ball_off_y + ((local_y / local_norm) * tube_ry)
                    hit_r = 0.12 + (0.05 * contact_strength)
                    gl.glColor4f(1.0, 0.40, 0.32, 0.62 + (0.18 * contact_strength))
                    self._draw_disc_outline_3d(
                        x=hit_x,
                        y=hit_y,
                        z=ball_z - 0.01,
                        radius=hit_r,
                    )
                    gl.glBegin(gl.GL_LINES)
                    gl.glVertex3f(hit_x, hit_y, ball_z - 0.02)
                    gl.glVertex3f(
                        hit_x - ((local_x / local_norm) * 0.28),
                        hit_y - ((local_y / local_norm) * 0.18),
                        ball_z - 0.02,
                    )
                    gl.glEnd()

        gl.glDisable(gl.GL_DEPTH_TEST)
        gl.glColor4f(0.72, 0.18, 0.22, 0.84)
        gl.glBegin(gl.GL_LINES)
        gl.glVertex3f(cross_x, cross_y + (tube_ry * 0.96), cross_z)
        gl.glVertex3f(cross_x, cross_y - (tube_ry * 0.96), cross_z)
        gl.glVertex3f(cross_x - (tube_rx * 0.96), cross_y, cross_z)
        gl.glVertex3f(cross_x + (tube_rx * 0.96), cross_y, cross_z)
        gl.glEnd()

        self._set_ortho_2d(width=vw, height=vh)

        gl.glColor4f(0.08, 0.18, 0.56, 0.92)
        gl.glBegin(gl.GL_QUADS)
        gl.glVertex2f(0.0, float(vh - 18))
        gl.glVertex2f(float(vw), float(vh - 18))
        gl.glVertex2f(float(vw), float(vh))
        gl.glVertex2f(0.0, float(vh))
        gl.glEnd()

        if runtime_visible_timers_enabled():
            gl.glColor4f(0.46, 0.50, 0.62, 0.70)
            bar_w = 132.0
            bar_h = 15.0
            bar_x = float(vw) - bar_w - 16.0
            bar_y = 12.0
            gl.glBegin(gl.GL_QUADS)
            gl.glVertex2f(bar_x, bar_y)
            gl.glVertex2f(bar_x + bar_w, bar_y)
            gl.glVertex2f(bar_x + bar_w, bar_y + bar_h)
            gl.glVertex2f(bar_x, bar_y + bar_h)
            gl.glEnd()

            gl.glColor4f(0.16, 0.18, 0.22, 0.78)
            gl.glBegin(gl.GL_LINE_LOOP)
            gl.glVertex2f(bar_x, bar_y)
            gl.glVertex2f(bar_x + bar_w, bar_y)
            gl.glVertex2f(bar_x + bar_w, bar_y + bar_h)
            gl.glVertex2f(bar_x, bar_y + bar_h)
            gl.glEnd()

            inner_x = bar_x + 4.0
            inner_y = bar_y + 4.0
            inner_w = bar_w - 8.0
            inner_h = bar_h - 8.0
            gl.glColor4f(0.12, 0.14, 0.18, 0.84)
            gl.glBegin(gl.GL_QUADS)
            gl.glVertex2f(inner_x, inner_y)
            gl.glVertex2f(inner_x + inner_w, inner_y)
            gl.glVertex2f(inner_x + inner_w, inner_y + inner_h)
            gl.glVertex2f(inner_x, inner_y + inner_h)
            gl.glEnd()

            fill_ratio = 0.72 if time_fill_ratio is None else max(0.0, min(1.0, time_fill_ratio))
            fill_w = max(0.0, inner_w * fill_ratio)
            gl.glColor4f(0.76, 0.80, 0.86, 0.90)
            if fill_w > 0.0:
                gl.glBegin(gl.GL_QUADS)
                gl.glVertex2f(inner_x, inner_y)
                gl.glVertex2f(inner_x + fill_w, inner_y)
                gl.glVertex2f(inner_x + fill_w, inner_y + inner_h)
                gl.glVertex2f(inner_x, inner_y + inner_h)
                gl.glEnd()
                gl.glColor4f(0.94, 0.96, 0.98, 0.70)
                gl.glBegin(gl.GL_LINES)
                gl.glVertex2f(inner_x + 1.0, inner_y + 1.0)
                gl.glVertex2f(inner_x + max(2.0, fill_w - 1.0), inner_y + 1.0)
                gl.glEnd()

        gl.glColor4f(0.16, 0.34, 0.84, 0.90)
        gl.glBegin(gl.GL_LINE_LOOP)
        gl.glVertex2f(1.0, 1.0)
        gl.glVertex2f(float(vw - 1), 1.0)
        gl.glVertex2f(float(vw - 1), float(vh - 1))
        gl.glVertex2f(1.0, float(vh - 1))
        gl.glEnd()
        gl.glColor4f(0.38, 0.52, 0.88, 0.72)
        gl.glBegin(gl.GL_LINE_LOOP)
        gl.glVertex2f(4.0, 4.0)
        gl.glVertex2f(float(vw - 4), 4.0)
        gl.glVertex2f(float(vw - 4), float(vh - 4))
        gl.glVertex2f(4.0, float(vh - 4))
        gl.glEnd()
        gate_count = len(payload.gates) if payload is not None else 0
        return max(1, gate_count + (1 if payload is not None else 0))

    def _prepare_scene_rect(
        self,
        *,
        rect: pygame.Rect,
        clear_rgba: tuple[float, float, float, float],
    ) -> tuple[int, int]:
        gl = self._gl
        vw = max(1, int(rect.w))
        vh = max(1, int(rect.h))
        vx = int(rect.x)
        vy = int(self._win_h - rect.bottom)
        gl.glEnable(gl.GL_SCISSOR_TEST)
        gl.glScissor(vx, vy, vw, vh)
        gl.glClearColor(*clear_rgba)
        gl.glClear(gl.GL_COLOR_BUFFER_BIT | gl.GL_DEPTH_BUFFER_BIT)
        gl.glDisable(gl.GL_SCISSOR_TEST)
        gl.glViewport(vx, vy, vw, vh)
        self._set_ortho_2d(width=vw, height=vh)
        gl.glDisable(gl.GL_DEPTH_TEST)
        return vw, vh

    def _draw_quad_2d(
        self,
        *,
        x0: float,
        y0: float,
        x1: float,
        y1: float,
        color: tuple[float, float, float, float],
    ) -> None:
        gl = self._gl
        gl.glColor4f(*color)
        gl.glBegin(gl.GL_QUADS)
        gl.glVertex2f(x0, y0)
        gl.glVertex2f(x1, y0)
        gl.glVertex2f(x1, y1)
        gl.glVertex2f(x0, y1)
        gl.glEnd()

    def _draw_line_2d(
        self,
        *,
        start: tuple[float, float],
        end: tuple[float, float],
        color: tuple[float, float, float, float],
        width: float = 1.0,
    ) -> None:
        gl = self._gl
        gl.glLineWidth(max(1.0, float(width)))
        gl.glColor4f(*color)
        gl.glBegin(gl.GL_LINES)
        gl.glVertex2f(start[0], start[1])
        gl.glVertex2f(end[0], end[1])
        gl.glEnd()
        gl.glLineWidth(1.0)

    def _draw_circle_2d(
        self,
        *,
        center: tuple[float, float],
        radius: float,
        color: tuple[float, float, float, float],
        filled: bool = True,
        segments: int = 28,
    ) -> None:
        gl = self._gl
        gl.glColor4f(*color)
        mode = gl.GL_TRIANGLE_FAN if filled else gl.GL_LINE_LOOP
        gl.glBegin(mode)
        if filled:
            gl.glVertex2f(center[0], center[1])
        for idx in range(segments + (1 if filled else 0)):
            angle = (idx / float(max(1, segments))) * math.tau
            gl.glVertex2f(
                center[0] + (math.cos(angle) * radius),
                center[1] + (math.sin(angle) * radius),
            )
        gl.glEnd()

    def _draw_aircraft_marker_2d(
        self,
        *,
        center: tuple[float, float],
        heading_deg: float,
        size: float,
        color: tuple[float, float, float, float],
        outline: tuple[float, float, float, float],
        pitch_deg: float = 0.0,
        bank_deg: float = 0.0,
        view_yaw_deg: float = 0.0,
        view_pitch_deg: float = 20.0,
    ) -> None:
        gl = self._gl
        palette = build_pygame_palette(
            body_color=tuple(max(0, min(255, int(round(channel * 255.0)))) for channel in color[:3]),
            outline_color=tuple(max(0, min(255, int(round(channel * 255.0)))) for channel in outline[:3]),
        )
        role_colors = {
            "body": palette.body,
            "accent": palette.accent,
            "canopy": palette.canopy,
            "engine": palette.engine,
        }
        projected = project_fixed_wing_faces(
            heading_deg=self._screen_heading_to_fixed_wing_heading(heading_deg),
            pitch_deg=float(pitch_deg),
            bank_deg=float(bank_deg),
            cx=int(round(center[0])),
            cy=int(round(center[1])),
            scale=max(8.0, float(size)),
            view_yaw_deg=view_yaw_deg,
            view_pitch_deg=view_pitch_deg,
        )
        for face in projected:
            base = role_colors.get(face.role, palette.body)
            fill = tuple(max(0, min(255, int(round(channel * face.shade)))) for channel in base)
            gl.glColor4f(fill[0] / 255.0, fill[1] / 255.0, fill[2] / 255.0, color[3])
            gl.glBegin(gl.GL_TRIANGLE_FAN)
            for px, py in face.points:
                gl.glVertex2f(float(px), float(py))
            gl.glEnd()
            gl.glColor4f(*outline)
            gl.glBegin(gl.GL_LINE_LOOP)
            for px, py in face.points:
                gl.glVertex2f(float(px), float(py))
            gl.glEnd()

    def _draw_rapid_tracking_scene(self, *, scene: RapidTrackingGlScene) -> int:
        rect = scene.world
        payload = scene.payload
        vw, vh = self._prepare_scene_rect(rect=rect, clear_rgba=(0.03, 0.08, 0.08, 1.0))
        horizon = vh * 0.48
        if payload is not None:
            rig = rapid_tracking_camera_rig_state(
                elapsed_s=float(payload.phase_elapsed_s),
                seed=int(payload.scene_seed),
                progress=float(payload.scene_progress),
                camera_yaw_deg=float(payload.camera_yaw_deg),
                camera_pitch_deg=float(payload.camera_pitch_deg),
                zoom=float(payload.capture_zoom),
                target_kind=str(payload.target_kind),
                target_world_x=float(payload.target_world_x),
                target_world_y=float(payload.target_world_y),
                focus_world_x=float(payload.focus_world_x),
                focus_world_y=float(payload.focus_world_y),
                turbulence_strength=float(payload.turbulence_strength),
            )
            horizon = max(vh * 0.28, min(vh * 0.70, vh * (0.60 - (rig.view_pitch_deg / 90.0))))

        band_h = max(1.0, vh / 10.0)
        for idx in range(10):
            y0 = vh - ((idx + 1) * band_h)
            y1 = vh - (idx * band_h)
            mix = idx / 9.0
            self._draw_quad_2d(
                x0=0.0,
                y0=y0,
                x1=float(vw),
                y1=y1,
                color=(0.08 + (0.12 * mix), 0.20 + (0.20 * mix), 0.28 + (0.18 * mix), 1.0),
            )
        self._draw_quad_2d(
            x0=0.0,
            y0=0.0,
            x1=float(vw),
            y1=horizon,
            color=(0.10, 0.22, 0.16, 1.0),
        )
        for lane in range(-4, 5):
            bottom_x = (vw * 0.5) + (lane * vw * 0.11)
            top_x = (vw * 0.5) + (lane * 18.0)
            self._draw_line_2d(
                start=(bottom_x, 0.0),
                end=(top_x, horizon),
                color=(0.14, 0.40, 0.28, 0.55),
            )
        self._draw_line_2d(
            start=(0.0, horizon),
            end=(float(vw), horizon),
            color=(0.56, 0.76, 0.70, 0.64),
        )

        if payload is None:
            return 0

        target = build_rapid_tracking_scene_target(payload=payload, size=(vw, vh))
        overlay = target.overlay
        target_center = (float(overlay.screen_x), float(vh - overlay.screen_y))
        if scene.active_phase:
            pulse = 0.4 + (0.6 * math.sin(pygame.time.get_ticks() / 220.0))
            self._draw_quad_2d(
                x0=0.0,
                y0=0.0,
                x1=12.0,
                y1=float(vh),
                color=(0.16, 0.56, 0.42, 0.10 + (0.08 * pulse)),
            )
            self._draw_quad_2d(
                x0=float(vw - 12),
                y0=0.0,
                x1=float(vw),
                y1=float(vh),
                color=(0.60, 0.34, 0.18, 0.10 + (0.08 * pulse)),
            )

        cx = vw * 0.5
        cy = vh * 0.5
        box_half_w = max(18.0, ((vw * 0.5) - 12.0) * float(payload.capture_box_half_width))
        box_half_h = max(14.0, ((vh * 0.5) - 12.0) * 0.90 * float(payload.capture_box_half_height))
        box_color = (0.56, 0.94, 0.74, 0.85) if payload.target_in_capture_box else (0.52, 0.72, 0.66, 0.78)
        self._draw_line_2d(start=(cx - box_half_w, cy - box_half_h), end=(cx + box_half_w, cy - box_half_h), color=box_color, width=2.0)
        self._draw_line_2d(start=(cx + box_half_w, cy - box_half_h), end=(cx + box_half_w, cy + box_half_h), color=box_color, width=2.0)
        self._draw_line_2d(start=(cx + box_half_w, cy + box_half_h), end=(cx - box_half_w, cy + box_half_h), color=box_color, width=2.0)
        self._draw_line_2d(start=(cx - box_half_w, cy + box_half_h), end=(cx - box_half_w, cy - box_half_h), color=box_color, width=2.0)
        self._draw_line_2d(start=(cx - 12.0, cy), end=(cx + 12.0, cy), color=box_color)
        self._draw_line_2d(start=(cx, cy - 12.0), end=(cx, cy + 12.0), color=box_color)

        if not payload.target_visible:
            self._draw_circle_2d(center=target_center, radius=22.0, color=(0.03, 0.05, 0.05, 0.92))
            self._draw_circle_2d(center=target_center, radius=22.0, color=(0.54, 0.64, 0.60, 0.80), filled=False)
            return 1

        if target.kind == "building":
            half_w = 18.0 if target.variant == "tower" else 28.0
            half_h = 36.0 if target.variant == "tower" else 18.0
            self._draw_quad_2d(
                x0=target_center[0] - half_w,
                y0=target_center[1] - half_h,
                x1=target_center[0] + half_w,
                y1=target_center[1] + half_h,
                color=(0.62, 0.78, 0.74, 0.92),
            )
            self._draw_circle_2d(
                center=target_center,
                radius=38.0,
                color=(0.86, 0.98, 0.94, 0.55),
                filled=False,
            )
        elif target.kind == "truck":
            self._draw_quad_2d(
                x0=target_center[0] - 20.0,
                y0=target_center[1] - 8.0,
                x1=target_center[0] + 20.0,
                y1=target_center[1] + 8.0,
                color=(0.88, 0.78, 0.36, 0.94),
            )
            self._draw_circle_2d(center=(target_center[0] - 12.0, target_center[1] - 10.0), radius=4.0, color=(0.10, 0.12, 0.12, 1.0))
            self._draw_circle_2d(center=(target_center[0] + 12.0, target_center[1] - 10.0), radius=4.0, color=(0.10, 0.12, 0.12, 1.0))
        elif target.kind == "soldier":
            self._draw_circle_2d(center=(target_center[0], target_center[1] + 11.0), radius=4.0, color=(0.92, 0.82, 0.74, 0.96))
            self._draw_line_2d(start=(target_center[0], target_center[1] + 8.0), end=(target_center[0], target_center[1] - 12.0), color=(0.86, 0.44, 0.38, 0.95), width=2.0)
            self._draw_line_2d(start=(target_center[0] - 7.0, target_center[1]), end=(target_center[0] + 7.0, target_center[1]), color=(0.86, 0.44, 0.38, 0.95), width=2.0)
            self._draw_line_2d(start=(target_center[0], target_center[1] - 12.0), end=(target_center[0] - 6.0, target_center[1] - 22.0), color=(0.86, 0.44, 0.38, 0.95), width=2.0)
            self._draw_line_2d(start=(target_center[0], target_center[1] - 12.0), end=(target_center[0] + 6.0, target_center[1] - 22.0), color=(0.86, 0.44, 0.38, 0.95), width=2.0)
        elif target.kind == "helicopter":
            self._draw_circle_2d(center=target_center, radius=11.0, color=(0.58, 0.90, 0.76, 0.95))
            self._draw_line_2d(start=(target_center[0] - 18.0, target_center[1] + 16.0), end=(target_center[0] + 18.0, target_center[1] + 16.0), color=(0.90, 0.96, 0.98, 0.85))
            self._draw_line_2d(start=(target_center[0] + 8.0, target_center[1]), end=(target_center[0] + 24.0, target_center[1]), color=(0.90, 0.96, 0.98, 0.82))
        else:
            heading_deg = math.degrees(math.atan2(float(payload.target_vy), float(payload.target_vx))) - 90.0
            self._draw_aircraft_marker_2d(
                center=target_center,
                heading_deg=heading_deg,
                size=14.0,
                color=(0.46, 0.78, 0.98, 0.96),
                outline=(0.94, 0.98, 1.0, 0.88),
            )

        self._draw_circle_2d(center=target_center, radius=30.0, color=(0.92, 0.98, 0.96, 0.64), filled=False)
        return 1

    def _draw_spatial_integration_scene(self, *, scene: SpatialIntegrationGlScene) -> int:
        rect = scene.world
        payload = scene.payload
        vw, vh = self._prepare_scene_rect(rect=rect, clear_rgba=(0.05, 0.08, 0.16, 1.0))
        layout = build_spatial_integration_scene_layout(payload=payload, size=(vw, vh))
        horizon = float(vh - layout.horizon_y)
        if layout.scene_view is SpatialIntegrationSceneView.TOPDOWN:
            self._draw_quad_2d(x0=0.0, y0=0.0, x1=float(vw), y1=float(vh), color=(0.24, 0.42, 0.22, 1.0))
            for idx in range(1, 6):
                x = (idx / 6.0) * vw
                self._draw_line_2d(start=(x, 0.0), end=(x, float(vh)), color=(0.62, 0.74, 0.58, 0.32))
                y = (idx / 6.0) * vh
                self._draw_line_2d(start=(0.0, y), end=(float(vw), y), color=(0.62, 0.74, 0.58, 0.32))
        else:
            self._draw_quad_2d(x0=0.0, y0=horizon, x1=float(vw), y1=float(vh), color=(0.42, 0.60, 0.82, 1.0))
            self._draw_quad_2d(x0=0.0, y0=0.0, x1=float(vw), y1=horizon, color=(0.30, 0.44, 0.22, 1.0))
            self._draw_line_2d(start=(0.0, horizon), end=(float(vw), horizon), color=(0.82, 0.88, 0.82, 0.60))

        for marker in layout.landmarks:
            center = (float(marker.screen_x), float(vh - marker.screen_y))
            self._draw_circle_2d(center=center, radius=7.0, color=(0.98, 0.88, 0.42, 0.94))
            self._draw_circle_2d(center=center, radius=11.0, color=(0.98, 0.94, 0.72, 0.44), filled=False)

        prev = (float(layout.aircraft_prev[0]), float(vh - layout.aircraft_prev[1]))
        now = (float(layout.aircraft_now[0]), float(vh - layout.aircraft_now[1]))
        self._draw_line_2d(start=prev, end=now, color=(0.94, 0.78, 0.32, 0.82), width=2.0)
        if layout.aircraft_future is not None:
            future = (float(layout.aircraft_future[0]), float(vh - layout.aircraft_future[1]))
            self._draw_line_2d(start=now, end=future, color=(0.94, 0.56, 0.30, 0.82), width=2.0)
        self._draw_circle_2d(center=prev, radius=5.0, color=(0.82, 0.88, 0.96, 0.78))
        self._draw_circle_2d(center=now, radius=7.0, color=(0.94, 0.36, 0.30, 0.96))
        return max(1, len(layout.landmarks) + 1)

    def _draw_trace_test_1_scene(self, *, scene: TraceTest1GlScene) -> int:
        rect = scene.world
        vw, vh = self._prepare_scene_rect(rect=rect, clear_rgba=(0.07, 0.10, 0.24, 1.0))
        payload = scene.payload
        self._draw_quad_2d(x0=0.0, y0=0.0, x1=float(vw), y1=float(vh), color=(0.56, 0.70, 0.88, 1.0))
        self._draw_quad_2d(
            x0=0.0,
            y0=float(vh * 0.52),
            x1=float(vw),
            y1=float(vh),
            color=(0.48, 0.60, 0.74, 1.0),
        )
        self._draw_line_2d(
            start=(0.0, float(vh * 0.52)),
            end=(float(vw), float(vh * 0.52)),
            color=(0.90, 0.94, 0.98, 0.46),
        )
        if payload is None:
            return 0
        target_pose, blue_poses = trace_test_1_aircraft_screen_poses_for_payload(
            payload,
            size=(vw, vh),
        )

        blue_colors = (
            (0.34, 0.52, 0.90, 0.96),
            (0.38, 0.60, 0.94, 0.96),
            (0.42, 0.66, 0.96, 0.96),
            (0.30, 0.46, 0.82, 0.96),
        )
        blue_outlines = (
            (0.92, 0.96, 1.0, 0.88),
            (0.90, 0.96, 1.0, 0.86),
            (0.88, 0.94, 0.98, 0.84),
            (0.84, 0.92, 0.98, 0.84),
        )
        for idx, (blue_frame, blue_pose) in enumerate(
            zip(payload.scene.blue_frames, blue_poses, strict=True)
        ):
            blue_center, blue_scale = trace_test_1_project_scene_position(
                blue_frame.position,
                size=(vw, vh),
            )
            self._draw_aircraft_marker_2d(
                center=(blue_center[0], float(vh - blue_center[1])),
                heading_deg=blue_pose[0],
                size=max(8.6, blue_scale * 10.2),
                color=blue_colors[idx % len(blue_colors)],
                outline=blue_outlines[idx % len(blue_outlines)],
                pitch_deg=blue_pose[1],
                bank_deg=blue_pose[2],
                view_pitch_deg=0.0,
            )

        target_frame = payload.scene.red_frame
        target_center, target_scale = trace_test_1_project_scene_position(
            target_frame.position,
            size=(vw, vh),
        )
        self._draw_aircraft_marker_2d(
            center=(target_center[0], float(vh - target_center[1])),
            heading_deg=target_pose[0],
            size=max(11.6, target_scale * 13.0),
            color=(0.92, 0.24, 0.24, 0.98),
            outline=(1.0, 0.92, 0.92, 0.90),
            pitch_deg=target_pose[1],
            bank_deg=target_pose[2],
            view_pitch_deg=0.0,
        )
        return 1 + len(payload.scene.blue_frames)

    def _draw_trace_test_2_scene(self, *, scene: TraceTest2GlScene) -> int:
        rect = scene.world
        payload = scene.payload
        vw, vh = self._prepare_scene_rect(rect=rect, clear_rgba=(0.06, 0.10, 0.24, 1.0))
        horizon = vh * 0.26
        self._draw_quad_2d(x0=0.0, y0=horizon, x1=float(vw), y1=float(vh), color=(0.50, 0.66, 0.86, 1.0))
        self._draw_quad_2d(x0=0.0, y0=0.0, x1=float(vw), y1=horizon, color=(0.40, 0.46, 0.52, 1.0))
        if payload is None:
            return 0

        progress = float(payload.observe_progress)
        for track in payload.aircraft:
            pos = trace_test_2_track_position(track=track, progress=progress)
            center = trace_test_2_project_point(pos, size=(vw, vh))
            pose = trace_test_2_aircraft_screen_pose_for_track(
                track=track,
                progress=progress,
                size=(vw, vh),
            )
            self._draw_aircraft_marker_2d(
                center=(center[0], float(vh - center[1])),
                heading_deg=pose[0],
                size=max(10.0, 14.0 - (abs(pose[1]) * 0.05)),
                color=(
                    track.color_rgb[0] / 255.0,
                    track.color_rgb[1] / 255.0,
                    track.color_rgb[2] / 255.0,
                    0.96,
                ),
                outline=(0.96, 0.98, 1.0, 0.88),
                pitch_deg=pose[1],
                bank_deg=pose[2],
                view_pitch_deg=22.0,
            )
        return len(payload.aircraft)

    def _draw_ui_surface(self, *, ui_surface: pygame.Surface) -> None:
        gl = self._gl
        w = max(1, int(ui_surface.get_width()))
        h = max(1, int(ui_surface.get_height()))

        pixels = pygame.image.tostring(ui_surface, "RGBA", True)

        gl.glViewport(0, 0, self._win_w, self._win_h)
        gl.glDisable(gl.GL_DEPTH_TEST)
        gl.glEnable(gl.GL_TEXTURE_2D)
        gl.glBindTexture(gl.GL_TEXTURE_2D, self._ui_texture_id)
        gl.glTexParameteri(gl.GL_TEXTURE_2D, gl.GL_TEXTURE_MIN_FILTER, gl.GL_LINEAR)
        gl.glTexParameteri(gl.GL_TEXTURE_2D, gl.GL_TEXTURE_MAG_FILTER, gl.GL_LINEAR)
        gl.glTexParameteri(gl.GL_TEXTURE_2D, gl.GL_TEXTURE_WRAP_S, gl.GL_CLAMP_TO_EDGE)
        gl.glTexParameteri(gl.GL_TEXTURE_2D, gl.GL_TEXTURE_WRAP_T, gl.GL_CLAMP_TO_EDGE)

        if self._ui_tex_size != (w, h):
            gl.glTexImage2D(
                gl.GL_TEXTURE_2D,
                0,
                gl.GL_RGBA,
                w,
                h,
                0,
                gl.GL_RGBA,
                gl.GL_UNSIGNED_BYTE,
                pixels,
            )
            self._ui_tex_size = (w, h)
        else:
            gl.glTexSubImage2D(
                gl.GL_TEXTURE_2D,
                0,
                0,
                0,
                w,
                h,
                gl.GL_RGBA,
                gl.GL_UNSIGNED_BYTE,
                pixels,
            )

        gl.glMatrixMode(gl.GL_PROJECTION)
        gl.glLoadIdentity()
        gl.glOrtho(0.0, float(self._win_w), 0.0, float(self._win_h), -1.0, 1.0)
        gl.glMatrixMode(gl.GL_MODELVIEW)
        gl.glLoadIdentity()

        gl.glColor4f(1.0, 1.0, 1.0, 1.0)
        gl.glBegin(gl.GL_QUADS)
        gl.glTexCoord2f(0.0, 0.0)
        gl.glVertex2f(0.0, 0.0)
        gl.glTexCoord2f(1.0, 0.0)
        gl.glVertex2f(float(self._win_w), 0.0)
        gl.glTexCoord2f(1.0, 1.0)
        gl.glVertex2f(float(self._win_w), float(self._win_h))
        gl.glTexCoord2f(0.0, 1.0)
        gl.glVertex2f(0.0, float(self._win_h))
        gl.glEnd()
        gl.glDisable(gl.GL_TEXTURE_2D)

    def _set_ortho_2d(self, *, width: int, height: int) -> None:
        gl = self._gl
        gl.glMatrixMode(gl.GL_PROJECTION)
        gl.glLoadIdentity()
        gl.glOrtho(0.0, float(width), 0.0, float(height), -1.0, 1.0)
        gl.glMatrixMode(gl.GL_MODELVIEW)
        gl.glLoadIdentity()

    def _set_perspective(
        self, *, fovy_deg: float, aspect: float, z_near: float, z_far: float
    ) -> None:
        gl = self._gl
        fovy = float(fovy_deg)
        near = max(0.01, float(z_near))
        far = max(near + 0.10, float(z_far))
        top = near * math.tan(math.radians(fovy * 0.5))
        bottom = -top
        right = top * float(aspect)
        left = -right
        gl.glMatrixMode(gl.GL_PROJECTION)
        gl.glLoadIdentity()
        gl.glFrustum(left, right, bottom, top, near, far)
        gl.glMatrixMode(gl.GL_MODELVIEW)
        gl.glLoadIdentity()

    @staticmethod
    def _tube_offset_at_depth(*, z: float, z_near: float, z_far: float) -> tuple[float, float]:
        span = max(0.001, float(z_far) - float(z_near))
        depth = max(0.0, min(1.0, ((-float(z)) - float(z_near)) / span))
        curve = depth**1.18

        # Deterministic S-curves that are gentle near the player and stronger farther out.
        x_wave = (math.sin((depth * math.tau * 1.05) + 0.45) * 0.74) + (
            math.sin((depth * math.tau * 2.25) - 0.35) * 0.26
        )
        y_wave = (math.sin((depth * math.tau * 1.45) + 1.45) * 0.72) + (
            math.sin((depth * math.tau * 2.55) + 0.80) * 0.28
        )

        off_x = x_wave * (0.58 * curve)
        off_y = y_wave * (0.35 * curve)
        return off_x, off_y

    @staticmethod
    def _gate_color(name: str) -> tuple[float, float, float]:
        palette = {
            "RED": (0.92, 0.32, 0.34),
            "ERROR_RED": (0.98, 0.46, 0.24),
            "GREEN": (0.34, 0.88, 0.56),
            "BLUE": (0.36, 0.62, 0.94),
            "YELLOW": (0.94, 0.82, 0.34),
            "WHITE": (0.92, 0.95, 1.0),
        }
        return palette.get(str(name).upper(), (0.86, 0.88, 0.92))

    @staticmethod
    def _mix_rgb3(
        a: tuple[float, float, float],
        b: tuple[float, float, float],
        *,
        mix: float,
    ) -> tuple[float, float, float]:
        m = max(0.0, min(1.0, float(mix)))
        return (
            (a[0] * (1.0 - m)) + (b[0] * m),
            (a[1] * (1.0 - m)) + (b[1] * m),
            (a[2] * (1.0 - m)) + (b[2] * m),
        )

    def _draw_gate_shape_wire_3d(
        self, *, shape: str, x: float, y: float, z: float, radius: float
    ) -> None:
        gl = self._gl
        token = str(shape).upper()
        if token == "TRIANGLE":
            gl.glBegin(gl.GL_LINE_LOOP)
            for px, py in AUDITORY_TRIANGLE_GATE_POINTS:
                gl.glVertex3f(x + (px * radius), y + (py * radius), z)
            gl.glEnd()
            return
        if token == "SQUARE":
            gl.glBegin(gl.GL_LINE_LOOP)
            gl.glVertex3f(x - radius, y - radius, z)
            gl.glVertex3f(x + radius, y - radius, z)
            gl.glVertex3f(x + radius, y + radius, z)
            gl.glVertex3f(x - radius, y + radius, z)
            gl.glEnd()
            return

        self._draw_disc_outline_3d(x=x, y=y, z=z, radius=radius)

    def _draw_gate_shape_filled_3d(
        self, *, shape: str, x: float, y: float, z: float, radius: float
    ) -> None:
        gl = self._gl
        token = str(shape).upper()
        if token == "TRIANGLE":
            gl.glBegin(gl.GL_TRIANGLES)
            for px, py in AUDITORY_TRIANGLE_GATE_POINTS:
                gl.glVertex3f(x + (px * radius), y + (py * radius), z)
            gl.glEnd()
            return
        if token == "SQUARE":
            gl.glBegin(gl.GL_QUADS)
            gl.glVertex3f(x - radius, y - radius, z)
            gl.glVertex3f(x + radius, y - radius, z)
            gl.glVertex3f(x + radius, y + radius, z)
            gl.glVertex3f(x - radius, y + radius, z)
            gl.glEnd()
            return
        self._draw_filled_disc_3d(x=x, y=y, z=z, radius=radius)

    def _draw_filled_disc_3d(self, *, x: float, y: float, z: float, radius: float) -> None:
        gl = self._gl
        gl.glBegin(gl.GL_TRIANGLE_FAN)
        gl.glVertex3f(x, y, z)
        segments = 28
        for i in range(segments + 1):
            a = (i / float(segments)) * math.tau
            gl.glVertex3f(x + (math.cos(a) * radius), y + (math.sin(a) * radius), z)
        gl.glEnd()

    def _draw_disc_outline_3d(self, *, x: float, y: float, z: float, radius: float) -> None:
        gl = self._gl
        gl.glBegin(gl.GL_LINE_LOOP)
        segments = 28
        for i in range(segments):
            a = (i / float(segments)) * math.tau
            gl.glVertex3f(x + (math.cos(a) * radius), y + (math.sin(a) * radius), z)
        gl.glEnd()


_OpenGLSceneRenderer = ModernSceneRenderer
_OpenGLAuditoryRenderer = ModernSceneRenderer


class App:
    def __init__(
        self,
        surface: pygame.Surface,
        font: pygame.font.Font,
        *,
        opengl_enabled: bool = False,
        window_mode: str = "windowed",
        headless_mode: bool = False,
        results_store: ResultsStore | None = None,
        input_profiles_store: InputProfilesStore | None = None,
        difficulty_settings_store: DifficultySettingsStore | None = None,
        test_seed_settings_store: TestSeedSettingsStore | None = None,
        rapid_tracking_settings_store: RapidTrackingSettingsStore | None = None,
        runtime_defaults_store: RuntimeDefaultsStore | None = None,
        app_version: str = "dev",
    ) -> None:
        self._surface = surface
        self._font = font
        self._screens: list[Screen] = []
        self._running = True
        self._opengl_enabled = bool(opengl_enabled)
        self._window_mode = str(window_mode).strip().lower() or "windowed"
        self._headless_mode = bool(headless_mode)
        self._gl_scene: GlScene | None = None
        self._results_store = results_store
        self._input_profiles_store = input_profiles_store
        self._joystick_binding_router = JoystickBindingRouter(profiles=input_profiles_store)
        self._keyboard_menu_repeat_down: dict[str, bool] = {
            action: False for action in _KEYBOARD_MENU_REPEAT_ACTIONS
        }
        self._keyboard_menu_repeat_due_ms: dict[str, int] = {}
        self._keyboard_menu_repeat_pending: dict[str, int] = {}
        self._difficulty_settings_store = difficulty_settings_store
        self._test_seed_settings_store = test_seed_settings_store
        self._rapid_tracking_settings_store = rapid_tracking_settings_store
        self._runtime_defaults_store = runtime_defaults_store
        self._app_version = str(app_version).strip() or "dev"
        self._activity_sessions: dict[int, _ActiveActivitySession] = {}
        self._renderer_path = (
            "MODERN_GL" if self._opengl_enabled else ("HEADLESS" if self._headless_mode else "FALLBACK_2D")
        )
        self._renderer_fallback_used = False
        self._renderer_diagnostic_codes: dict[str, str] = {}
        self._renderer_gl_requested = not self._headless_mode
        self._renderer_gl_attempted = bool(opengl_enabled)
        self._renderer_bootstrap_failure: OpenGLFailureInfo | None = None
        self._failure_recovery_used = False
        self._pending_renderer_action: str | None = None
        self._menu_banner_message: str | None = None
        self._menu_banner_until_ms = 0
        self._shell_pause_active = False
        self._shell_pause_selected = 0
        self._shell_pause_hitboxes: dict[int, pygame.Rect] = {}
        self._status_font = pygame.font.Font(None, 22)
        self._status_tiny_font = pygame.font.Font(None, 18)
        self._exit_code = 0
        self._exit_reason = "running"
        self._dev_tools_enabled = os.environ.get(DEV_TOOLS_ENV, "").strip().lower() in {
            "1",
            "true",
            "on",
            "yes",
        }
        if self._results_store is not None:
            try:
                self._results_store.start_app_session(app_version=self._app_version)
            except Exception:
                pass

    @property
    def running(self) -> bool:
        return self._running

    @property
    def font(self) -> pygame.font.Font:
        return self._font

    @property
    def surface(self) -> pygame.Surface:
        return self._surface

    @property
    def opengl_enabled(self) -> bool:
        return self._opengl_enabled

    def set_surface(self, surface: pygame.Surface) -> None:
        self._surface = surface

    def _window_pointer_space(self) -> tuple[int, int] | None:
        get_window_size = getattr(pygame.display, "get_window_size", None)
        if not callable(get_window_size):
            return None
        try:
            raw_size = get_window_size()
        except Exception:
            return None
        try:
            width = max(1, int(raw_size[0]))
            height = max(1, int(raw_size[1]))
        except Exception:
            return None
        return (width, height)

    def _surface_pointer_space(self) -> tuple[int, int]:
        return (
            max(1, int(self._surface.get_width())),
            max(1, int(self._surface.get_height())),
        )

    @staticmethod
    def _scale_pointer_component(value: object, *, src: int, dst: int) -> int:
        try:
            numeric = float(value)
        except Exception:
            numeric = 0.0
        scaled = int(round(numeric * (float(dst) / float(max(1, src)))))
        return max(0, min(dst - 1, scaled))

    @staticmethod
    def _scale_pointer_delta(value: object, *, src: int, dst: int) -> int:
        try:
            numeric = float(value)
        except Exception:
            numeric = 0.0
        return int(round(numeric * (float(dst) / float(max(1, src)))))

    def _normalize_pointer_event(self, event: pygame.event.Event) -> pygame.event.Event:
        if event.type not in (
            pygame.MOUSEMOTION,
            pygame.MOUSEBUTTONDOWN,
            pygame.MOUSEBUTTONUP,
        ):
            return event
        window_space = self._window_pointer_space()
        if window_space is None:
            return event
        surface_space = self._surface_pointer_space()
        if surface_space == window_space:
            return event

        payload = dict(getattr(event, "dict", {}))
        pos = payload.get("pos")
        if isinstance(pos, tuple) and len(pos) >= 2:
            payload["pos"] = (
                self._scale_pointer_component(pos[0], src=window_space[0], dst=surface_space[0]),
                self._scale_pointer_component(pos[1], src=window_space[1], dst=surface_space[1]),
            )
        if "x" in payload:
            payload["x"] = self._scale_pointer_component(
                payload["x"],
                src=window_space[0],
                dst=surface_space[0],
            )
        if "y" in payload:
            payload["y"] = self._scale_pointer_component(
                payload["y"],
                src=window_space[1],
                dst=surface_space[1],
            )
        rel = payload.get("rel")
        if isinstance(rel, tuple) and len(rel) >= 2:
            payload["rel"] = (
                self._scale_pointer_delta(rel[0], src=window_space[0], dst=surface_space[0]),
                self._scale_pointer_delta(rel[1], src=window_space[1], dst=surface_space[1]),
            )
        return pygame.event.Event(event.type, payload)

    @staticmethod
    def _pressed_key_active(keys: object, key: int) -> bool:
        try:
            return bool(keys[key])
        except Exception:
            return False

    def _poll_keyboard_menu_repeat_actions(self, *, now_ms: int | None = None) -> None:
        if not _KEYBOARD_MENU_REPEAT_ACTIONS:
            return
        now = pygame.time.get_ticks() if now_ms is None else int(now_ms)
        try:
            keys = pygame.key.get_pressed()
        except Exception:
            keys = ()

        current_down: dict[str, bool] = {
            action: any(self._pressed_key_active(keys, key) for key in aliases)
            for action, aliases in _KEYBOARD_MENU_REPEAT_ACTIONS.items()
        }
        if current_down.get("menu_up") and current_down.get("menu_down"):
            current_down["menu_up"] = False
            current_down["menu_down"] = False

        for action in _KEYBOARD_MENU_REPEAT_ACTIONS:
            active = bool(current_down.get(action, False))
            previous = bool(self._keyboard_menu_repeat_down.get(action, False))
            self._keyboard_menu_repeat_down[action] = active
            if active and not previous:
                self._keyboard_menu_repeat_due_ms[action] = (
                    now + _KEYBOARD_MENU_REPEAT_INITIAL_DELAY_MS
                )
                continue
            if active and previous:
                due = self._keyboard_menu_repeat_due_ms.get(action)
                if due is not None and now >= due:
                    self._keyboard_menu_repeat_pending[action] = (
                        self._keyboard_menu_repeat_pending.get(action, 0) + 1
                    )
                    self._keyboard_menu_repeat_due_ms[action] = (
                        now + _KEYBOARD_MENU_REPEAT_INTERVAL_MS
                    )
                continue
            self._keyboard_menu_repeat_due_ms.pop(action, None)

    def set_opengl_enabled(self, enabled: bool) -> None:
        self._opengl_enabled = bool(enabled)
        if not self._opengl_enabled:
            self._gl_scene = None
        self._renderer_path = (
            "MODERN_GL" if self._opengl_enabled else ("HEADLESS" if self._headless_mode else "FALLBACK_2D")
        )

    def push(self, screen: Screen) -> None:
        self._screens.append(screen)

    def replace_top(self, screen: Screen) -> None:
        if not self._screens:
            self.push(screen)
            return
        old = self._screens[-1]
        self._screens[-1] = screen
        close = getattr(old, "close", None)
        if callable(close):
            close()

    def pop(self) -> None:
        # Never pop the last/root screen; root handles its own quit/back behavior.
        if len(self._screens) > 1:
            screen = self._screens.pop()
            close = getattr(screen, "close", None)
            if callable(close):
                close()
        if self._shell_pause_active and not self._screen_has_activity(self._current_screen()):
            self._set_shell_pause_active(False)

    def pop_to_root(self) -> None:
        while len(self._screens) > 1:
            screen = self._screens.pop()
            close = getattr(screen, "close", None)
            if callable(close):
                close()
        if self._shell_pause_active:
            self._set_shell_pause_active(False)

    def quit(self, *, exit_reason: str = "app_quit", exit_code: int = 0) -> None:
        self._exit_reason = str(exit_reason)
        self._exit_code = int(exit_code)
        self._set_shell_pause_active(False)
        for screen in tuple(reversed(self._screens)):
            abort = getattr(screen, "abort_activity", None)
            if callable(abort):
                abort(exit_reason)
        if self._results_store is not None:
            try:
                self._results_store.close_app_session(exit_reason=exit_reason)
            except Exception:
                pass
        self._running = False

    @property
    def exit_code(self) -> int:
        return int(self._exit_code)

    @property
    def exit_reason(self) -> str:
        return str(self._exit_reason)

    def headless_mode(self) -> bool:
        return bool(self._headless_mode)

    def current_run_state(self) -> RunStateIndicator:
        screen = self._current_screen()
        activity_label = self._screen_activity_label(screen)
        if self._shell_pause_active:
            shell_state = "PAUSED"
        elif self._screen_has_activity(screen):
            shell_state = "RUNNING"
        else:
            shell_state = "MENU"
        warning = None
        if self._headless_mode:
            warning = "HEADLESS"
        elif self.used_renderer_fallback():
            warning = "FALLBACK"
        elif self.used_failure_recovery():
            warning = "RECOVERED"
        return RunStateIndicator(
            shell_state=shell_state,
            display_mode=str(self._window_mode).upper(),
            renderer_path=str(self._renderer_path),
            activity_label=activity_label,
            warning=warning,
        )

    def used_renderer_fallback(self) -> bool:
        return bool(self._renderer_fallback_used)

    def used_failure_recovery(self) -> bool:
        return bool(self._failure_recovery_used)

    def shell_pause_overlay_active(self) -> bool:
        return bool(self._shell_pause_active)

    def set_window_mode(self, window_mode: str) -> None:
        token = str(window_mode).strip().lower()
        self._window_mode = token if token in {"windowed", "fullscreen", "borderless"} else "windowed"

    def stored_use_opengl(self) -> bool | None:
        if self._runtime_defaults_store is None:
            return None
        return self._runtime_defaults_store.stored_use_opengl()

    def set_stored_use_opengl(self, value: bool | None) -> None:
        if self._runtime_defaults_store is None:
            return
        self._runtime_defaults_store.set_use_opengl(value)

    @staticmethod
    def use_opengl_env_override() -> str | None:
        raw = os.environ.get("CFAST_USE_OPENGL")
        if raw is None:
            return None
        token = str(raw).strip()
        return token or None

    @classmethod
    def use_opengl_env_forces_enabled(cls) -> bool:
        return _parse_optional_env_bool(cls.use_opengl_env_override()) is True

    def set_renderer_bootstrap_state(
        self,
        *,
        requested: bool,
        attempted: bool,
        failure: OpenGLFailureInfo | None = None,
    ) -> None:
        self._renderer_gl_requested = bool(requested)
        self._renderer_gl_attempted = bool(attempted)
        self._renderer_bootstrap_failure = failure

    def renderer_gl_requested(self) -> bool:
        return bool(self._renderer_gl_requested)

    def renderer_gl_attempted(self) -> bool:
        return bool(self._renderer_gl_attempted)

    def renderer_bootstrap_failure(self) -> OpenGLFailureInfo | None:
        return self._renderer_bootstrap_failure

    def request_renderer_action(self, action: str) -> None:
        token = str(action).strip().lower()
        if token in {"quit"}:
            self._pending_renderer_action = token

    def consume_renderer_action(self) -> str | None:
        action = self._pending_renderer_action
        self._pending_renderer_action = None
        return action

    def note_renderer_fallback(
        self,
        *,
        scene: str | None = None,
        stage: str | None = None,
        path: str | None = None,
    ) -> str | None:
        self._renderer_fallback_used = True
        if scene is None:
            return None
        code = _renderer_diagnostic_code(scene=scene, stage=stage, path=path)
        self._renderer_diagnostic_codes[str(scene).strip().lower()] = code
        return code

    def set_renderer_diagnostic_code(self, scene: str, code: str | None) -> None:
        key = str(scene).strip().lower()
        token = "" if code is None else str(code).strip().upper()
        if token == "":
            self._renderer_diagnostic_codes.pop(key, None)
            return
        self._renderer_diagnostic_codes[key] = token

    def renderer_diagnostic_code(self, scene: str) -> str | None:
        token = self._renderer_diagnostic_codes.get(str(scene).strip().lower())
        return None if token is None or token.strip() == "" else token

    def _renderer_failure_activity_session_id(self) -> int | None:
        screen = self._current_screen()
        handle = getattr(screen, "_activity_session_handle", None)
        value = getattr(handle, "activity_session_id", None)
        if value is None:
            return None
        try:
            return int(value)
        except Exception:
            return None

    def _renderer_failure_state(self, failure: OpenGLFailureInfo) -> dict[str, object]:
        screen = self._current_screen()
        surface_size = self._surface.get_size()
        state: dict[str, object] = {
            "activity_label": self._screen_activity_label(screen),
            "display_mode": str(self._window_mode).upper(),
            "renderer_path": str(self._renderer_path),
            "opengl_enabled": bool(self._opengl_enabled),
            "renderer_gl_requested": bool(self._renderer_gl_requested),
            "renderer_gl_attempted": bool(self._renderer_gl_attempted),
            "headless_mode": bool(self._headless_mode),
            "window_size": [int(surface_size[0]), int(surface_size[1])],
            "video_driver": str(os.environ.get("SDL_VIDEODRIVER", "")).strip(),
        }
        if failure.path:
            state["failure_path"] = str(failure.path)
        if failure.state:
            state.update({str(key): value for key, value in failure.state.items()})
        return state

    def _record_renderer_failure_diagnostic(self, failure: OpenGLFailureInfo) -> None:
        if self._results_store is None:
            return
        try:
            self._results_store.record_app_diagnostic(
                category="renderer_failure",
                subsystem=str(failure.scene).strip().lower() or "renderer",
                status="failed",
                stage=str(failure.stage).strip() or None,
                summary=str(failure.summary).strip() or "Renderer failed.",
                detail=str(failure.detail).strip(),
                diagnostic_code=failure.diagnostic_code,
                renderer_path=failure.path,
                exception_type=failure.exception_type,
                location=failure.location,
                state=self._renderer_failure_state(failure),
                activity_session_id=self._renderer_failure_activity_session_id(),
                app_version=self._app_version,
            )
        except Exception:
            return

    def _should_render_run_state_indicator(self) -> bool:
        state = self.current_run_state()
        return self._dev_tools_enabled or state.warning is not None

    def set_renderer_path(self, path: str) -> None:
        token = str(path).strip().upper()
        self._renderer_path = token or "MODERN_GL"

    def present_renderer_failure(self, failure: OpenGLFailureInfo) -> None:
        scene_key = str(failure.scene).strip().lower()
        if scene_key != "" and failure.diagnostic_code:
            self.set_renderer_diagnostic_code(scene_key, failure.diagnostic_code)
        self._record_renderer_failure_diagnostic(failure)
        self._set_shell_pause_active(False)
        screen = self._current_screen()
        if self._screen_has_activity(screen):
            emergency = getattr(screen, "shell_emergency_exit", None)
            if callable(emergency):
                try:
                    emergency("renderer_failure_abort")
                except Exception:
                    self.pop_to_root()
            else:
                abort = getattr(screen, "abort_activity", None)
                if callable(abort):
                    try:
                        abort("renderer_failure_abort")
                    except Exception:
                        pass
                self.pop_to_root()
        else:
            self.pop_to_root()
        self.push(OpenGLFailureScreen(self, failure=failure))

    def dismiss_renderer_failure(self) -> None:
        screen = self._current_screen()
        if isinstance(screen, OpenGLFailureScreen):
            self.pop()

    def _current_screen(self) -> Screen | None:
        if not self._screens:
            return None
        return self._screens[-1]

    @staticmethod
    def _screen_call_bool(screen: object | None, method_name: str) -> bool:
        if screen is None:
            return False
        method = getattr(screen, method_name, None)
        if not callable(method):
            return False
        try:
            return bool(method())
        except Exception:
            return False

    @staticmethod
    def _screen_call_text(screen: object | None, method_name: str) -> str | None:
        if screen is None:
            return None
        method = getattr(screen, method_name, None)
        if not callable(method):
            return None
        try:
            value = method()
        except Exception:
            return None
        if value is None:
            return None
        text = str(value).strip()
        return text or None

    def _screen_has_activity(self, screen: object | None) -> bool:
        return self._screen_call_bool(screen, "shell_activity_active")

    def _screen_supports_safe_pause(self, screen: object | None) -> bool:
        return self._screen_call_bool(screen, "shell_pause_available")

    def _screen_activity_label(self, screen: object | None) -> str | None:
        return self._screen_call_text(screen, "shell_activity_label")

    @staticmethod
    def _is_emergency_hotkey(event: pygame.event.Event) -> bool:
        if event.type != pygame.KEYDOWN:
            return False
        mod = int(getattr(event, "mod", 0))
        if event.key == pygame.K_F12:
            return True
        return event.key == pygame.K_ESCAPE and bool(mod & pygame.KMOD_SHIFT)

    def _set_menu_banner(self, message: str, *, duration_ms: int = 5200) -> None:
        text = str(message).strip()
        if text == "":
            return
        self._menu_banner_message = text
        self._menu_banner_until_ms = pygame.time.get_ticks() + max(1000, int(duration_ms))

    def _set_shell_pause_active(self, active: bool) -> bool:
        screen = self._current_screen()
        if not active:
            if self._shell_pause_active and screen is not None:
                setter = getattr(screen, "shell_pause_set_active", None)
                if callable(setter):
                    try:
                        setter(False)
                    except Exception:
                        pass
            self._shell_pause_active = False
            self._shell_pause_selected = 0
            self._shell_pause_hitboxes = {}
            self.clear_pending_bound_actions(
                "pause_toggle",
                "menu_up",
                "menu_down",
                "menu_select",
                "menu_back",
            )
            return True
        if screen is None or not self._screen_supports_safe_pause(screen):
            return False
        setter = getattr(screen, "shell_pause_set_active", None)
        if callable(setter):
            setter(True)
        self._shell_pause_active = True
        self._shell_pause_selected = 0
        self._shell_pause_hitboxes = {}
        self.clear_pending_bound_actions("pause_toggle")
        return True

    def _shell_pause_delegates_to_screen(self, screen: object | None) -> bool:
        if screen is None:
            return False
        return self._screen_call_bool(screen, "shell_pause_renders_own_overlay")

    def _sync_shell_pause_screen_state(self, screen: object | None) -> None:
        if not self._shell_pause_active:
            return
        if not self._screen_has_activity(self._current_screen()):
            self._set_shell_pause_active(False)
            return
        if not self._screen_call_bool(screen, "shell_pause_menu_active"):
            self._set_shell_pause_active(False)

    def _shell_pause_items(self) -> tuple[tuple[str, str], ...]:
        return (
            ("resume", "Resume"),
            ("restart", "Restart Current"),
            ("main_menu", "Main Menu"),
            ("quit_app", "Quit App"),
        )

    def _handle_shell_pause_event(self, event: pygame.event.Event) -> None:
        items = self._shell_pause_items()
        if event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for idx, rect in self._shell_pause_hitboxes.items():
                if rect.collidepoint(pos):
                    self._shell_pause_selected = idx
                    return
            return
        if event.type == pygame.MOUSEBUTTONDOWN and getattr(event, "button", 0) == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for idx, rect in self._shell_pause_hitboxes.items():
                if rect.collidepoint(pos):
                    self._shell_pause_selected = idx
                    self._activate_shell_pause_selection()
                    return
            return
        if event.type != pygame.KEYDOWN:
            return
        if event.key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._set_shell_pause_active(False)
            return
        if event.key in (pygame.K_UP, pygame.K_w):
            self._shell_pause_selected = (self._shell_pause_selected - 1) % len(items)
            return
        if event.key in (pygame.K_DOWN, pygame.K_s):
            self._shell_pause_selected = (self._shell_pause_selected + 1) % len(items)
            return
        if event.key in (pygame.K_RETURN, pygame.K_KP_ENTER, pygame.K_SPACE):
            self._activate_shell_pause_selection()

    def _activate_shell_pause_selection(self) -> None:
        screen = self._current_screen()
        items = self._shell_pause_items()
        action = items[self._shell_pause_selected % len(items)][0]
        self._set_shell_pause_active(False)
        if screen is None:
            return
        if action == "resume":
            return
        if action == "restart":
            restart = getattr(screen, "shell_pause_restart", None)
            if callable(restart):
                restart()
            return
        if action == "main_menu":
            to_menu = getattr(screen, "shell_pause_main_menu", None)
            if callable(to_menu):
                to_menu()
            else:
                self.pop_to_root()
            return
        if action == "quit_app":
            emergency = getattr(screen, "shell_emergency_exit", None)
            if callable(emergency):
                emergency("app_quit")
            self.quit(exit_reason="app_quit")

    def _handle_emergency_hotkey(self) -> None:
        self._set_shell_pause_active(False)
        screen = self._current_screen()
        if self._screen_has_activity(screen):
            emergency = getattr(screen, "shell_emergency_exit", None)
            if callable(emergency):
                emergency("emergency_abort")
            else:
                abort = getattr(screen, "abort_activity", None)
                if callable(abort):
                    abort("emergency_abort")
                self.pop_to_root()
            return
        self.quit(exit_reason="emergency_abort")

    def recover_to_menu(self, *, reason: str, detail: str) -> None:
        self._failure_recovery_used = True
        self._set_shell_pause_active(False)
        self._set_menu_banner(f"Recovered to menu after {detail}.")
        screen = self._current_screen()
        if self._screen_has_activity(screen):
            emergency = getattr(screen, "shell_emergency_exit", None)
            if callable(emergency):
                try:
                    emergency(str(reason))
                except Exception:
                    self.pop_to_root()
            else:
                abort = getattr(screen, "abort_activity", None)
                if callable(abort):
                    try:
                        abort(str(reason))
                    except Exception:
                        pass
                self.pop_to_root()
            return
        self.quit(exit_reason=str(reason), exit_code=1)

    def handle_event(self, event: pygame.event.Event) -> None:
        event = self._normalize_pointer_event(event)
        if event.type == pygame.QUIT:
            self.quit()
            return
        if event.type == pygame.KEYDOWN:
            mod = int(getattr(event, "mod", 0))
            if event.key == pygame.K_q and (mod & (pygame.KMOD_CTRL | pygame.KMOD_META)):
                self.quit()
                return
        if self._is_emergency_hotkey(event):
            self._handle_emergency_hotkey()
            return
        if self._shell_pause_active:
            screen = self._current_screen()
            if self._shell_pause_delegates_to_screen(screen):
                handler = getattr(screen, "shell_pause_handle_event", None)
                if callable(handler):
                    try:
                        handler(event)
                    except Exception:
                        self.recover_to_menu(reason="input_failure_abort", detail="input failure")
                        return
                    self._sync_shell_pause_screen_state(screen)
                    return
            self._handle_shell_pause_event(event)
            return
        screen = self._current_screen()
        if (
            event.type == pygame.KEYDOWN
            and event.key == pygame.K_ESCAPE
            and self._screen_supports_safe_pause(screen)
        ):
            self._set_shell_pause_active(True)
            return
        if screen is None:
            return
        try:
            screen.handle_event(event)
        except Exception:
            self.recover_to_menu(reason="input_failure_abort", detail="input failure")

    def render(self) -> None:
        if not self._screens:
            return
        try:
            self._joystick_binding_router.poll()
            self._poll_keyboard_menu_repeat_actions()
        except Exception:
            self.recover_to_menu(reason="input_failure_abort", detail="input failure")
            return
        screen = self._current_screen()
        if screen is None:
            return
        if self._shell_pause_active:
            if self._shell_pause_delegates_to_screen(screen):
                while self.consume_bound_action("pause_toggle"):
                    handler = getattr(screen, "shell_pause_handle_event", None)
                    if callable(handler):
                        handler(
                            pygame.event.Event(
                                pygame.KEYDOWN,
                                {"key": pygame.K_ESCAPE, "unicode": ""},
                            )
                        )
                        self._sync_shell_pause_screen_state(screen)
                while self.consume_bound_action("menu_up"):
                    handler = getattr(screen, "shell_pause_handle_event", None)
                    if callable(handler):
                        handler(
                            pygame.event.Event(
                                pygame.KEYDOWN,
                                {"key": pygame.K_UP, "unicode": ""},
                            )
                        )
                while self.consume_bound_action("menu_down"):
                    handler = getattr(screen, "shell_pause_handle_event", None)
                    if callable(handler):
                        handler(
                            pygame.event.Event(
                                pygame.KEYDOWN,
                                {"key": pygame.K_DOWN, "unicode": ""},
                            )
                        )
                while self.consume_bound_action("menu_left"):
                    handler = getattr(screen, "shell_pause_handle_event", None)
                    if callable(handler):
                        handler(
                            pygame.event.Event(
                                pygame.KEYDOWN,
                                {"key": pygame.K_LEFT, "unicode": ""},
                            )
                        )
                while self.consume_bound_action("menu_right"):
                    handler = getattr(screen, "shell_pause_handle_event", None)
                    if callable(handler):
                        handler(
                            pygame.event.Event(
                                pygame.KEYDOWN,
                                {"key": pygame.K_RIGHT, "unicode": ""},
                            )
                        )
                while self.consume_bound_action("menu_select"):
                    handler = getattr(screen, "shell_pause_handle_event", None)
                    if callable(handler):
                        handler(
                            pygame.event.Event(
                                pygame.KEYDOWN,
                                {"key": pygame.K_RETURN, "unicode": ""},
                            )
                        )
                while self.consume_bound_action("menu_back"):
                    handler = getattr(screen, "shell_pause_handle_event", None)
                    if callable(handler):
                        handler(
                            pygame.event.Event(
                                pygame.KEYDOWN,
                                {"key": pygame.K_ESCAPE, "unicode": ""},
                            )
                        )
                        self._sync_shell_pause_screen_state(screen)
                self._sync_shell_pause_screen_state(screen)
            else:
                if self.consume_bound_action("pause_toggle"):
                    self._set_shell_pause_active(False)
                while self.consume_bound_action("menu_up"):
                    self._shell_pause_selected = (self._shell_pause_selected - 1) % len(
                        self._shell_pause_items()
                    )
                while self.consume_bound_action("menu_down"):
                    self._shell_pause_selected = (self._shell_pause_selected + 1) % len(
                        self._shell_pause_items()
                    )
                while self.consume_bound_action("menu_select"):
                    self._activate_shell_pause_selection()
                while self.consume_bound_action("menu_back"):
                    self._set_shell_pause_active(False)
        else:
            if self._screen_supports_safe_pause(screen) and self.consume_bound_action("pause_toggle"):
                self._set_shell_pause_active(True)
            else:
                poll_bound_input = getattr(screen, "poll_bound_input", None)
                if callable(poll_bound_input):
                    try:
                        poll_bound_input()
                    except Exception:
                        self.recover_to_menu(reason="input_failure_abort", detail="input failure")
                        return
        if not self._screens:
            return
        self._gl_scene = None
        try:
            self._screens[-1].render(self._surface)
        except Exception:
            self.recover_to_menu(reason="runtime_failure_abort", detail="runtime failure")
            return
        if not self._screens:
            return
        if self._shell_pause_active and not self._shell_pause_delegates_to_screen(self._current_screen()):
            self._render_shell_pause_overlay(self._surface)
        self._render_menu_banner(self._surface)
        if self._should_render_run_state_indicator():
            self._render_run_state_indicator(self._surface)

    def queue_gl_scene(self, scene: GlScene) -> None:
        if not self._opengl_enabled:
            return
        self._gl_scene = scene

    def consume_gl_scene(self) -> GlScene | None:
        return self._gl_scene

    def queue_auditory_gl_scene(
        self,
        *,
        world: pygame.Rect,
        payload: AuditoryCapacityPayload | None,
        time_remaining_s: float | None,
        time_fill_ratio: float | None,
    ) -> None:
        self.queue_gl_scene(
            AuditoryGlScene(
                world=pygame.Rect(world),
                payload=payload,
                time_remaining_s=time_remaining_s,
                time_fill_ratio=time_fill_ratio,
            )
        )

    def consume_auditory_gl_scene(self) -> AuditoryGlScene | None:
        scene = self.consume_gl_scene()
        if isinstance(scene, AuditoryGlScene):
            return scene
        return None

    def start_activity_session(
        self,
        *,
        owner: object,
        activity_code: str,
        activity_kind: str,
        engine: object,
        test_version: int = 1,
    ) -> None:
        if self._results_store is None:
            return
        owner_id = id(owner)
        if owner_id in self._activity_sessions:
            return
        try:
            activity_session_id = self._results_store.start_activity_session(
                activity_code=activity_code,
                activity_kind=activity_kind,
                app_version=self._app_version,
                test_version=test_version,
                engine=engine,
                input_profile_id=self.active_input_profile_id(),
            )
        except Exception:
            return
        self._activity_sessions[owner_id] = _ActiveActivitySession(
            activity_session_id=activity_session_id,
            activity_code=str(activity_code),
            activity_kind=str(activity_kind),
            test_version=int(test_version),
        )

    def complete_activity_session(
        self,
        *,
        owner: object,
        engine: object,
        test_code: str,
        test_version: int = 1,
        completion_reason: str = "completed",
    ) -> list[str]:
        if self._results_store is None:
            return []
        try:
            result = attempt_result_from_engine(
                engine,
                test_code=test_code,
                test_version=test_version,
            )
            handle = self._activity_sessions.pop(id(owner), None)
            if handle is None:
                self._results_store.record_attempt(
                    result=result,
                    app_version=self._app_version,
                    input_profile_id=self.active_input_profile_id(),
                )
            else:
                self._results_store.complete_activity_session(
                    activity_session_id=handle.activity_session_id,
                    result=result,
                    app_version=self._app_version,
                    input_profile_id=self.active_input_profile_id(),
                    completion_reason=str(completion_reason),
                )
            return self._build_persistence_summary_lines(test_code=test_code)
        except Exception:
            return ["Local save failed."]

    def record_child_attempt(
        self,
        *,
        parent_owner: object,
        result: AttemptResult,
        activity_code: str | None = None,
        activity_kind: str,
        origin_item_index: int | None = None,
        origin_activity_code: str | None = None,
        origin_activity_kind: str | None = None,
        test_version: int | None = None,
    ) -> None:
        if self._results_store is None:
            return
        parent_handle = self._activity_sessions.get(id(parent_owner))
        parent_activity_session_id = (
            None if parent_handle is None else int(parent_handle.activity_session_id)
        )
        if origin_activity_code is None and parent_handle is not None:
            origin_activity_code = parent_handle.activity_code
        if origin_activity_kind is None and parent_handle is not None:
            origin_activity_kind = parent_handle.activity_kind
        try:
            self._results_store.record_attempt(
                result=result,
                app_version=self._app_version,
                input_profile_id=self.active_input_profile_id(),
                activity_code=str(activity_code or result.test_code),
                activity_kind=str(activity_kind),
                test_version=result.test_version if test_version is None else int(test_version),
                parent_activity_session_id=parent_activity_session_id,
                origin_activity_code=origin_activity_code,
                origin_activity_kind=origin_activity_kind,
                origin_item_index=origin_item_index,
            )
        except Exception:
            return

    def abort_activity_session(
        self,
        *,
        owner: object,
        engine: object | None,
        completion_reason: str,
        test_code: str | None,
        test_version: int = 1,
    ) -> None:
        if self._results_store is None:
            return
        handle = self._activity_sessions.pop(id(owner), None)
        if handle is None:
            return
        result = None
        if engine is not None and test_code:
            try:
                result = attempt_result_from_engine(
                    engine,
                    test_code=str(test_code),
                    test_version=int(test_version),
                )
            except Exception:
                result = None
        try:
            self._results_store.abort_activity_session(
                activity_session_id=handle.activity_session_id,
                app_version=self._app_version,
                completion_reason=completion_reason,
                result=result,
                input_profile_id=self.active_input_profile_id(),
            )
        except Exception:
            return

    def active_input_profile_id(self) -> str | None:
        if self._input_profiles_store is None:
            return None
        try:
            return str(self._input_profiles_store.active_profile().profile_id)
        except Exception:
            return None

    def input_profiles_store(self) -> InputProfilesStore | None:
        return self._input_profiles_store

    def bound_axis_role_value(self, role: str) -> float | None:
        return self._joystick_binding_router.analog_value(role=str(role))

    def has_explicit_axis_role_binding(self, role: str) -> bool:
        return self._joystick_binding_router.has_explicit_axis_binding(role=str(role))

    def has_explicit_action_binding(self, action: str) -> bool:
        return self._joystick_binding_router.has_explicit_action_binding(action=str(action))

    def consume_bound_action(self, action: str) -> bool:
        token = str(action)
        if self._joystick_binding_router.consume_action(token):
            return True
        pending = self._keyboard_menu_repeat_pending.get(token, 0)
        if pending <= 0:
            return False
        self._keyboard_menu_repeat_pending[token] = pending - 1
        return True

    def bound_action_active(self, action: str) -> bool:
        token = str(action)
        if self._joystick_binding_router.action_active(action=token):
            return True
        return bool(self._keyboard_menu_repeat_down.get(token, False))

    def clear_pending_bound_actions(self, *actions: str) -> None:
        self._joystick_binding_router.clear_pending_actions(*actions)
        if not actions:
            self._keyboard_menu_repeat_pending.clear()
            self._keyboard_menu_repeat_due_ms.clear()
            for action in self._keyboard_menu_repeat_down:
                self._keyboard_menu_repeat_down[action] = False
            return
        for action in actions:
            token = str(action)
            self._keyboard_menu_repeat_pending.pop(token, None)
            self._keyboard_menu_repeat_due_ms.pop(token, None)
            if token in self._keyboard_menu_repeat_down:
                self._keyboard_menu_repeat_down[token] = False

    def effective_difficulty_level(self, test_code: str | None) -> int:
        if self._difficulty_settings_store is None or not test_code:
            return DEFAULT_DIFFICULTY_LEVEL
        return self._difficulty_settings_store.effective_level(str(test_code))

    def effective_difficulty_ratio(self, test_code: str | None) -> float:
        level = self.effective_difficulty_level(test_code)
        return (max(1, min(10, int(level))) - 1) / 9.0

    def stored_test_difficulty_level(self, test_code: str | None) -> int:
        if self._difficulty_settings_store is None or not test_code:
            return DEFAULT_DIFFICULTY_LEVEL
        return self._difficulty_settings_store.test_level(str(test_code))

    def stored_global_difficulty_level(self) -> int:
        if self._difficulty_settings_store is None:
            return DEFAULT_DIFFICULTY_LEVEL
        return self._difficulty_settings_store.global_level()

    def difficulty_override_enabled(self) -> bool:
        if self._difficulty_settings_store is None:
            return False
        return self._difficulty_settings_store.global_override_enabled()

    def intro_difficulty_mode_label(self, test_code: str | None) -> str:
        if self._difficulty_settings_store is None or not test_code:
            return "Session"
        return self._difficulty_settings_store.intro_mode_label(str(test_code))

    def set_persistent_difficulty_level(self, *, test_code: str | None, level: int) -> int:
        clamped = max(1, min(10, int(level)))
        if self._difficulty_settings_store is None or not test_code:
            return clamped
        if self._difficulty_settings_store.global_override_enabled():
            self._difficulty_settings_store.set_global_level(clamped)
            return self._difficulty_settings_store.global_level()
        self._difficulty_settings_store.set_test_level(test_code=str(test_code), level=clamped)
        return self._difficulty_settings_store.test_level(str(test_code))

    def set_global_difficulty_override_enabled(self, enabled: bool) -> None:
        if self._difficulty_settings_store is None:
            return
        self._difficulty_settings_store.set_global_override_enabled(enabled)

    def set_global_difficulty_level(self, level: int) -> int:
        clamped = max(1, min(10, int(level)))
        if self._difficulty_settings_store is None:
            return clamped
        self._difficulty_settings_store.set_global_level(clamped)
        return self._difficulty_settings_store.global_level()

    def set_test_difficulty_level(self, *, test_code: str, level: int) -> int:
        clamped = max(1, min(10, int(level)))
        if self._difficulty_settings_store is None:
            return clamped
        self._difficulty_settings_store.set_test_level(test_code=test_code, level=clamped)
        return self._difficulty_settings_store.test_level(test_code)

