class InputProfilesStore:
    _version = 1

    def __init__(self, path: Path) -> None:
        self._path = path
        self._profiles: list[InputProfile] = [InputProfile("default", "Default", {})]
        self._active_profile_id = "default"
        self._load()

    @classmethod
    def default_path(cls) -> Path:
        explicit = os.environ.get(INPUT_PROFILE_STORE_ENV)
        if explicit:
            return Path(explicit).expanduser()
        return Path.home() / ".rcaf_cfast_input_profiles.json"

    def _load(self) -> None:
        if not self._path.exists():
            return
        try:
            payload = json.loads(self._path.read_text(encoding="utf-8"))
        except Exception:
            return
        if not isinstance(payload, dict):
            return

        raw_profiles = payload.get("profiles")
        if not isinstance(raw_profiles, list):
            return

        loaded_profiles: list[InputProfile] = []
        for item in raw_profiles:
            if not isinstance(item, dict):
                continue
            profile_id = str(item.get("id", "")).strip()
            name = str(item.get("name", "")).strip()
            if profile_id == "":
                continue
            if name == "":
                name = profile_id
            raw_axes = item.get("axis_calibrations")
            axis_calibrations: dict[str, AxisCalibrationSettings] = {}
            if isinstance(raw_axes, dict):
                for axis_key, settings in raw_axes.items():
                    axis_calibrations[str(axis_key)] = AxisCalibrationSettings.from_dict(settings)
            raw_axis_role_bindings = item.get("axis_role_bindings")
            axis_role_bindings: dict[str, AnalogBinding] = {}
            if isinstance(raw_axis_role_bindings, dict):
                for role, binding_data in raw_axis_role_bindings.items():
                    binding = AnalogBinding.from_dict(binding_data)
                    if binding is not None:
                        axis_role_bindings[str(role)] = binding
            raw_action_bindings = item.get("action_bindings")
            action_bindings: dict[str, list[DigitalBinding | None]] = {}
            if isinstance(raw_action_bindings, dict):
                for action, bindings_data in raw_action_bindings.items():
                    if not isinstance(bindings_data, list):
                        continue
                    bindings: list[DigitalBinding | None] = []
                    for binding_data in bindings_data[:ACTION_BINDING_SLOT_COUNT]:
                        if binding_data is None:
                            bindings.append(None)
                            continue
                        bindings.append(DigitalBinding.from_dict(binding_data))
                    if any(binding is not None for binding in bindings):
                        action_bindings[str(action)] = bindings
            loaded_profiles.append(
                InputProfile(
                    profile_id=profile_id,
                    name=name,
                    axis_calibrations=axis_calibrations,
                    axis_role_bindings=axis_role_bindings,
                    action_bindings=action_bindings,
                )
            )

        if loaded_profiles:
            self._profiles = loaded_profiles
        raw_active = str(payload.get("active_profile_id", "")).strip()
        if raw_active != "" and any(p.profile_id == raw_active for p in self._profiles):
            self._active_profile_id = raw_active
        else:
            self._active_profile_id = self._profiles[0].profile_id

    def save(self) -> None:
        payload = {
            "version": self._version,
            "active_profile_id": self._active_profile_id,
            "profiles": [profile.to_dict() for profile in self._profiles],
        }
        try:
            self._path.parent.mkdir(parents=True, exist_ok=True)
            tmp_path = self._path.with_suffix(f"{self._path.suffix}.tmp")
            tmp_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
            tmp_path.replace(self._path)
        except Exception:
            return

    def profiles(self) -> list[InputProfile]:
        return list(self._profiles)

    def active_profile(self) -> InputProfile:
        for profile in self._profiles:
            if profile.profile_id == self._active_profile_id:
                return profile
        self._active_profile_id = self._profiles[0].profile_id
        return self._profiles[0]

    def set_active_profile(self, profile_id: str) -> None:
        if any(profile.profile_id == profile_id for profile in self._profiles):
            self._active_profile_id = profile_id
            self.save()

    def create_profile(self, *, name: str, copy_from: InputProfile | None) -> InputProfile:
        candidate = str(name).strip()
        if candidate == "":
            candidate = "Profile"
        profile_id = self._next_profile_id(candidate)
        copied: dict[str, AxisCalibrationSettings] = {}
        copied_axis_bindings: dict[str, AnalogBinding] = {}
        copied_action_bindings: dict[str, list[DigitalBinding | None]] = {}
        if copy_from is not None:
            copied = {
                axis_key: AxisCalibrationSettings.from_dict(settings.to_dict())
                for axis_key, settings in copy_from.axis_calibrations.items()
            }
            copied_axis_bindings = {
                role: cast(AnalogBinding, AnalogBinding.from_dict(binding.to_dict()))
                for role, binding in copy_from.axis_role_bindings.items()
                if AnalogBinding.from_dict(binding.to_dict()) is not None
            }
            copied_action_bindings = {
                action: [
                    None
                    if binding is None
                    else cast(DigitalBinding, DigitalBinding.from_dict(binding.to_dict()))
                    for binding in bindings
                ]
                for action, bindings in copy_from.action_bindings.items()
            }
        profile = InputProfile(
            profile_id=profile_id,
            name=candidate,
            axis_calibrations=copied,
            axis_role_bindings=copied_axis_bindings,
            action_bindings=copied_action_bindings,
        )
        self._profiles.append(profile)
        self._active_profile_id = profile.profile_id
        self.save()
        return profile

    def delete_profile(self, profile_id: str) -> bool:
        if len(self._profiles) <= 1:
            return False
        idx = next((i for i, p in enumerate(self._profiles) if p.profile_id == profile_id), -1)
        if idx < 0:
            return False
        del self._profiles[idx]
        if not any(p.profile_id == self._active_profile_id for p in self._profiles):
            self._active_profile_id = self._profiles[max(0, idx - 1)].profile_id
        self.save()
        return True

    def rename_profile(self, profile_id: str, new_name: str) -> bool:
        cleaned = str(new_name).strip()
        if cleaned == "":
            return False
        for profile in self._profiles:
            if profile.profile_id == profile_id:
                profile.name = cleaned
                self.save()
                return True
        return False

    def get_axis_calibration(
        self,
        *,
        profile_id: str,
        axis_key: str,
    ) -> AxisCalibrationSettings:
        for profile in self._profiles:
            if profile.profile_id != profile_id:
                continue
            found = profile.axis_calibrations.get(axis_key)
            if found is None:
                found = AxisCalibrationSettings()
                profile.axis_calibrations[axis_key] = found
            return found
        return AxisCalibrationSettings()

    def set_axis_calibration(
        self,
        *,
        profile_id: str,
        axis_key: str,
        settings: AxisCalibrationSettings,
    ) -> None:
        for profile in self._profiles:
            if profile.profile_id == profile_id:
                profile.axis_calibrations[axis_key] = AxisCalibrationSettings.from_dict(
                    settings.to_dict()
                )
                self.save()
                return

    def get_axis_role_binding(self, *, profile_id: str, role: str) -> AnalogBinding | None:
        for profile in self._profiles:
            if profile.profile_id == profile_id:
                binding = profile.axis_role_bindings.get(str(role))
                if binding is None:
                    return None
                return AnalogBinding.from_dict(binding.to_dict())
        return None

    def set_axis_role_binding(
        self,
        *,
        profile_id: str,
        role: str,
        binding: AnalogBinding | None,
    ) -> None:
        for profile in self._profiles:
            if profile.profile_id != profile_id:
                continue
            if binding is None:
                profile.axis_role_bindings.pop(str(role), None)
            else:
                profile.axis_role_bindings[str(role)] = cast(
                    AnalogBinding, AnalogBinding.from_dict(binding.to_dict())
                )
            self.save()
            return

    def get_action_bindings(self, *, profile_id: str, action: str) -> list[DigitalBinding]:
        for profile in self._profiles:
            if profile.profile_id != profile_id:
                continue
            bindings = profile.action_bindings.get(str(action), [])
            out: list[DigitalBinding] = []
            for binding in bindings[:ACTION_BINDING_SLOT_COUNT]:
                if binding is None:
                    continue
                parsed = DigitalBinding.from_dict(binding.to_dict())
                if parsed is not None:
                    out.append(parsed)
            return out
        return []

    def get_action_binding_slots(
        self,
        *,
        profile_id: str,
        action: str,
    ) -> list[DigitalBinding | None]:
        for profile in self._profiles:
            if profile.profile_id != profile_id:
                continue
            bindings = list(profile.action_bindings.get(str(action), []))
            while len(bindings) < ACTION_BINDING_SLOT_COUNT:
                bindings.append(None)
            out: list[DigitalBinding | None] = []
            for binding in bindings[:ACTION_BINDING_SLOT_COUNT]:
                if binding is None:
                    out.append(None)
                else:
                    out.append(DigitalBinding.from_dict(binding.to_dict()))
            return out
        return [None for _ in range(ACTION_BINDING_SLOT_COUNT)]

    def set_action_binding(
        self,
        *,
        profile_id: str,
        action: str,
        slot_index: int,
        binding: DigitalBinding | None,
    ) -> None:
        slot = max(0, min(ACTION_BINDING_SLOT_COUNT - 1, int(slot_index)))
        for profile in self._profiles:
            if profile.profile_id != profile_id:
                continue
            key = str(action)
            existing = list(profile.action_bindings.get(key, []))
            while len(existing) <= slot:
                existing.append(None)
            if binding is None:
                existing[slot] = None
            else:
                parsed = DigitalBinding.from_dict(binding.to_dict())
                if parsed is None:
                    return
                existing[slot] = parsed
            while existing and existing[-1] is None:
                existing.pop()
            if existing:
                profile.action_bindings[key] = existing[:ACTION_BINDING_SLOT_COUNT]
            else:
                profile.action_bindings.pop(key, None)
            self.save()
            return

    def _next_profile_id(self, base_name: str) -> str:
        base = "".join(ch.lower() if ch.isalnum() else "_" for ch in base_name).strip("_")
        if base == "":
            base = "profile"
        candidate = base
        suffix = 2
        existing = {profile.profile_id for profile in self._profiles}
        while candidate in existing:
            candidate = f"{base}_{suffix}"
            suffix += 1
        return candidate


def _as_float(value: object, fallback: float) -> float:
    try:
        return float(value)
    except Exception:
        return fallback


def _clamp(value: float, lo: float, hi: float) -> float:
    if value <= lo:
        return lo
    if value >= hi:
        return hi
    return float(value)


def _iter_connected_joysticks() -> list[pygame.joystick.Joystick]:
    joysticks: list[pygame.joystick.Joystick] = []
    try:
        count = int(pygame.joystick.get_count())
    except Exception:
        return joysticks
    for idx in range(count):
        try:
            js = pygame.joystick.Joystick(idx)
            if not js.get_init():
                js.init()
            joysticks.append(js)
        except Exception:
            continue
    return joysticks


def _joystick_name_lower(joystick: pygame.joystick.Joystick | None) -> str:
    if joystick is None:
        return ""
    getter = getattr(joystick, "get_name", None)
    if not callable(getter):
        return ""
    try:
        return str(getter()).strip().lower()
    except Exception:
        return ""


def _joystick_axis_count(joystick: pygame.joystick.Joystick | None) -> int:
    if joystick is None:
        return 0
    getter = getattr(joystick, "get_numaxes", None)
    if not callable(getter):
        return 0
    try:
        return max(0, int(getter()))
    except Exception:
        return 0


def _joystick_is_rudder_device(joystick: pygame.joystick.Joystick | None) -> bool:
    name = _joystick_name_lower(joystick)
    return any(token in name for token in _RUDDER_DEVICE_NAME_HINTS)


def _primary_stick_sort_key(joystick: pygame.joystick.Joystick) -> tuple[int, int, int, str]:
    name = _joystick_name_lower(joystick)
    primary_hint_score = sum(1 for token in _PRIMARY_STICK_NAME_HINTS if token in name)
    axis_count = _joystick_axis_count(joystick)
    return (
        1 if _joystick_is_rudder_device(joystick) else 0,
        -primary_hint_score,
        -axis_count,
        name,
    )


def _select_primary_stick(
    joysticks: Sequence[pygame.joystick.Joystick],
) -> pygame.joystick.Joystick | None:
    devices = list(joysticks)
    if not devices:
        return None
    return sorted(devices, key=_primary_stick_sort_key)[0]


def _select_rudder_device(
    joysticks: Sequence[pygame.joystick.Joystick],
) -> pygame.joystick.Joystick | None:
    devices = [joystick for joystick in joysticks if _joystick_is_rudder_device(joystick)]
    if not devices:
        return None
    return sorted(
        devices,
        key=lambda joystick: (
            -int("rudder" in _joystick_name_lower(joystick)),
            -int("pedal" in _joystick_name_lower(joystick)),
            -_joystick_axis_count(joystick),
            _joystick_name_lower(joystick),
        ),
    )[0]


def _joystick_guid(joystick: pygame.joystick.Joystick) -> str:
    getter = getattr(joystick, "get_guid", None)
    if callable(getter):
        try:
            value = str(getter()).strip()
            if value != "":
                return value
        except Exception:
            pass
    return ""


def _joystick_key(joystick: pygame.joystick.Joystick) -> str:
    name = str(joystick.get_name())
    guid = _joystick_guid(joystick)
    return f"{name}|{guid}" if guid != "" else name


def _axis_key(joystick: pygame.joystick.Joystick, axis_index: int) -> str:
    return f"{_joystick_key(joystick)}::axis{int(axis_index)}"


def _axis_raw_value(joystick: pygame.joystick.Joystick, axis_index: int) -> float:
    try:
        return _clamp(float(joystick.get_axis(axis_index)), -1.0, 1.0)
    except Exception:
        return 0.0


def _read_preferred_axis_value(
    *,
    joystick: pygame.joystick.Joystick | None,
    indices: Sequence[int],
    reader: Callable[[pygame.joystick.Joystick, int], float | None],
) -> float | None:
    if joystick is None:
        return None
    axis_count = _joystick_axis_count(joystick)
    for axis_index in indices:
        if axis_index < 0 or axis_index >= axis_count:
            continue
        value = reader(joystick, int(axis_index))
        if value is not None:
            return value
    return None


def _apply_axis_calibration(raw: float, settings: AxisCalibrationSettings) -> float:
    value = _clamp(float(raw), -1.0, 1.0)
    if settings.invert:
        value = -value

    pos_span = max(0.001, float(settings.max_raw))
    neg_span = max(0.001, abs(float(settings.min_raw)))
    normalized = value / (pos_span if value >= 0.0 else neg_span)
    normalized = _clamp(normalized, -1.0, 1.0)

    deadzone = _clamp(float(settings.deadzone), 0.0, 0.45)
    magnitude = abs(normalized)
    if magnitude <= deadzone:
        normalized = 0.0
    else:
        scaled = (magnitude - deadzone) / max(0.001, 1.0 - deadzone)
        normalized = math.copysign(scaled, normalized)

    curve = _clamp(float(settings.curve), 0.4, 2.6)
    curved = math.copysign(abs(normalized) ** curve, normalized)
    return _clamp(curved, -1.0, 1.0)


def _draw_axis_bar(
    surface: pygame.Surface,
    rect: pygame.Rect,
    value: float,
    *,
    fill_color: tuple[int, int, int],
    line_color: tuple[int, int, int],
) -> None:
    pygame.draw.rect(surface, (7, 14, 95), rect)
    pygame.draw.rect(surface, line_color, rect, 1)
    center_x = rect.x + rect.w // 2
    pygame.draw.line(surface, line_color, (center_x, rect.y + 2), (center_x, rect.bottom - 2), 1)

    value = _clamp(value, -1.0, 1.0)
    if abs(value) < 0.001:
        return
    if value > 0.0:
        width = int((rect.w // 2 - 2) * value)
        fill = pygame.Rect(center_x, rect.y + 2, max(1, width), rect.h - 4)
    else:
        width = int((rect.w // 2 - 2) * abs(value))
        fill = pygame.Rect(center_x - width, rect.y + 2, max(1, width), rect.h - 4)
    pygame.draw.rect(surface, fill_color, fill)


def _binding_label(options: tuple[tuple[str, str], ...], key: str) -> str:
    token = str(key)
    for option_key, label in options:
        if option_key == token:
            return label
    return token.replace("_", " ").title()


def _hat_matches_direction(value: tuple[int, int], direction: str | None) -> bool:
    if direction == "up":
        return value[1] > 0
    if direction == "down":
        return value[1] < 0
    if direction == "left":
        return value[0] < 0
    if direction == "right":
        return value[0] > 0
    return False


def _describe_analog_binding(binding: AnalogBinding | None) -> str:
    if binding is None:
        return "AUTO"
    device = binding.device_key.split("|", 1)[0].strip() or binding.device_key
    return f"{device} A{binding.axis_index}"


def _describe_digital_binding(binding: DigitalBinding | None) -> str:
    if binding is None:
        return "AUTO"
    device = binding.device_key.split("|", 1)[0].strip() or binding.device_key
    if binding.kind == "button":
        return f"{device} B{binding.control_index}"
    if binding.kind == "hat":
        direction = str(binding.direction or "").upper()
        return f"{device} Hat{binding.control_index} {direction}".strip()
    direction = "+" if binding.direction == "+" else "-"
    return f"{device} A{binding.control_index} {direction}"


class JoystickBindingRouter:
    def __init__(self, *, profiles: InputProfilesStore | None) -> None:
        self._profiles = profiles
        self._axis_values: dict[tuple[str, int], float] = {}
        self._action_down: dict[str, bool] = {}
        self._action_pending: dict[str, int] = {}
        self._action_repeat_due_ms: dict[str, int] = {}
        self._digital_binding_active: dict[tuple[str, str, int, str | None], bool] = {}

    def poll(self, *, now_ms: int | None = None) -> None:
        now = pygame.time.get_ticks() if now_ms is None else int(now_ms)
        profile = None if self._profiles is None else self._profiles.active_profile()
        joysticks = _iter_connected_joysticks()
        axis_values: dict[tuple[str, int], float] = {}
        pressed_buttons: set[tuple[str, int]] = set()
        hat_values: dict[tuple[str, int], tuple[int, int]] = {}

        for joystick in joysticks:
            device_key = _joystick_key(joystick)
            axis_count = max(0, int(getattr(joystick, "get_numaxes", lambda: 0)()))
            for axis_index in range(axis_count):
                raw = _axis_raw_value(joystick, axis_index)
                calibrated = raw
                if profile is not None:
                    settings = self._profiles.get_axis_calibration(
                        profile_id=profile.profile_id,
                        axis_key=_axis_key(joystick, axis_index),
                    )
                    calibrated = _apply_axis_calibration(raw, settings)
                axis_values[(device_key, axis_index)] = calibrated

            button_count = max(0, int(getattr(joystick, "get_numbuttons", lambda: 0)()))
            for button_index in range(button_count):
                try:
                    if bool(joystick.get_button(button_index)):
                        pressed_buttons.add((device_key, button_index))
                except Exception:
                    continue

            hat_count = max(0, int(getattr(joystick, "get_numhats", lambda: 0)()))
            for hat_index in range(hat_count):
                try:
                    value = joystick.get_hat(hat_index)
                except Exception:
                    continue
                if isinstance(value, tuple) and len(value) == 2:
                    hat_values[(device_key, hat_index)] = (int(value[0]), int(value[1]))

        self._axis_values = axis_values
        if profile is None:
            self._action_down.clear()
            self._action_repeat_due_ms.clear()
            self._digital_binding_active.clear()
            return

        for action, _label in DIGITAL_BINDING_ACTION_OPTIONS:
            bindings = self._profiles.get_action_binding_slots(
                profile_id=profile.profile_id,
                action=action,
            )
            if not any(binding is not None for binding in bindings):
                self._action_down[action] = False
                self._action_repeat_due_ms.pop(action, None)
                continue

            current_down = False
            for binding in bindings:
                if binding is None:
                    continue
                if binding.kind == "button":
                    if (binding.device_key, binding.control_index) in pressed_buttons:
                        current_down = True
                        break
                    continue
                if binding.kind == "hat":
                    hat_value = hat_values.get((binding.device_key, binding.control_index), (0, 0))
                    if _hat_matches_direction(hat_value, binding.direction):
                        current_down = True
                        break
                    continue

                signature = (
                    binding.kind,
                    binding.device_key,
                    binding.control_index,
                    binding.direction,
                )
                prev_active = self._digital_binding_active.get(signature, False)
                threshold = (
                    _DIGITAL_AXIS_RELEASE_THRESHOLD if prev_active else _DIGITAL_AXIS_PRESS_THRESHOLD
                )
                axis_value = axis_values.get((binding.device_key, binding.control_index), 0.0)
                if binding.direction == "+":
                    active = axis_value >= threshold
                else:
                    active = axis_value <= -threshold
                self._digital_binding_active[signature] = active
                if active:
                    current_down = True
                    break

            previous_down = self._action_down.get(action, False)
            self._action_down[action] = current_down
            if action in MENU_REPEAT_ACTIONS:
                if current_down and not previous_down:
                    self._action_pending[action] = self._action_pending.get(action, 0) + 1
                    self._action_repeat_due_ms[action] = now + 260
                elif current_down and previous_down:
                    due = self._action_repeat_due_ms.get(action)
                    if due is not None and now >= due:
                        self._action_pending[action] = self._action_pending.get(action, 0) + 1
                        self._action_repeat_due_ms[action] = now + 110
                else:
                    self._action_repeat_due_ms.pop(action, None)
            else:
                if current_down and not previous_down:
                    self._action_pending[action] = self._action_pending.get(action, 0) + 1

    def analog_value(self, *, role: str) -> float | None:
        if self._profiles is None:
            return None
        profile = self._profiles.active_profile()
        binding = self._profiles.get_axis_role_binding(profile_id=profile.profile_id, role=role)
        if binding is None:
            return None
        axis_key = (binding.device_key, binding.axis_index)
        if axis_key not in self._axis_values:
            return None
        return float(self._axis_values[axis_key])

    def has_explicit_axis_binding(self, *, role: str) -> bool:
        if self._profiles is None:
            return False
        profile = self._profiles.active_profile()
        return self._profiles.get_axis_role_binding(profile_id=profile.profile_id, role=role) is not None

    def has_explicit_action_binding(self, *, action: str) -> bool:
        if self._profiles is None:
            return False
        profile = self._profiles.active_profile()
        slots = self._profiles.get_action_binding_slots(profile_id=profile.profile_id, action=action)
        return any(binding is not None for binding in slots)

    def consume_action(self, action: str) -> bool:
        pending = self._action_pending.get(str(action), 0)
        if pending <= 0:
            return False
        if pending <= 1:
            self._action_pending.pop(str(action), None)
        else:
            self._action_pending[str(action)] = pending - 1
        return True

    def action_active(self, *, action: str) -> bool:
        return bool(self._action_down.get(str(action), False))

    def clear_pending_actions(self, *actions: str) -> None:
        if actions:
            for action in actions:
                self._action_pending.pop(str(action), None)
            return
        self._action_pending.clear()


class AxisCalibrationScreen:
    def __init__(self, app: App, *, profiles: InputProfilesStore) -> None:
        self._app = app
        self._profiles = profiles
        self._title_font = pygame.font.Font(None, 40)
        self._small_font = pygame.font.Font(None, 25)
        self._tiny_font = pygame.font.Font(None, 20)
        self._device_index = 0
        self._axis_index = 0
        self._capturing = False
        self._message = ""

    def handle_event(self, event: pygame.event.Event) -> None:
        if event.type != pygame.KEYDOWN:
            return
        key = int(event.key)
        if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.pop()
            return

        joysticks = _iter_connected_joysticks()
        if not joysticks:
            self._message = "No joystick detected."
            return
        self._device_index %= len(joysticks)
        joystick = joysticks[self._device_index]
        axis_count = max(1, int(joystick.get_numaxes()))
        self._axis_index %= axis_count

        if key == pygame.K_LEFT:
            self._device_index = (self._device_index - 1) % len(joysticks)
            self._axis_index = 0
            self._capturing = False
            return
        if key == pygame.K_RIGHT:
            self._device_index = (self._device_index + 1) % len(joysticks)
            self._axis_index = 0
            self._capturing = False
            return
        if key == pygame.K_UP:
            self._axis_index = (self._axis_index - 1) % axis_count
            self._capturing = False
            return
        if key == pygame.K_DOWN:
            self._axis_index = (self._axis_index + 1) % axis_count
            self._capturing = False
            return

        axis_key = _axis_key(joystick, self._axis_index)
        profile = self._profiles.active_profile()
        settings = self._profiles.get_axis_calibration(
            profile_id=profile.profile_id, axis_key=axis_key
        )

        if key == pygame.K_SPACE:
            if not self._capturing:
                current = _axis_raw_value(joystick, self._axis_index)
                settings.min_raw = min(-0.001, current)
                settings.max_raw = max(0.001, current)
                self._capturing = True
                self._message = (
                    "Capture started. Move axis through full range, then press Space again."
                )
            else:
                self._capturing = False
                self._profiles.set_axis_calibration(
                    profile_id=profile.profile_id,
                    axis_key=axis_key,
                    settings=settings,
                )
                self._message = "Capture complete. Calibration saved."
            return

        if key == pygame.K_i:
            settings.invert = not settings.invert
            self._profiles.set_axis_calibration(
                profile_id=profile.profile_id,
                axis_key=axis_key,
                settings=settings,
            )
            self._message = "Invert toggled."
            return

        if key == pygame.K_r:
            self._capturing = False
            self._profiles.set_axis_calibration(
                profile_id=profile.profile_id,
                axis_key=axis_key,
                settings=AxisCalibrationSettings(),
            )
            self._message = "Axis calibration reset."
            return

        if key in (pygame.K_MINUS, pygame.K_KP_MINUS):
            settings.deadzone = _clamp(settings.deadzone - 0.01, 0.0, 0.45)
            self._profiles.set_axis_calibration(
                profile_id=profile.profile_id,
                axis_key=axis_key,
                settings=settings,
            )
            return
        if key in (pygame.K_EQUALS, pygame.K_PLUS, pygame.K_KP_PLUS):
            settings.deadzone = _clamp(settings.deadzone + 0.01, 0.0, 0.45)
            self._profiles.set_axis_calibration(
                profile_id=profile.profile_id,
                axis_key=axis_key,
                settings=settings,
            )
            return
        if key == pygame.K_LEFTBRACKET:
            settings.curve = _clamp(settings.curve - 0.05, 0.4, 2.6)
            self._profiles.set_axis_calibration(
                profile_id=profile.profile_id,
                axis_key=axis_key,
                settings=settings,
            )
            return
        if key == pygame.K_RIGHTBRACKET:
            settings.curve = _clamp(settings.curve + 0.05, 0.4, 2.6)
            self._profiles.set_axis_calibration(
                profile_id=profile.profile_id,
                axis_key=axis_key,
                settings=settings,
            )
            return

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        surface.fill((3, 9, 78))
        frame = pygame.Rect(12, 12, w - 24, h - 24)
        pygame.draw.rect(surface, (8, 18, 104), frame)
        pygame.draw.rect(surface, (226, 236, 255), frame, 2)

        profile = self._profiles.active_profile()
        title = self._title_font.render("Axis Calibration", True, (238, 245, 255))
        surface.blit(title, (30, 26))
        subtitle = self._small_font.render(f"Profile: {profile.name}", True, (188, 204, 228))
        surface.blit(subtitle, (32, 66))

        joysticks = _iter_connected_joysticks()
        if not joysticks:
            msg = self._small_font.render(
                "No joystick detected. Connect device and reopen this screen.",
                True,
                (238, 245, 255),
            )
            surface.blit(msg, (32, 120))
            footer = self._tiny_font.render("Esc/Backspace: Back", True, (188, 204, 228))
            surface.blit(footer, (32, frame.bottom - 30))
            return

        self._device_index %= len(joysticks)
        joystick = joysticks[self._device_index]
        axis_count = max(1, int(joystick.get_numaxes()))
        self._axis_index %= axis_count
        axis_key = _axis_key(joystick, self._axis_index)
        settings = self._profiles.get_axis_calibration(
            profile_id=profile.profile_id, axis_key=axis_key
        )
        raw = _axis_raw_value(joystick, self._axis_index)
        calibrated = _apply_axis_calibration(raw, settings)

        if self._capturing:
            settings.min_raw = min(settings.min_raw, raw)
            settings.max_raw = max(settings.max_raw, raw)

        device_text = self._small_font.render(
            f"Device {self._device_index + 1}/{len(joysticks)}: {joystick.get_name()}",
            True,
            (238, 245, 255),
        )
        surface.blit(device_text, (32, 112))

        axis_text = self._small_font.render(
            f"Axis {self._axis_index + 1}/{axis_count}",
            True,
            (238, 245, 255),
        )
        surface.blit(axis_text, (32, 145))

        raw_rect = pygame.Rect(32, 178, frame.w - 64, 24)
        cal_rect = pygame.Rect(32, 214, frame.w - 64, 24)
        _draw_axis_bar(
            surface,
            raw_rect,
            raw,
            fill_color=(116, 208, 255),
            line_color=(98, 130, 190),
        )
        _draw_axis_bar(
            surface,
            cal_rect,
            calibrated,
            fill_color=(145, 232, 178),
            line_color=(98, 130, 190),
        )
        raw_label = self._tiny_font.render(f"Raw: {raw:+.3f}", True, (188, 204, 228))
        cal_label = self._tiny_font.render(f"Calibrated: {calibrated:+.3f}", True, (188, 204, 228))
        surface.blit(raw_label, (raw_rect.right - raw_label.get_width(), raw_rect.y - 18))
        surface.blit(cal_label, (cal_rect.right - cal_label.get_width(), cal_rect.y - 18))

        rows = [
            f"min_raw: {settings.min_raw:+.3f}",
            f"max_raw: {settings.max_raw:+.3f}",
            f"deadzone: {settings.deadzone:.2f}",
            f"invert: {'ON' if settings.invert else 'OFF'}",
            f"curve: {settings.curve:.2f}",
            f"capture: {'ACTIVE' if self._capturing else 'idle'}",
        ]
        y = cal_rect.bottom + 20
        for row in rows:
            text = self._small_font.render(row, True, (238, 245, 255))
            surface.blit(text, (32, y))
            y += 28

        if self._message != "":
            note = self._tiny_font.render(self._message, True, (188, 204, 228))
            surface.blit(note, (32, min(frame.bottom - 54, y + 8)))

        footer = self._tiny_font.render(
            "Left/Right: Device  Up/Down: Axis  Space: Capture  I: Invert  "
            "+/-: Deadzone  [/]: Curve  R: Reset  Esc: Back",
            True,
            (188, 204, 228),
        )
        surface.blit(footer, (32, frame.bottom - 28))

    def poll_bound_input(self) -> None:
        while self._app.consume_bound_action("menu_up"):
            self.handle_event(pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_UP, "unicode": ""}))
        while self._app.consume_bound_action("menu_down"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_DOWN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_left"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_LEFT, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_right"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RIGHT, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_select"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_SPACE, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )


class AxisVisualizerScreen:
    def __init__(self, app: App, *, profiles: InputProfilesStore) -> None:
        self._app = app
        self._profiles = profiles
        self._title_font = pygame.font.Font(None, 40)
        self._small_font = pygame.font.Font(None, 24)
        self._tiny_font = pygame.font.Font(None, 19)

    def handle_event(self, event: pygame.event.Event) -> None:
        if event.type != pygame.KEYDOWN:
            return
        if event.key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.pop()

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        surface.fill((3, 9, 78))
        frame = pygame.Rect(12, 12, w - 24, h - 24)
        pygame.draw.rect(surface, (8, 18, 104), frame)
        pygame.draw.rect(surface, (226, 236, 255), frame, 2)

        profile = self._profiles.active_profile()
        title = self._title_font.render("Axis Visualizer", True, (238, 245, 255))
        surface.blit(title, (30, 26))
        subtitle = self._small_font.render(f"Profile: {profile.name}", True, (188, 204, 228))
        surface.blit(subtitle, (32, 66))

        joysticks = _iter_connected_joysticks()
        if not joysticks:
            msg = self._small_font.render("No joystick detected.", True, (238, 245, 255))
            surface.blit(msg, (32, 120))
            footer = self._tiny_font.render("Esc/Backspace: Back", True, (188, 204, 228))
            surface.blit(footer, (32, frame.bottom - 30))
            return

        max_visible_rows = max(1, (frame.h - 170) // 28)
        y = 108
        drawn_rows = 0
        for joystick_index, joystick in enumerate(joysticks, start=1):
            if drawn_rows >= max_visible_rows:
                break
            axis_count = max(0, int(joystick.get_numaxes()))
            button_count = max(0, int(joystick.get_numbuttons()))
            pressed_buttons = sum(1 for i in range(button_count) if bool(joystick.get_button(i)))
            header = self._small_font.render(
                f"[{joystick_index}] {joystick.get_name()}  axes:{axis_count}  "
                f"buttons:{pressed_buttons}/{button_count}",
                True,
                (238, 245, 255),
            )
            surface.blit(header, (32, y))
            y += 26
            drawn_rows += 1

            for axis_idx in range(axis_count):
                if drawn_rows >= max_visible_rows:
                    break
                raw = _axis_raw_value(joystick, axis_idx)
                axis_key = _axis_key(joystick, axis_idx)
                settings = self._profiles.get_axis_calibration(
                    profile_id=profile.profile_id,
                    axis_key=axis_key,
                )
                calibrated = _apply_axis_calibration(raw, settings)

                label = self._tiny_font.render(f"A{axis_idx:02d}", True, (188, 204, 228))
                surface.blit(label, (36, y + 6))

                raw_rect = pygame.Rect(76, y + 2, (frame.w - 130) // 2, 16)
                cal_rect = pygame.Rect(raw_rect.right + 10, y + 2, (frame.w - 130) // 2, 16)
                _draw_axis_bar(
                    surface,
                    raw_rect,
                    raw,
                    fill_color=(116, 208, 255),
                    line_color=(98, 130, 190),
                )
                _draw_axis_bar(
                    surface,
                    cal_rect,
                    calibrated,
                    fill_color=(145, 232, 178),
                    line_color=(98, 130, 190),
                )
                raw_text = self._tiny_font.render(f"{raw:+.2f}", True, (188, 204, 228))
                cal_text = self._tiny_font.render(f"{calibrated:+.2f}", True, (188, 204, 228))
                surface.blit(
                    raw_text, raw_text.get_rect(midtop=(raw_rect.centerx, raw_rect.bottom + 2))
                )
                surface.blit(
                    cal_text, cal_text.get_rect(midtop=(cal_rect.centerx, cal_rect.bottom + 2))
                )

                y += 28
                drawn_rows += 1

        footer = self._tiny_font.render(
            "Live raw + calibrated axis values. Esc/Backspace: Back", True, (188, 204, 228)
        )
        surface.blit(footer, (32, frame.bottom - 28))

    def poll_bound_input(self) -> None:
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )


class InputProfilesScreen:
    def __init__(self, app: App, *, profiles: InputProfilesStore) -> None:
        self._app = app
        self._profiles = profiles
        self._title_font = pygame.font.Font(None, 40)
        self._small_font = pygame.font.Font(None, 28)
        self._tiny_font = pygame.font.Font(None, 21)
        self._selected_index = 0
        self._renaming = False
        self._rename_buffer = ""
        self._message = ""
        self._row_hitboxes: dict[int, pygame.Rect] = {}

    def handle_event(self, event: pygame.event.Event) -> None:
        profiles = self._profiles.profiles()
        if not profiles:
            return
        self._selected_index %= len(profiles)
        selected = profiles[self._selected_index]

        if not self._renaming and event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._row_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected_index = idx
                        break
            return

        if not self._renaming and event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for idx, rect in self._row_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected_index = idx
                    profile = profiles[idx]
                    self._profiles.set_active_profile(profile.profile_id)
                    self._message = f"Active profile set: {profile.name}"
                    return
            return

        if event.type != pygame.KEYDOWN:
            return
        key = int(event.key)
        selected = profiles[self._selected_index]

        if self._renaming:
            if key == pygame.K_ESCAPE:
                self._renaming = False
                self._rename_buffer = ""
                return
            if key == pygame.K_BACKSPACE:
                self._rename_buffer = self._rename_buffer[:-1]
                return
            if key in (pygame.K_RETURN, pygame.K_KP_ENTER):
                if self._profiles.rename_profile(selected.profile_id, self._rename_buffer):
                    self._message = "Profile renamed."
                self._renaming = False
                self._rename_buffer = ""
                return
            ch = event.unicode
            if ch and ch.isprintable() and len(self._rename_buffer) < 24:
                self._rename_buffer += ch
            return

        if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.pop()
            return
        if key == pygame.K_UP:
            self._selected_index = (self._selected_index - 1) % len(profiles)
            return
        if key == pygame.K_DOWN:
            self._selected_index = (self._selected_index + 1) % len(profiles)
            return
        if key in (pygame.K_RETURN, pygame.K_KP_ENTER):
            self._profiles.set_active_profile(selected.profile_id)
            self._message = f"Active profile set: {selected.name}"
            return
        if key == pygame.K_n:
            name = f"Profile {len(profiles) + 1}"
            created = self._profiles.create_profile(
                name=name, copy_from=self._profiles.active_profile()
            )
            new_profiles = self._profiles.profiles()
            self._selected_index = next(
                i
                for i, profile in enumerate(new_profiles)
                if profile.profile_id == created.profile_id
            )
            self._message = f"Created {created.name}."
            return
        if key == pygame.K_c:
            created = self._profiles.create_profile(
                name=f"{selected.name} Copy",
                copy_from=selected,
            )
            new_profiles = self._profiles.profiles()
            self._selected_index = next(
                i
                for i, profile in enumerate(new_profiles)
                if profile.profile_id == created.profile_id
            )
            self._message = f"Copied {selected.name}."
            return
        if key == pygame.K_d:
            deleted = self._profiles.delete_profile(selected.profile_id)
            profiles = self._profiles.profiles()
            if deleted:
                self._selected_index = min(self._selected_index, len(profiles) - 1)
                self._message = "Profile deleted."
            else:
                self._message = "Cannot delete the last profile."
            return
        if key == pygame.K_r:
            self._renaming = True
            self._rename_buffer = selected.name

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        surface.fill((3, 9, 78))
        frame = pygame.Rect(12, 12, w - 24, h - 24)
        pygame.draw.rect(surface, (8, 18, 104), frame)
        pygame.draw.rect(surface, (226, 236, 255), frame, 2)

        title = self._title_font.render("Input Profiles", True, (238, 245, 255))
        surface.blit(title, (30, 26))

        profiles = self._profiles.profiles()
        if not profiles:
            note = self._small_font.render("No profiles available.", True, (238, 245, 255))
            surface.blit(note, (32, 120))
            return

        self._selected_index %= len(profiles)
        active_id = self._profiles.active_profile().profile_id

        list_rect = pygame.Rect(32, 100, frame.w - 64, frame.h - 170)
        pygame.draw.rect(surface, (6, 13, 92), list_rect)
        pygame.draw.rect(surface, (78, 102, 170), list_rect, 1)

        self._row_hitboxes = {}
        y = list_rect.y + 10
        row_h = 34
        for idx, profile in enumerate(profiles):
            row = pygame.Rect(list_rect.x + 10, y, list_rect.w - 20, row_h)
            self._row_hitboxes[idx] = row.copy()
            selected = idx == self._selected_index
            is_active = profile.profile_id == active_id
            if selected:
                pygame.draw.rect(surface, (244, 248, 255), row)
                text_color = (16, 32, 88)
            else:
                pygame.draw.rect(surface, (9, 20, 106), row)
                text_color = (238, 245, 255)
            pygame.draw.rect(surface, (62, 84, 152), row, 1)
            marker = "*" if is_active else " "
            label = f"{marker} {profile.name}"
            text = self._small_font.render(label, True, text_color)
            surface.blit(text, (row.x + 10, row.y + (row.h - text.get_height()) // 2))
            y += row_h + 6
            if y + row_h > list_rect.bottom:
                break

        if self._renaming:
            editor = pygame.Rect(32, frame.bottom - 98, frame.w - 64, 34)
            pygame.draw.rect(surface, (9, 20, 106), editor)
            pygame.draw.rect(surface, (120, 144, 198), editor, 2)
            caret = "|" if (pygame.time.get_ticks() // 500) % 2 == 0 else ""
            entry = self._small_font.render(self._rename_buffer + caret, True, (238, 245, 255))
            surface.blit(entry, (editor.x + 10, editor.y + 6))
            help_text = "Renaming: type name, Enter to save, Esc to cancel"
        else:
            help_text = (
                "Enter: Set Active  N: New  C: Copy  R: Rename  "
                "D: Delete  Up/Down: Select  Esc: Back"
            )

        hint = self._tiny_font.render(help_text, True, (188, 204, 228))
        surface.blit(hint, (32, frame.bottom - 52))
        if self._message != "":
            msg = self._tiny_font.render(self._message, True, (188, 204, 228))
            surface.blit(msg, (32, frame.bottom - 30))

    def poll_bound_input(self) -> None:
        if self._renaming:
            while self._app.consume_bound_action("menu_back"):
                self.handle_event(
                    pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
                )
            return
        while self._app.consume_bound_action("menu_up"):
            self.handle_event(pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_UP, "unicode": ""}))
        while self._app.consume_bound_action("menu_down"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_DOWN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_select"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RETURN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )


@dataclass(slots=True)
class _JoystickBindingRow:
    row_type: str
    key: str
    label: str
    slot_index: int = 0


class JoystickBindingsScreen:
    def __init__(self, app: App, *, profiles: InputProfilesStore) -> None:
        self._app = app
        self._profiles = profiles
        self._selected = 0
        self._scroll_top = 0
        self._title_font = pygame.font.Font(None, 42)
        self._item_font = pygame.font.Font(None, 28)
        self._hint_font = pygame.font.Font(None, 22)
        self._tiny_font = pygame.font.Font(None, 19)
        self._row_hitboxes: dict[int, pygame.Rect] = {}
        self._capturing_row: _JoystickBindingRow | None = None
        self._capture_seen_buttons: set[tuple[str, int]] = set()
        self._capture_seen_hats: set[tuple[str, int, str]] = set()
        self._capture_seen_axes: set[tuple[str, int, str]] = set()
        self._message = ""

    def _rows(self) -> list[_JoystickBindingRow]:
        rows = [
            _JoystickBindingRow("analog", role, label)
            for role, label in ANALOG_BINDING_ROLE_OPTIONS
        ]
        for action, label in DIGITAL_BINDING_ACTION_OPTIONS:
            for slot_index in range(ACTION_BINDING_SLOT_COUNT):
                rows.append(
                    _JoystickBindingRow(
                        "digital",
                        action,
                        f"{label} [{slot_index + 1}]",
                        slot_index=slot_index,
                    )
                )
        rows.append(_JoystickBindingRow("back", "back", "Back"))
        return rows

    def _current_profile(self) -> InputProfile:
        return self._profiles.active_profile()

    def _row_value(self, row: _JoystickBindingRow) -> str:
        profile = self._current_profile()
        if row.row_type == "analog":
            return _describe_analog_binding(
                self._profiles.get_axis_role_binding(profile_id=profile.profile_id, role=row.key)
            )
        if row.row_type == "digital":
            bindings = self._profiles.get_action_binding_slots(
                profile_id=profile.profile_id,
                action=row.key,
            )
            binding = bindings[row.slot_index] if row.slot_index < len(bindings) else None
            return _describe_digital_binding(binding)
        return "Return to previous screen"

    def _poll_calibrated_axis_value(
        self,
        *,
        profile: InputProfile,
        joystick: pygame.joystick.Joystick,
        axis_index: int,
    ) -> float:
        raw = _axis_raw_value(joystick, axis_index)
        settings = self._profiles.get_axis_calibration(
            profile_id=profile.profile_id,
            axis_key=_axis_key(joystick, axis_index),
        )
        return _apply_axis_calibration(raw, settings)

    def _begin_capture(self, row: _JoystickBindingRow) -> None:
        if row.row_type == "back":
            self._app.pop()
            return

        profile = self._current_profile()
        self._capturing_row = row
        self._capture_seen_buttons = set()
        self._capture_seen_hats = set()
        self._capture_seen_axes = set()
        for joystick in _iter_connected_joysticks():
            device_key = _joystick_key(joystick)
            button_count = max(0, int(getattr(joystick, "get_numbuttons", lambda: 0)()))
            for button_index in range(button_count):
                try:
                    if bool(joystick.get_button(button_index)):
                        self._capture_seen_buttons.add((device_key, button_index))
                except Exception:
                    continue
            hat_count = max(0, int(getattr(joystick, "get_numhats", lambda: 0)()))
            for hat_index in range(hat_count):
                try:
                    value = joystick.get_hat(hat_index)
                except Exception:
                    continue
                if not isinstance(value, tuple) or len(value) != 2:
                    continue
                for direction in ("up", "down", "left", "right"):
                    if _hat_matches_direction((int(value[0]), int(value[1])), direction):
                        self._capture_seen_hats.add((device_key, hat_index, direction))
            axis_count = max(0, int(getattr(joystick, "get_numaxes", lambda: 0)()))
            for axis_index in range(axis_count):
                value = self._poll_calibrated_axis_value(
                    profile=profile,
                    joystick=joystick,
                    axis_index=axis_index,
                )
                if abs(value) >= 0.35:
                    self._capture_seen_axes.add((device_key, axis_index, "+" if value >= 0.0 else "-"))

        self._app.clear_pending_bound_actions()
        if row.row_type == "analog":
            self._message = "Capture active. Move the axis you want to bind."
        else:
            self._message = (
                "Capture active. Press a button, move a hat, or push an axis past the trigger threshold."
            )

    def _clear_selected_binding(self) -> None:
        rows = self._rows()
        if not rows:
            return
        row = rows[self._selected % len(rows)]
        profile = self._current_profile()
        if row.row_type == "analog":
            self._profiles.set_axis_role_binding(profile_id=profile.profile_id, role=row.key, binding=None)
            self._message = f"{row.label} reset to AUTO."
            return
        if row.row_type == "digital":
            self._profiles.set_action_binding(
                profile_id=profile.profile_id,
                action=row.key,
                slot_index=row.slot_index,
                binding=None,
            )
            self._message = f"{row.label} reset to AUTO."

    def _poll_capture(self) -> None:
        row = self._capturing_row
        if row is None:
            return
        profile = self._current_profile()
        self._app.clear_pending_bound_actions()
        for joystick in _iter_connected_joysticks():
            device_key = _joystick_key(joystick)
            axis_count = max(0, int(getattr(joystick, "get_numaxes", lambda: 0)()))
            button_count = max(0, int(getattr(joystick, "get_numbuttons", lambda: 0)()))
            hat_count = max(0, int(getattr(joystick, "get_numhats", lambda: 0)()))

            if row.row_type == "digital":
                for button_index in range(button_count):
                    signature = (device_key, button_index)
                    try:
                        pressed = bool(joystick.get_button(button_index))
                    except Exception:
                        pressed = False
                    if pressed and signature not in self._capture_seen_buttons:
                        binding = DigitalBinding(
                            kind="button",
                            device_key=device_key,
                            control_index=button_index,
                        )
                        self._profiles.set_action_binding(
                            profile_id=profile.profile_id,
                            action=row.key,
                            slot_index=row.slot_index,
                            binding=binding,
                        )
                        self._capturing_row = None
                        self._message = f"{row.label} bound to {_describe_digital_binding(binding)}."
                        self._app.clear_pending_bound_actions()
                        return
                for hat_index in range(hat_count):
                    try:
                        value = joystick.get_hat(hat_index)
                    except Exception:
                        continue
                    if not isinstance(value, tuple) or len(value) != 2:
                        continue
                    hat_value = (int(value[0]), int(value[1]))
                    for direction in ("up", "down", "left", "right"):
                        signature = (device_key, hat_index, direction)
                        if (
                            _hat_matches_direction(hat_value, direction)
                            and signature not in self._capture_seen_hats
                        ):
                            binding = DigitalBinding(
                                kind="hat",
                                device_key=device_key,
                                control_index=hat_index,
                                direction=direction,
                            )
                            self._profiles.set_action_binding(
                                profile_id=profile.profile_id,
                                action=row.key,
                                slot_index=row.slot_index,
                                binding=binding,
                            )
                            self._capturing_row = None
                            self._message = f"{row.label} bound to {_describe_digital_binding(binding)}."
                            self._app.clear_pending_bound_actions()
                            return

            for axis_index in range(axis_count):
                value = self._poll_calibrated_axis_value(
                    profile=profile,
                    joystick=joystick,
                    axis_index=axis_index,
                )
                direction = "+" if value >= 0.0 else "-"
                signature = (device_key, axis_index, direction)
                if row.row_type == "analog":
                    if abs(value) >= 0.35 and signature not in self._capture_seen_axes:
                        binding = AnalogBinding(device_key=device_key, axis_index=axis_index)
                        self._profiles.set_axis_role_binding(
                            profile_id=profile.profile_id,
                            role=row.key,
                            binding=binding,
                        )
                        self._capturing_row = None
                        self._message = f"{row.label} bound to {_describe_analog_binding(binding)}."
                        self._app.clear_pending_bound_actions()
                        return
                    continue

                if abs(value) >= _DIGITAL_AXIS_PRESS_THRESHOLD and signature not in self._capture_seen_axes:
                    binding = DigitalBinding(
                        kind="axis",
                        device_key=device_key,
                        control_index=axis_index,
                        direction=direction,
                    )
                    self._profiles.set_action_binding(
                        profile_id=profile.profile_id,
                        action=row.key,
                        slot_index=row.slot_index,
                        binding=binding,
                    )
                    self._capturing_row = None
                    self._message = f"{row.label} bound to {_describe_digital_binding(binding)}."
                    self._app.clear_pending_bound_actions()
                    return

    def poll_bound_input(self) -> None:
        if self._capturing_row is not None:
            self._poll_capture()
            return
        while self._app.consume_bound_action("menu_up"):
            self.handle_event(pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_UP, "unicode": ""}))
        while self._app.consume_bound_action("menu_down"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_DOWN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_select"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RETURN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )

    def handle_event(self, event: pygame.event.Event) -> None:
        rows = self._rows()
        if self._capturing_row is not None:
            if event.type == pygame.KEYDOWN and event.key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
                self._capturing_row = None
                self._message = "Capture cancelled."
                self._app.clear_pending_bound_actions()
            return

        if event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._row_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected = idx
                        break
            return
        if event.type == pygame.MOUSEBUTTONDOWN and getattr(event, "button", 0) == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for idx, rect in self._row_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    row = rows[idx]
                    if row.row_type == "back":
                        self._app.pop()
                    else:
                        self._begin_capture(row)
                    return
            return
        if event.type == pygame.MOUSEWHEEL:
            if event.y > 0:
                self._selected = max(0, self._selected - 1)
            elif event.y < 0:
                self._selected = min(max(0, len(rows) - 1), self._selected + 1)
            return
        if event.type != pygame.KEYDOWN:
            return

        key = int(event.key)
        if key == pygame.K_ESCAPE:
            self._app.pop()
            return
        if key in (pygame.K_UP, pygame.K_w):
            self._selected = (self._selected - 1) % max(1, len(rows))
            return
        if key in (pygame.K_DOWN, pygame.K_s):
            self._selected = (self._selected + 1) % max(1, len(rows))
            return
        if key in (pygame.K_BACKSPACE, pygame.K_DELETE):
            self._clear_selected_binding()
            return
        if key == pygame.K_r:
            self._clear_selected_binding()
            return
        if key in (pygame.K_RETURN, pygame.K_KP_ENTER, pygame.K_SPACE):
            row = rows[self._selected % len(rows)]
            if row.row_type == "back":
                self._app.pop()
            else:
                self._begin_capture(row)

    def render(self, surface: pygame.Surface) -> None:
        if self._capturing_row is not None:
            self._poll_capture()
        w, h = surface.get_size()
        bg = (4, 10, 72)
        panel_bg = (8, 18, 104)
        border = (226, 236, 255)
        text_main = (238, 245, 255)
        text_muted = (186, 200, 224)
        active_bg = (244, 248, 255)
        active_text = (14, 26, 74)

        surface.fill(bg)
        panel = pygame.Rect(max(12, w // 28), max(12, h // 24), w - max(24, w // 14), h - max(24, h // 12))
        pygame.draw.rect(surface, panel_bg, panel)
        pygame.draw.rect(surface, border, panel, 2)

        title = self._title_font.render("Joystick Bindings", True, text_main)
        surface.blit(title, title.get_rect(midtop=(panel.centerx, panel.y + 14)))
        subtitle = self._hint_font.render(
            f"Active profile: {self._current_profile().name}",
            True,
            text_muted,
        )
        surface.blit(subtitle, subtitle.get_rect(midtop=(panel.centerx, panel.y + 54)))

        rows = self._rows()
        self._selected %= max(1, len(rows))
        list_rect = pygame.Rect(panel.x + 18, panel.y + 86, panel.w - 36, panel.h - 136)
        pygame.draw.rect(surface, (6, 13, 92), list_rect)
        pygame.draw.rect(surface, (78, 102, 170), list_rect, 1)

        gap = 8
        row_h = 40
        visible_count = max(1, (list_rect.h - gap) // (row_h + gap))
        max_scroll_top = max(0, len(rows) - visible_count)
        if self._scroll_top > max_scroll_top:
            self._scroll_top = max_scroll_top
        if self._selected < self._scroll_top:
            self._scroll_top = self._selected
        elif self._selected >= self._scroll_top + visible_count:
            self._scroll_top = self._selected - visible_count + 1

        self._row_hitboxes = {}
        y = list_rect.y + gap
        start = self._scroll_top
        end = min(len(rows), start + visible_count)
        for idx in range(start, end):
            row_meta = rows[idx]
            row = pygame.Rect(list_rect.x + 10, y, list_rect.w - 20, row_h)
            self._row_hitboxes[idx] = row.copy()
            selected = idx == self._selected
            fill = active_bg if selected else (9, 20, 106)
            edge = (120, 142, 196) if selected else (62, 84, 152)
            pygame.draw.rect(surface, fill, row, border_radius=6)
            pygame.draw.rect(surface, edge, row, 2 if selected else 1, border_radius=6)
            label_color = active_text if selected else text_main
            value_color = (46, 62, 112) if selected else text_muted

            label_surf = self._item_font.render(row_meta.label, True, label_color)
            surface.blit(label_surf, (row.x + 12, row.y + (row.h - label_surf.get_height()) // 2))

            value_surf = self._hint_font.render(self._row_value(row_meta), True, value_color)
            surface.blit(value_surf, value_surf.get_rect(midright=(row.right - 14, row.centery)))
            y += row_h + gap

        footer_text = (
            "Capture active: move/press the desired control. Esc cancels."
            if self._capturing_row is not None
            else "Up/Down: Select  Enter: Capture  Backspace/Delete: Clear  R: Reset to AUTO  Esc: Back"
        )
        footer = self._hint_font.render(footer_text, True, text_muted)
        surface.blit(footer, footer.get_rect(midbottom=(panel.centerx, panel.bottom - 12)))

        if self._message != "":
            note = self._tiny_font.render(self._message, True, text_muted)
            surface.blit(note, (panel.x + 22, panel.bottom - 38))


class MenuScreen:
    def __init__(
        self, app: App, title: str, items: list[MenuItem], *, is_root: bool = False
    ) -> None:
        self._app = app
        self._title = title
        self._items = items
        self._selected = 0
        self._is_root = is_root
        # HOTAS devices can emit stale startup button events; debounce briefly.
        self._joy_input_unlock_ms = pygame.time.get_ticks() + 900
        self._title_font = pygame.font.Font(None, 42)
        self._item_font = pygame.font.Font(None, 32)
        self._hint_font = pygame.font.Font(None, 22)
        self._item_hitboxes: dict[int, pygame.Rect] = {}
        self._scroll_top = 0

    def _prime_item_hitboxes(self) -> None:
        if self._item_hitboxes:
            return
        scratch = pygame.Surface(self._app.surface.get_size(), pygame.SRCALPHA)
        self.render(scratch)

    def handle_event(self, event: pygame.event.Event) -> None:
        if event.type == pygame.KEYDOWN:
            self._handle_key(event.key)
            return

        if event.type == pygame.MOUSEMOTION:
            self._prime_item_hitboxes()
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._item_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected = idx
                        break
            return

        if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
            self._prime_item_hitboxes()
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for idx, rect in self._item_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    self._activate()
                    return
            return

        if event.type == pygame.MOUSEWHEEL:
            if event.y > 0:
                self._move(-1)
            elif event.y < 0:
                self._move(1)
            return

        if event.type == pygame.JOYHATMOTION:
            if pygame.time.get_ticks() < self._joy_input_unlock_ms:
                return
            # D-pad / hat navigation (works on many sticks).
            _, y = event.value
            if y == 1 and not self._app.has_explicit_action_binding("menu_up"):
                self._move(-1)
            elif y == -1 and not self._app.has_explicit_action_binding("menu_down"):
                self._move(1)
            return

        if event.type == pygame.JOYBUTTONDOWN:
            if pygame.time.get_ticks() < self._joy_input_unlock_ms:
                return
            # Common mapping: 0 = select, 1 = back/cancel.
            if event.button == 0 and not self._app.has_explicit_action_binding("menu_select"):
                self._activate()
            elif event.button == 1 and not self._app.has_explicit_action_binding("menu_back"):
                self._back()

    def _handle_key(self, key: int) -> None:
        if key in (pygame.K_UP, pygame.K_w):
            self._move(-1)
        elif key in (pygame.K_DOWN, pygame.K_s):
            self._move(1)
        elif key in (pygame.K_RETURN, pygame.K_KP_ENTER, pygame.K_SPACE):
            self._activate()
        elif key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._back()

    def _move(self, delta: int) -> None:
        if not self._items:
            return
        self._selected = (self._selected + delta) % len(self._items)

    def _activate(self) -> None:
        if not self._items:
            return
        self._items[self._selected].action()

    def _back(self) -> None:
        if self._is_root:
            self._app.quit()
        else:
            self._app.pop()

    def _fit_label(self, font: pygame.font.Font, label: str, max_width: int) -> str:
        if max_width <= 0:
            return ""
        if font.size(label)[0] <= max_width:
            return label
        clipped = label
        while clipped and font.size(f"{clipped}...")[0] > max_width:
            clipped = clipped[:-1]
        return f"{clipped}..." if clipped else "..."

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        bg = (3, 9, 78)
        panel_bg = (8, 18, 104)
        header_bg = (18, 30, 118)
        border = (226, 236, 255)
        text_main = (238, 245, 255)
        text_muted = (186, 200, 224)
        active_bg = (244, 248, 255)
        active_text = (14, 26, 74)

        surface.fill(bg)

        frame_margin = max(10, min(26, w // 34))
        frame = pygame.Rect(
            frame_margin,
            frame_margin,
            max(260, w - frame_margin * 2),
            max(220, h - frame_margin * 2),
        )
        pygame.draw.rect(surface, panel_bg, frame)
        pygame.draw.rect(surface, border, frame, 2)

        header_h = max(34, min(52, h // 8))
        header = pygame.Rect(frame.x + 2, frame.y + 2, frame.w - 4, header_h)
        pygame.draw.rect(surface, header_bg, header)
        pygame.draw.line(
            surface,
            border,
            (header.x, header.bottom),
            (header.right, header.bottom),
            1,
        )

        tag = self._hint_font.render("MENU", True, text_muted)
        surface.blit(tag, (header.x + 12, header.y + (header.h - tag.get_height()) // 2))

        title = self._title_font.render(self._title, True, text_main)
        surface.blit(title, title.get_rect(center=(frame.centerx, header.centery)))

        content_top = header.bottom + max(16, h // 30)
        content_bottom = frame.bottom - max(44, h // 12)
        list_rect = pygame.Rect(
            frame.x + max(14, w // 44),
            content_top,
            frame.w - max(28, w // 22),
            max(120, content_bottom - content_top),
        )
        pygame.draw.rect(surface, (6, 13, 92), list_rect)
        pygame.draw.rect(surface, (78, 102, 170), list_rect, 1)

        item_count = len(self._items)
        if item_count <= 0:
            self._item_hitboxes = {}
            footer = "Enter/Space: Select  |  Esc/Backspace: Back  |  D-pad + Button0/1"
            foot = self._hint_font.render(footer, True, text_muted)
            surface.blit(foot, foot.get_rect(midbottom=(frame.centerx, frame.bottom - 10)))
            return

        self._selected %= item_count

        gap = max(3, min(8, list_rect.h // 40))
        min_row_h = max(18, self._item_font.get_height() + 4)
        fit_row_h = (list_rect.h - gap * (item_count + 1)) // item_count

        if fit_row_h >= min_row_h:
            # Everything fits: no scrolling required.
            row_h = min(44, fit_row_h)
            visible_count = item_count
            self._scroll_top = 0
            total_h = row_h * visible_count + gap * (visible_count - 1)
            y = list_rect.y + max(gap, (list_rect.h - total_h) // 2)
        else:
            # Long menu: keep rows readable and scroll the visible window.
            row_h = max(min_row_h, min(40, list_rect.h // 8))
            visible_count = max(1, (list_rect.h - gap) // (row_h + gap))
            max_scroll_top = max(0, item_count - visible_count)
            if self._scroll_top > max_scroll_top:
                self._scroll_top = max_scroll_top
            if self._selected < self._scroll_top:
                self._scroll_top = self._selected
            elif self._selected >= self._scroll_top + visible_count:
                self._scroll_top = self._selected - visible_count + 1
            y = list_rect.y + gap

        self._item_hitboxes = {}
        start = int(self._scroll_top)
        end = min(item_count, start + visible_count)
        for idx in range(start, end):
            item = self._items[idx]
            row = pygame.Rect(list_rect.x + 12, y, list_rect.w - 24, row_h)
            self._item_hitboxes[idx] = row.copy()
            selected = idx == self._selected
            if selected:
                pygame.draw.rect(surface, active_bg, row)
                pygame.draw.rect(surface, (120, 142, 196), row, 2)
            else:
                pygame.draw.rect(surface, (9, 20, 106), row)
                pygame.draw.rect(surface, (62, 84, 152), row, 1)

            color = active_text if selected else text_main
            label = self._fit_label(self._item_font, item.label, row.w - 20)
            text = self._item_font.render(label, True, color)
            surface.blit(text, (row.x + 10, row.y + (row.h - text.get_height()) // 2))
            y += row_h + gap

        max_scroll_top = max(0, item_count - visible_count)
        if max_scroll_top > 0:
            up_color = text_main if self._scroll_top > 0 else (98, 118, 166)
            down_color = text_main if self._scroll_top < max_scroll_top else (98, 118, 166)
            up = self._hint_font.render("^", True, up_color)
            down = self._hint_font.render("v", True, down_color)
            surface.blit(up, up.get_rect(topright=(list_rect.right - 8, list_rect.y + 4)))
            surface.blit(down, down.get_rect(bottomright=(list_rect.right - 8, list_rect.bottom - 4)))

        footer = "Enter/Space: Select  |  Esc/Backspace: Back  |  D-pad + Button0/1"
        foot = self._hint_font.render(footer, True, text_muted)
        surface.blit(foot, foot.get_rect(midbottom=(frame.centerx, frame.bottom - 10)))

    def poll_bound_input(self) -> None:
        while self._app.consume_bound_action("menu_up"):
            self._move(-1)
        while self._app.consume_bound_action("menu_down"):
            self._move(1)
        while self._app.consume_bound_action("menu_select"):
            self._activate()
        while self._app.consume_bound_action("menu_back"):
            self._back()


class DifficultySettingsScreen:
    def __init__(self, app: App) -> None:
        self._app = app
        self._selected = 0
        self._scroll_top = 0
        self._title_font = pygame.font.Font(None, 42)
        self._item_font = pygame.font.Font(None, 30)
        self._hint_font = pygame.font.Font(None, 22)
        self._row_hitboxes: dict[int, pygame.Rect] = {}
        self._control_hitboxes: dict[tuple[int, str], pygame.Rect] = {}

    def _rows(self) -> list[tuple[str, str, str]]:
        rows = [
            (
                "override",
                "Global Difficulty Override",
                "ON" if self._app.difficulty_override_enabled() else "OFF",
            ),
            (
                "global_level",
                "Global Difficulty",
                f"{self._app.stored_global_difficulty_level()} / 10",
            ),
            (
                "review_mode",
                "Dev Answer Review",
                "ON" if self._app.review_mode_enabled() else "OFF",
            ),
        ]
        for test_code, label in TEST_DIFFICULTY_OPTIONS:
            rows.append(
                (
                    f"test:{test_code}",
                    label,
                    f"{self._app.stored_test_difficulty_level(test_code)} / 10",
                )
            )
        rows.append(("back", "Back", "Return to Main Menu"))
        return rows

    def handle_event(self, event: pygame.event.Event) -> None:
        rows = self._rows()
        if event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._row_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected = idx
                        break
            return
        if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for (idx, action), rect in self._control_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    self._adjust_row(rows[idx][0], -1 if action == "dec" else 1)
                    return
            for idx, rect in self._row_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    if rows[idx][0] == "back":
                        self._app.pop()
                    return
            return
        if event.type == pygame.MOUSEWHEEL:
            if event.y > 0:
                self._selected = max(0, self._selected - 1)
            elif event.y < 0:
                self._selected = min(max(0, len(rows) - 1), self._selected + 1)
            return
        if event.type != pygame.KEYDOWN:
            return

        key = event.key
        if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.pop()
            return
        if key in (pygame.K_UP, pygame.K_w):
            self._selected = (self._selected - 1) % max(1, len(rows))
            return
        if key in (pygame.K_DOWN, pygame.K_s):
            self._selected = (self._selected + 1) % max(1, len(rows))
            return
        if key in (pygame.K_LEFT, pygame.K_a):
            self._adjust_row(rows[self._selected][0], -1)
            return
        if key in (pygame.K_RIGHT, pygame.K_d):
            self._adjust_row(rows[self._selected][0], 1)
            return
        if key in (pygame.K_RETURN, pygame.K_KP_ENTER, pygame.K_SPACE):
            if rows[self._selected][0] == "back":
                self._app.pop()
            elif rows[self._selected][0] == "override":
                self._adjust_row("override", 1)
            elif rows[self._selected][0] == "review_mode":
                self._adjust_row("review_mode", 1)

    def _adjust_row(self, key: str, direction: int) -> None:
        if key == "override":
            self._app.set_global_difficulty_override_enabled(
                not self._app.difficulty_override_enabled()
            )
            return
        if key == "global_level":
            self._app.set_global_difficulty_level(
                self._app.stored_global_difficulty_level() + int(direction)
            )
            return
        if key == "review_mode":
            self._app.set_review_mode_enabled(not self._app.review_mode_enabled())
            return
        if key.startswith("test:"):
            test_code = key.split(":", 1)[1]
            self._app.set_test_difficulty_level(
                test_code=test_code,
                level=self._app.stored_test_difficulty_level(test_code) + int(direction),
            )

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        bg = (4, 10, 72)
        panel_bg = (8, 18, 104)
        border = (226, 236, 255)
        text_main = (238, 245, 255)
        text_muted = (186, 200, 224)
        active_bg = (244, 248, 255)
        active_text = (14, 26, 74)

        surface.fill(bg)
        panel = pygame.Rect(max(12, w // 28), max(12, h // 24), w - max(24, w // 14), h - max(24, h // 12))
        pygame.draw.rect(surface, panel_bg, panel)
        pygame.draw.rect(surface, border, panel, 2)

        title = self._title_font.render("Settings", True, text_main)
        surface.blit(title, title.get_rect(midtop=(panel.centerx, panel.y + 14)))
        subtitle = self._hint_font.render(
            "Global override applies everywhere. Per-test values are stored underneath.",
            True,
            text_muted,
        )
        surface.blit(subtitle, subtitle.get_rect(midtop=(panel.centerx, panel.y + 54)))

        rows = self._rows()
        self._selected %= max(1, len(rows))

        list_rect = pygame.Rect(panel.x + 18, panel.y + 86, panel.w - 36, panel.h - 128)
        pygame.draw.rect(surface, (6, 13, 92), list_rect)
        pygame.draw.rect(surface, (78, 102, 170), list_rect, 1)

        gap = 8
        row_h = 42
        visible_count = max(1, (list_rect.h - gap) // (row_h + gap))
        max_scroll_top = max(0, len(rows) - visible_count)
        if self._scroll_top > max_scroll_top:
            self._scroll_top = max_scroll_top
        if self._selected < self._scroll_top:
            self._scroll_top = self._selected
        elif self._selected >= self._scroll_top + visible_count:
            self._scroll_top = self._selected - visible_count + 1

        self._row_hitboxes = {}
        self._control_hitboxes = {}
        y = list_rect.y + gap
        start = self._scroll_top
        end = min(len(rows), start + visible_count)
        for idx in range(start, end):
            key, label, value = rows[idx]
            row = pygame.Rect(list_rect.x + 10, y, list_rect.w - 20, row_h)
            self._row_hitboxes[idx] = row.copy()
            selected = idx == self._selected
            fill = active_bg if selected else (9, 20, 106)
            edge = (120, 142, 196) if selected else (62, 84, 152)
            pygame.draw.rect(surface, fill, row, border_radius=6)
            pygame.draw.rect(surface, edge, row, 2 if selected else 1, border_radius=6)
            label_color = active_text if selected else text_main
            value_color = (46, 62, 112) if selected else text_muted

            label_text = MenuScreen._fit_label(self, self._item_font, label, row.w - 240)
            label_surf = self._item_font.render(label_text, True, label_color)
            surface.blit(label_surf, (row.x + 12, row.y + (row.h - label_surf.get_height()) // 2))

            if key == "back":
                value_surf = self._hint_font.render(value, True, value_color)
                surface.blit(value_surf, value_surf.get_rect(midright=(row.right - 14, row.centery)))
            else:
                value_box = pygame.Rect(row.right - 176, row.y + 6, 164, row.h - 12)
                dec_box = pygame.Rect(value_box.x, value_box.y, 32, value_box.h)
                inc_box = pygame.Rect(value_box.right - 32, value_box.y, 32, value_box.h)
                mid_box = pygame.Rect(dec_box.right + 6, value_box.y, value_box.w - 76, value_box.h)
                self._control_hitboxes[(idx, "dec")] = dec_box.copy()
                self._control_hitboxes[(idx, "inc")] = inc_box.copy()
                for box, glyph in ((dec_box, "<"), (inc_box, ">")):
                    pygame.draw.rect(surface, (20, 32, 92), box, border_radius=5)
                    pygame.draw.rect(surface, (110, 130, 184), box, 1, border_radius=5)
                    glyph_surf = self._item_font.render(glyph, True, text_main)
                    surface.blit(glyph_surf, glyph_surf.get_rect(center=box.center))
                pygame.draw.rect(surface, (14, 26, 78), mid_box, border_radius=5)
                pygame.draw.rect(surface, (92, 112, 168), mid_box, 1, border_radius=5)
                value_surf = self._hint_font.render(value, True, text_main)
                surface.blit(value_surf, value_surf.get_rect(center=mid_box.center))

            y += row_h + gap

        footer = self._hint_font.render(
            "Up/Down: Select  Left/Right: Adjust  Enter: Toggle/Back  Esc: Main Menu",
            True,
            text_muted,
        )
        surface.blit(footer, footer.get_rect(midbottom=(panel.centerx, panel.bottom - 12)))

    def poll_bound_input(self) -> None:
        while self._app.consume_bound_action("menu_up"):
            self.handle_event(pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_UP, "unicode": ""}))
        while self._app.consume_bound_action("menu_down"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_DOWN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_left"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_LEFT, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_right"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RIGHT, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_select"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RETURN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )


class StatsHistoryScreen:
    def __init__(self, app: App) -> None:
        self._app = app
        self._selected = 0
        self._scroll_top = 0
        self._title_font = pygame.font.Font(None, 42)
        self._item_font = pygame.font.Font(None, 28)
        self._small_font = pygame.font.Font(None, 22)
        self._hint_font = pygame.font.Font(None, 20)
        self._row_hitboxes: dict[int, pygame.Rect] = {}
        self._summaries: list[AttemptCodeSummary] = []
        self._history_cache: dict[str, list[AttemptHistoryEntry]] = {}
        self._reload()

    def _reload(self) -> None:
        self._summaries = self._app.attempt_code_summaries()
        if not self._summaries:
            self._selected = 0
            self._scroll_top = 0
            return
        self._selected = max(0, min(self._selected, len(self._summaries) - 1))
        self._scroll_top = max(0, min(self._scroll_top, len(self._summaries) - 1))

    @staticmethod
    def _fallback_label(test_code: str) -> str:
        words = [token for token in str(test_code).replace("-", "_").split("_") if token]
        if not words:
            return str(test_code)
        return " ".join(word.upper() if len(word) <= 3 else word.capitalize() for word in words)

    @classmethod
    def _label_for_code(cls, test_code: str) -> str:
        briefing = TEST_GUIDE_BRIEFS.get(str(test_code))
        if briefing is not None:
            return briefing.label
        guide = official_guide_test(test_code)
        if guide is not None:
            return guide.official_name
        return cls._fallback_label(str(test_code))

    @staticmethod
    def _fmt_ratio(value: float | None) -> str:
        if value is None:
            return "n/a"
        return f"{value * 100.0:.0f}%"

    @staticmethod
    def _fmt_range(low: float | None, high: float | None, *, scale: float = 100.0) -> str:
        if low is None and high is None:
            return "n/a"
        if low is None:
            return f"<= {high * scale:.0f}" if high is not None else "n/a"
        if high is None:
            return f">= {low * scale:.0f}"
        return f"{low * scale:.0f} to {high * scale:.0f}"

    @staticmethod
    def _fmt_total(value: float | None) -> str:
        if value is None:
            return "n/a"
        rounded = round(float(value), 1)
        if abs(rounded - round(rounded)) <= 1.0e-6:
            return str(int(round(rounded)))
        return f"{rounded:.1f}"

    @staticmethod
    def _metric_float(metrics: Mapping[str, str], key: str) -> float | None:
        raw = str(metrics.get(key, "")).strip()
        if raw == "":
            return None
        try:
            return float(raw)
        except Exception:
            return None

    @staticmethod
    def _wrap_text_lines(text: str, font: pygame.font.Font, max_width: int) -> list[str]:
        if max_width <= 0:
            return [""]
        words = str(text).split()
        if not words:
            return [""]
        lines: list[str] = []
        current = ""
        for word in words:
            trial = word if current == "" else f"{current} {word}"
            if font.size(trial)[0] <= max_width:
                current = trial
            else:
                if current:
                    lines.append(current)
                current = word
        if current:
            lines.append(current)
        return lines or [""]

    @staticmethod
    def _fmt_level_range(summary: AttemptCodeSummary) -> str:
        if summary.observed_level_min is None and summary.observed_level_max is None:
            return "n/a"
        if summary.observed_level_min == summary.observed_level_max:
            return f"L{summary.observed_level_min}"
        return f"L{summary.observed_level_min}-{summary.observed_level_max}"

    def _selected_summary(self) -> AttemptCodeSummary | None:
        if not self._summaries:
            return None
        return self._summaries[self._selected % len(self._summaries)]

    def _selected_history(self) -> list[AttemptHistoryEntry]:
        summary = self._selected_summary()
        if summary is None:
            return []
        test_code = str(summary.test_code)
        cached = self._history_cache.get(test_code)
        if cached is not None:
            return cached
        history = self._app.recent_attempt_history_for_code(test_code=test_code, limit=12)
        self._history_cache[test_code] = history
        return history

    def handle_event(self, event: pygame.event.Event) -> None:
        if event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._row_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected = idx
                        break
            return
        if event.type == pygame.MOUSEBUTTONDOWN and getattr(event, "button", 0) == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for idx, rect in self._row_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    return
            return
        if event.type == pygame.MOUSEWHEEL:
            if event.y > 0:
                self._selected = max(0, self._selected - 1)
            elif event.y < 0:
                self._selected = min(max(0, len(self._summaries) - 1), self._selected + 1)
            return
        if event.type != pygame.KEYDOWN:
            return

        key = event.key
        if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.pop()
            return
        if key in (pygame.K_UP, pygame.K_w):
            self._selected = (self._selected - 1) % max(1, len(self._summaries))
            return
        if key in (pygame.K_DOWN, pygame.K_s):
            self._selected = (self._selected + 1) % max(1, len(self._summaries))
            return
        if key == pygame.K_r:
            self._history_cache.clear()
            self._reload()

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        bg = (4, 10, 72)
        panel_bg = (8, 18, 104)
        border = (226, 236, 255)
        text_main = (238, 245, 255)
        text_muted = (186, 200, 224)
        active_bg = (244, 248, 255)
        active_text = (14, 26, 74)

        surface.fill(bg)
        panel = pygame.Rect(
            max(12, w // 28),
            max(12, h // 24),
            w - max(24, w // 14),
            h - max(24, h // 12),
        )
        pygame.draw.rect(surface, panel_bg, panel)
        pygame.draw.rect(surface, border, panel, 2)

        title = self._title_font.render("Stats & History", True, text_main)
        surface.blit(title, title.get_rect(midtop=(panel.centerx, panel.y + 14)))
        subtitle = self._hint_font.render(
            "Summary-first saved performance history with observed and theoretical calibration bounds.",
            True,
            text_muted,
        )
        surface.blit(subtitle, subtitle.get_rect(midtop=(panel.centerx, panel.y + 54)))

        body = pygame.Rect(panel.x + 18, panel.y + 86, panel.w - 36, panel.h - 128)
        left_w = max(280, int(body.w * 0.36))
        left_rect = pygame.Rect(body.x, body.y, left_w, body.h)
        right_rect = pygame.Rect(left_rect.right + 14, body.y, body.w - left_w - 14, body.h)

        pygame.draw.rect(surface, (6, 13, 92), left_rect)
        pygame.draw.rect(surface, (78, 102, 170), left_rect, 1)
        pygame.draw.rect(surface, (6, 13, 92), right_rect)
        pygame.draw.rect(surface, (78, 102, 170), right_rect, 1)

        left_title = self._small_font.render("Saved Codes", True, text_main)
        surface.blit(left_title, (left_rect.x + 12, left_rect.y + 10))

        if not self._summaries:
            empty = self._item_font.render("No saved history yet.", True, text_main)
            surface.blit(empty, empty.get_rect(center=body.center))
            footer = self._hint_font.render("Esc/Backspace: Back", True, text_muted)
            surface.blit(footer, footer.get_rect(midbottom=(panel.centerx, panel.bottom - 12)))
            self._row_hitboxes = {}
            return

        self._selected %= len(self._summaries)
        list_rect = pygame.Rect(left_rect.x + 10, left_rect.y + 40, left_rect.w - 20, left_rect.h - 50)
        row_h = 58
        gap = 8
        visible_count = max(1, (list_rect.h - gap) // (row_h + gap))
        max_scroll_top = max(0, len(self._summaries) - visible_count)
        if self._scroll_top > max_scroll_top:
            self._scroll_top = max_scroll_top
        if self._selected < self._scroll_top:
            self._scroll_top = self._selected
        elif self._selected >= self._scroll_top + visible_count:
            self._scroll_top = self._selected - visible_count + 1

        self._row_hitboxes = {}
        y = list_rect.y + gap
        for idx in range(self._scroll_top, min(len(self._summaries), self._scroll_top + visible_count)):
            summary = self._summaries[idx]
            row = pygame.Rect(list_rect.x, y, list_rect.w, row_h)
            self._row_hitboxes[idx] = row.copy()
            selected = idx == self._selected
            fill = active_bg if selected else (9, 20, 106)
            edge = (120, 142, 196) if selected else (62, 84, 152)
            pygame.draw.rect(surface, fill, row, border_radius=6)
            pygame.draw.rect(surface, edge, row, 2 if selected else 1, border_radius=6)

            label_color = active_text if selected else text_main
            meta_color = (46, 62, 112) if selected else text_muted
            label = self._label_for_code(summary.test_code)
            label_text = MenuScreen._fit_label(self, self._item_font, label, row.w - 24)
            label_surf = self._item_font.render(label_text, True, label_color)
            surface.blit(label_surf, (row.x + 10, row.y + 8))

            meta = (
                f"{summary.attempt_count} saved  "
                f"latest {self._fmt_ratio(summary.latest_score_ratio)}  "
                f"best {self._fmt_ratio(summary.best_score_ratio)}"
            )
            meta_surf = self._hint_font.render(meta, True, meta_color)
            surface.blit(meta_surf, (row.x + 10, row.y + 34))
            y += row_h + gap

        summary = self._selected_summary()
        if summary is None:
            return
        calibration = theoretical_score_calibration(summary.test_code)
        history = self._selected_history()

        header = self._item_font.render(self._label_for_code(summary.test_code), True, text_main)
        surface.blit(header, (right_rect.x + 12, right_rect.y + 10))
        code_line = self._hint_font.render(
            f"Code: {summary.test_code}",
            True,
            text_muted,
        )
        surface.blit(code_line, (right_rect.x + 12, right_rect.y + 40))

        detail_lines = [
            f"Saved attempts: {summary.attempt_count}",
            f"Latest score ratio: {self._fmt_ratio(summary.latest_score_ratio)}",
            (
                "Observed score ratio range: "
                f"{self._fmt_range(summary.worst_score_ratio, summary.best_score_ratio)}%"
            ),
            (
                "Theoretical score ratio range: "
                f"{self._fmt_range(calibration.score_ratio.minimum, calibration.score_ratio.maximum)}%"
            ),
            (
                "Observed accuracy range: "
                f"{self._fmt_range(summary.worst_accuracy, summary.best_accuracy)}%"
            ),
            (
                "Theoretical accuracy range: "
                f"{self._fmt_range(calibration.accuracy.minimum, calibration.accuracy.maximum)}%"
            ),
            (
                "Observed total score range: "
                f"{self._fmt_total(summary.worst_total_score)} to {self._fmt_total(summary.best_total_score)}"
            ),
            (
                "Theoretical total score range: "
                f"{self._fmt_total(calibration.total_score.minimum)} to "
                f"{'open-ended' if calibration.total_score.maximum is None else self._fmt_total(calibration.total_score.maximum)}"
            ),
            f"Observed difficulty range: {self._fmt_level_range(summary)}",
        ]
        if calibration.total_score.note:
            detail_lines.append(calibration.total_score.note)

        y = right_rect.y + 72
        for line in detail_lines:
            wrapped = self._wrap_text_lines(line, self._hint_font, right_rect.w - 24)
            for chunk in wrapped:
                text = self._hint_font.render(chunk, True, text_muted)
                surface.blit(text, (right_rect.x + 12, y))
                y += self._hint_font.get_linesize() + 2
            y += 2

        history_title = self._small_font.render("Recent Attempts", True, text_main)
        surface.blit(history_title, (right_rect.x + 12, y + 8))
        y += 34
        max_history_y = right_rect.bottom - 34
        for entry in history:
            timestamp = str(entry.completed_at_utc).replace("T", " ").replace("Z", " UTC")
            ratio = self._fmt_ratio(self._metric_float(entry.metrics, "score_ratio"))
            accuracy = self._fmt_ratio(self._metric_float(entry.metrics, "accuracy"))
            mode = str(entry.metrics.get("training_mode", "")).strip()
            level_bits = []
            if entry.difficulty_level_start is not None:
                level_bits.append(f"L{entry.difficulty_level_start}")
            if entry.difficulty_level_end is not None and entry.difficulty_level_end != entry.difficulty_level_start:
                level_bits.append(f"to L{entry.difficulty_level_end}")
            header_line = f"{timestamp}  score {ratio}  acc {accuracy}"
            if level_bits:
                header_line += "  " + " ".join(level_bits)
            for chunk in self._wrap_text_lines(header_line, self._hint_font, right_rect.w - 24):
                if y > max_history_y:
                    break
                surf = self._hint_font.render(chunk, True, text_main)
                surface.blit(surf, (right_rect.x + 12, y))
                y += self._hint_font.get_linesize() + 1
            if y > max_history_y:
                break
            if mode != "":
                mode_line = self._hint_font.render(f"mode {mode}", True, text_muted)
                surface.blit(mode_line, (right_rect.x + 24, y))
                y += self._hint_font.get_linesize() + 1
            if y > max_history_y:
                break
            y += 4

        footer = self._hint_font.render(
            "Up/Down: Select  R: Refresh  Esc/Backspace: Back",
            True,
            text_muted,
        )
        surface.blit(footer, footer.get_rect(midbottom=(panel.centerx, panel.bottom - 12)))

    def poll_bound_input(self) -> None:
        while self._app.consume_bound_action("menu_up"):
            self.handle_event(pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_UP, "unicode": ""}))
        while self._app.consume_bound_action("menu_down"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_DOWN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )


class TestSeedSettingsScreen:
    __test__ = False

    def __init__(self, app: App) -> None:
        self._app = app
        self._selected = 0
        self._title_font = pygame.font.Font(None, 42)
        self._item_font = pygame.font.Font(None, 30)
        self._hint_font = pygame.font.Font(None, 22)
        self._row_hitboxes: dict[int, pygame.Rect] = {}
        self._control_hitboxes: dict[tuple[int, str], pygame.Rect] = {}
        self._editing_seed = False
        self._seed_input = ""

    def _rows(self) -> list[tuple[str, str, str]]:
        return [
            (
                "rapid_tracking_override",
                "Rapid Tracking Seed Override",
                "ON" if self._app.rapid_tracking_seed_override_enabled() else "OFF",
            ),
            (
                "rapid_tracking_seed",
                "Rapid Tracking Seed",
                str(self._app.rapid_tracking_seed_value()),
            ),
            ("back", "Back", "Return to Settings"),
        ]

    def _begin_seed_edit(self) -> None:
        self._editing_seed = True
        self._seed_input = str(self._app.rapid_tracking_seed_value())

    def _finish_seed_edit(self) -> None:
        if self._seed_input.strip():
            self._app.set_rapid_tracking_seed_value(int(self._seed_input.strip()))
        self._editing_seed = False
        self._seed_input = ""

    def _cancel_seed_edit(self) -> None:
        self._editing_seed = False
        self._seed_input = ""

    def handle_event(self, event: pygame.event.Event) -> None:
        rows = self._rows()
        if self._editing_seed:
            if event.type != pygame.KEYDOWN:
                return
            key = event.key
            if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE) and self._seed_input == "":
                self._cancel_seed_edit()
                return
            if key == pygame.K_ESCAPE:
                self._cancel_seed_edit()
                return
            if key == pygame.K_RETURN or key == pygame.K_KP_ENTER:
                self._finish_seed_edit()
                return
            if key == pygame.K_BACKSPACE:
                self._seed_input = self._seed_input[:-1]
                return
            if key == pygame.K_r:
                self._seed_input = str(_new_seed())
                return
            ch = str(getattr(event, "unicode", ""))
            if ch.isdigit():
                next_token = (self._seed_input + ch).lstrip("0")
                self._seed_input = next_token or "0"
            return

        if event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._row_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected = idx
                        break
            return
        if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for (idx, action), rect in self._control_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    self._adjust_row(rows[idx][0], action)
                    return
            for idx, rect in self._row_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    self._activate_row(rows[idx][0])
                    return
            return
        if event.type != pygame.KEYDOWN:
            return

        key = event.key
        if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.pop()
            return
        if key in (pygame.K_UP, pygame.K_w):
            self._selected = (self._selected - 1) % max(1, len(rows))
            return
        if key in (pygame.K_DOWN, pygame.K_s):
            self._selected = (self._selected + 1) % max(1, len(rows))
            return
        if key in (pygame.K_LEFT, pygame.K_a):
            self._adjust_row(rows[self._selected][0], "dec")
            return
        if key in (pygame.K_RIGHT, pygame.K_d):
            self._adjust_row(rows[self._selected][0], "inc")
            return
        if key in (pygame.K_RETURN, pygame.K_KP_ENTER, pygame.K_SPACE):
            self._activate_row(rows[self._selected][0])

    def _activate_row(self, key: str) -> None:
        if key == "back":
            self._app.pop()
            return
        if key == "rapid_tracking_override":
            self._app.set_rapid_tracking_seed_override_enabled(
                not self._app.rapid_tracking_seed_override_enabled()
            )
            return
        if key == "rapid_tracking_seed":
            self._begin_seed_edit()

    def _adjust_row(self, key: str, action: str) -> None:
        if key == "rapid_tracking_override":
            self._app.set_rapid_tracking_seed_override_enabled(
                not self._app.rapid_tracking_seed_override_enabled()
            )
            return
        if key == "rapid_tracking_seed":
            delta = -1 if action == "dec" else 1
            current = self._app.rapid_tracking_seed_value()
            self._app.set_rapid_tracking_seed_value(current + delta)

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        bg = (4, 10, 72)
        panel_bg = (8, 18, 104)
        border = (226, 236, 255)
        text_main = (238, 245, 255)
        text_muted = (186, 200, 224)
        active_bg = (244, 248, 255)
        active_text = (14, 26, 74)

        surface.fill(bg)
        panel = pygame.Rect(max(12, w // 28), max(12, h // 24), w - max(24, w // 14), h - max(24, h // 12))
        pygame.draw.rect(surface, panel_bg, panel)
        pygame.draw.rect(surface, border, panel, 2)

        title = self._title_font.render("Test Seeds", True, text_main)
        surface.blit(title, title.get_rect(midtop=(panel.centerx, panel.y + 14)))
        subtitle = self._hint_font.render(
            "Use a persistent manual seed when you want Rapid Tracking runs to be reproducible.",
            True,
            text_muted,
        )
        surface.blit(subtitle, subtitle.get_rect(midtop=(panel.centerx, panel.y + 54)))

        rows = self._rows()
        self._selected %= max(1, len(rows))
        list_rect = pygame.Rect(panel.x + 18, panel.y + 86, panel.w - 36, panel.h - 128)
        pygame.draw.rect(surface, (6, 13, 92), list_rect)
        pygame.draw.rect(surface, (78, 102, 170), list_rect, 1)

        self._row_hitboxes = {}
        self._control_hitboxes = {}
        row_h = 46
        gap = 10
        y = list_rect.y + 16
        for idx, (key, label, value) in enumerate(rows):
            row = pygame.Rect(list_rect.x + 16, y, list_rect.w - 32, row_h)
            self._row_hitboxes[idx] = row.copy()
            selected = idx == self._selected
            fill = active_bg if selected else (9, 20, 106)
            edge = (120, 142, 196) if selected else (62, 84, 152)
            pygame.draw.rect(surface, fill, row, border_radius=6)
            pygame.draw.rect(surface, edge, row, 2 if selected else 1, border_radius=6)
            label_color = active_text if selected else text_main
            value_color = (46, 62, 112) if selected else text_muted

            label_text = MenuScreen._fit_label(self, self._item_font, label, row.w - 240)
            label_surf = self._item_font.render(label_text, True, label_color)
            surface.blit(label_surf, (row.x + 12, row.y + (row.h - label_surf.get_height()) // 2))

            if key == "back":
                value_surf = self._hint_font.render(value, True, value_color)
                surface.blit(value_surf, value_surf.get_rect(midright=(row.right - 14, row.centery)))
            elif key == "rapid_tracking_seed":
                value_box = pygame.Rect(row.right - 176, row.y + 6, 164, row.h - 12)
                dec_box = pygame.Rect(value_box.x, value_box.y, 32, value_box.h)
                inc_box = pygame.Rect(value_box.right - 32, value_box.y, 32, value_box.h)
                mid_box = pygame.Rect(dec_box.right + 6, value_box.y, value_box.w - 76, value_box.h)
                self._control_hitboxes[(idx, "dec")] = dec_box.copy()
                self._control_hitboxes[(idx, "inc")] = inc_box.copy()
                for box, glyph in ((dec_box, "<"), (inc_box, ">")):
                    pygame.draw.rect(surface, (20, 32, 92), box, border_radius=5)
                    pygame.draw.rect(surface, (110, 130, 184), box, 1, border_radius=5)
                    glyph_surf = self._item_font.render(glyph, True, text_main)
                    surface.blit(glyph_surf, glyph_surf.get_rect(center=box.center))
                pygame.draw.rect(surface, (14, 26, 78), mid_box, border_radius=5)
                pygame.draw.rect(surface, (92, 112, 168), mid_box, 1, border_radius=5)
                value_surf = self._hint_font.render(value, True, text_main)
                surface.blit(value_surf, value_surf.get_rect(center=mid_box.center))
            else:
                value_box = pygame.Rect(row.right - 120, row.y + 6, 108, row.h - 12)
                self._control_hitboxes[(idx, "toggle")] = value_box.copy()
                pygame.draw.rect(surface, (14, 26, 78), value_box, border_radius=5)
                pygame.draw.rect(surface, (92, 112, 168), value_box, 1, border_radius=5)
                value_surf = self._hint_font.render(value, True, text_main)
                surface.blit(value_surf, value_surf.get_rect(center=value_box.center))

            y += row_h + gap

        footer = self._hint_font.render(
            "Enter edits the seed. While editing: digits, Backspace, R=randomize, Enter=save, Esc=cancel.",
            True,
            text_muted,
        )
        surface.blit(footer, footer.get_rect(midbottom=(panel.centerx, panel.bottom - 12)))

        if self._editing_seed:
            dim = pygame.Surface(surface.get_size(), pygame.SRCALPHA)
            dim.fill((4, 8, 18, 168))
            surface.blit(dim, (0, 0))

            overlay = pygame.Rect(0, 0, min(520, w - 40), 180)
            overlay.center = (w // 2, h // 2)
            pygame.draw.rect(surface, panel_bg, overlay, border_radius=10)
            pygame.draw.rect(surface, border, overlay, 2, border_radius=10)

            title = self._item_font.render("Rapid Tracking Seed", True, text_main)
            surface.blit(title, title.get_rect(midtop=(overlay.centerx, overlay.y + 18)))
            prompt = self._hint_font.render(
                "Type a positive integer seed. Press R to randomize before saving.",
                True,
                text_muted,
            )
            surface.blit(prompt, prompt.get_rect(midtop=(overlay.centerx, overlay.y + 50)))

            box = pygame.Rect(overlay.x + 40, overlay.y + 84, overlay.w - 80, 42)
            pygame.draw.rect(surface, (14, 26, 78), box, border_radius=6)
            pygame.draw.rect(surface, (92, 112, 168), box, 1, border_radius=6)
            caret = "|" if (pygame.time.get_ticks() // 500) % 2 == 0 else ""
            token = self._seed_input if self._seed_input != "" else " "
            seed_surf = self._item_font.render(token + caret, True, text_main)
            surface.blit(seed_surf, seed_surf.get_rect(center=box.center))

            hint = self._hint_font.render(
                "Enter: Save   Esc: Cancel   Backspace: Delete   R: Randomize",
                True,
                text_muted,
            )
            surface.blit(hint, hint.get_rect(midbottom=(overlay.centerx, overlay.bottom - 20)))

    def poll_bound_input(self) -> None:
        if self._editing_seed:
            while self._app.consume_bound_action("menu_back"):
                self.handle_event(
                    pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
                )
            while self._app.consume_bound_action("menu_select"):
                self.handle_event(
                    pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RETURN, "unicode": ""})
                )
            return
        while self._app.consume_bound_action("menu_up"):
            self.handle_event(pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_UP, "unicode": ""}))
        while self._app.consume_bound_action("menu_down"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_DOWN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_left"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_LEFT, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_right"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RIGHT, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_select"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RETURN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )


class RapidTrackingSettingsScreen:
    def __init__(self, app: App) -> None:
        self._app = app
        self._selected = 0
        self._title_font = pygame.font.Font(None, 42)
        self._item_font = pygame.font.Font(None, 30)
        self._hint_font = pygame.font.Font(None, 22)
        self._row_hitboxes: dict[int, pygame.Rect] = {}
        self._control_hitboxes: dict[tuple[int, str], pygame.Rect] = {}

    def _rows(self) -> list[tuple[str, str, str]]:
        return [
            (
                "invert_pitch",
                "Invert Pitch",
                "ON" if self._app.rapid_tracking_invert_pitch_enabled() else "OFF",
            ),
            ("back", "Back", "Return to Settings"),
        ]

    def _toggle_invert_pitch(self) -> None:
        self._app.set_rapid_tracking_invert_pitch_enabled(
            not self._app.rapid_tracking_invert_pitch_enabled()
        )

    def handle_event(self, event: pygame.event.Event) -> None:
        rows = self._rows()
        if event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._row_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected = idx
                        break
            return
        if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for (idx, _action), rect in self._control_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    self._toggle_invert_pitch()
                    return
            for idx, rect in self._row_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    key = rows[idx][0]
                    if key == "back":
                        self._app.pop()
                    elif key == "invert_pitch":
                        self._toggle_invert_pitch()
                    return
            return
        if event.type != pygame.KEYDOWN:
            return

        key = event.key
        if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.pop()
            return
        if key in (pygame.K_UP, pygame.K_w):
            self._selected = (self._selected - 1) % max(1, len(rows))
            return
        if key in (pygame.K_DOWN, pygame.K_s):
            self._selected = (self._selected + 1) % max(1, len(rows))
            return
        if key in (pygame.K_LEFT, pygame.K_a, pygame.K_RIGHT, pygame.K_d):
            if rows[self._selected][0] == "invert_pitch":
                self._toggle_invert_pitch()
            return
        if key in (pygame.K_RETURN, pygame.K_KP_ENTER, pygame.K_SPACE):
            current = rows[self._selected][0]
            if current == "back":
                self._app.pop()
                return
            if current == "invert_pitch":
                self._toggle_invert_pitch()

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        bg = (4, 10, 72)
        panel_bg = (8, 18, 104)
        border = (226, 236, 255)
        text_main = (238, 245, 255)
        text_muted = (186, 200, 224)
        active_bg = (244, 248, 255)
        active_text = (14, 26, 74)

        surface.fill(bg)
        panel = pygame.Rect(
            max(12, w // 28),
            max(12, h // 24),
            w - max(24, w // 14),
            h - max(24, h // 12),
        )
        pygame.draw.rect(surface, panel_bg, panel)
        pygame.draw.rect(surface, border, panel, 2)

        title = self._title_font.render("Rapid Tracking Settings", True, text_main)
        surface.blit(title, title.get_rect(midtop=(panel.centerx, panel.y + 14)))
        subtitle = self._hint_font.render(
            "Invert Pitch applies after joystick axis calibration and affects every RT control path.",
            True,
            text_muted,
        )
        surface.blit(subtitle, subtitle.get_rect(midtop=(panel.centerx, panel.y + 54)))

        rows = self._rows()
        self._selected %= max(1, len(rows))
        list_rect = pygame.Rect(panel.x + 18, panel.y + 86, panel.w - 36, panel.h - 128)
        pygame.draw.rect(surface, (6, 13, 92), list_rect)
        pygame.draw.rect(surface, (78, 102, 170), list_rect, 1)

        self._row_hitboxes = {}
        self._control_hitboxes = {}
        row_h = 46
        gap = 10
        y = list_rect.y + 16
        for idx, (key, label, value) in enumerate(rows):
            row = pygame.Rect(list_rect.x + 16, y, list_rect.w - 32, row_h)
            self._row_hitboxes[idx] = row.copy()
            selected = idx == self._selected
            fill = active_bg if selected else (9, 20, 106)
            edge = (120, 142, 196) if selected else (62, 84, 152)
            pygame.draw.rect(surface, fill, row, border_radius=6)
            pygame.draw.rect(surface, edge, row, 2 if selected else 1, border_radius=6)
            label_color = active_text if selected else text_main
            value_color = (46, 62, 112) if selected else text_muted

            label_text = MenuScreen._fit_label(self, self._item_font, label, row.w - 240)
            label_surf = self._item_font.render(label_text, True, label_color)
            surface.blit(label_surf, (row.x + 12, row.y + (row.h - label_surf.get_height()) // 2))

            if key == "back":
                value_surf = self._hint_font.render(value, True, value_color)
                surface.blit(value_surf, value_surf.get_rect(midright=(row.right - 14, row.centery)))
            else:
                value_box = pygame.Rect(row.right - 120, row.y + 6, 108, row.h - 12)
                self._control_hitboxes[(idx, "toggle")] = value_box.copy()
                pygame.draw.rect(surface, (14, 26, 78), value_box, border_radius=5)
                pygame.draw.rect(surface, (92, 112, 168), value_box, 1, border_radius=5)
                value_surf = self._hint_font.render(value, True, text_main)
                surface.blit(value_surf, value_surf.get_rect(center=value_box.center))

            y += row_h + gap

        footer = self._hint_font.render(
            "Enter or Left/Right toggles pitch inversion. Esc returns to Settings.",
            True,
            text_muted,
        )
        surface.blit(footer, footer.get_rect(midbottom=(panel.centerx, panel.bottom - 12)))

    def poll_bound_input(self) -> None:
        while self._app.consume_bound_action("menu_up"):
            self.handle_event(pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_UP, "unicode": ""}))
        while self._app.consume_bound_action("menu_down"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_DOWN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_left"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_LEFT, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_right"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RIGHT, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_select"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RETURN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )


class DisplaySettingsScreen:
    def __init__(self, app: App) -> None:
        self._app = app
        self._selected = 0
        self._title_font = pygame.font.Font(None, 42)
        self._item_font = pygame.font.Font(None, 30)
        self._hint_font = pygame.font.Font(None, 22)
        self._row_hitboxes: dict[int, pygame.Rect] = {}
        self._control_hitboxes: dict[tuple[int, str], pygame.Rect] = {}

    def _rows(self) -> list[tuple[str, str, str]]:
        stored = self._app.stored_use_opengl()
        if stored is None:
            value = "AUTO"
        else:
            value = "ON" if stored else "OFF"
        return [
            ("use_opengl", "OpenGL Renderer", value),
            ("back", "Back", "Return to Settings"),
        ]

    def _toggle_use_opengl(self) -> None:
        current = self._app.stored_use_opengl()
        next_value = True if current is None else not current
        self._app.set_stored_use_opengl(next_value)

    def handle_event(self, event: pygame.event.Event) -> None:
        rows = self._rows()
        if event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._row_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected = idx
                        break
            return
        if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for (idx, action), rect in self._control_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    if rows[idx][0] == "use_opengl" and action == "toggle":
                        self._toggle_use_opengl()
                    return
            for idx, rect in self._row_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    self._activate_row(rows[idx][0])
                    return
            return
        if event.type != pygame.KEYDOWN:
            return

        key = event.key
        if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.pop()
            return
        if key in (pygame.K_UP, pygame.K_w):
            self._selected = (self._selected - 1) % max(1, len(rows))
            return
        if key in (pygame.K_DOWN, pygame.K_s):
            self._selected = (self._selected + 1) % max(1, len(rows))
            return
        if key in (pygame.K_LEFT, pygame.K_a, pygame.K_RIGHT, pygame.K_d):
            if rows[self._selected][0] == "use_opengl":
                self._toggle_use_opengl()
            return
        if key in (pygame.K_RETURN, pygame.K_KP_ENTER, pygame.K_SPACE):
            self._activate_row(rows[self._selected][0])

    def _activate_row(self, key: str) -> None:
        if key == "back":
            self._app.pop()
            return
        if key == "use_opengl":
            self._toggle_use_opengl()

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        bg = (4, 10, 72)
        panel_bg = (8, 18, 104)
        border = (226, 236, 255)
        text_main = (238, 245, 255)
