class OpenGLFailureScreen:
    def __init__(self, app: App, *, failure: OpenGLFailureInfo) -> None:
        self._app = app
        self._failure = failure
        self._selected = 0
        self._title_font = pygame.font.Font(None, 44)
        self._item_font = pygame.font.Font(None, 32)
        self._body_font = pygame.font.Font(None, 28)
        self._hint_font = pygame.font.Font(None, 22)
        self._row_hitboxes: dict[int, pygame.Rect] = {}

    def _rows(self) -> list[tuple[str, str, str, bool]]:
        return [("quit", "Quit", "Exit the app.", True)]

    def _activate_selected(self) -> None:
        action, _label, _detail, enabled = self._rows()[self._selected % len(self._rows())]
        if not enabled:
            return
        if action == "quit":
            self._app.quit(exit_reason="renderer_failure_quit", exit_code=1)

    def handle_event(self, event: pygame.event.Event) -> None:
        rows = self._rows()
        if event.type == pygame.MOUSEMOTION:
            pos = getattr(event, "pos", None)
            if pos is not None:
                for idx, rect in self._row_hitboxes.items():
                    if rect.collidepoint(pos):
                        self._selected = idx
                        break
            return
        if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
            pos = getattr(event, "pos", None)
            if pos is None:
                return
            for idx, rect in self._row_hitboxes.items():
                if rect.collidepoint(pos):
                    self._selected = idx
                    self._activate_selected()
                    return
            return
        if event.type != pygame.KEYDOWN:
            return

        key = event.key
        if key in (pygame.K_ESCAPE, pygame.K_BACKSPACE):
            self._app.quit(exit_reason="renderer_failure_quit", exit_code=1)
            return
        if key in (pygame.K_UP, pygame.K_w):
            self._selected = (self._selected - 1) % max(1, len(rows))
            return
        if key in (pygame.K_DOWN, pygame.K_s):
            self._selected = (self._selected + 1) % max(1, len(rows))
            return
        if key in (pygame.K_RETURN, pygame.K_KP_ENTER, pygame.K_SPACE):
            self._activate_selected()

    def render(self, surface: pygame.Surface) -> None:
        w, h = surface.get_size()
        bg = (10, 10, 18)
        panel_bg = (24, 22, 44)
        border = (246, 210, 168)
        text_main = (255, 242, 220)
        text_muted = (226, 210, 188)
        active_bg = (255, 243, 224)
        active_text = (64, 30, 18)

        surface.fill(bg)
        panel = pygame.Rect(max(20, w // 10), max(20, h // 12), w - max(40, w // 5), h - max(40, h // 6))
        pygame.draw.rect(surface, panel_bg, panel, border_radius=14)
        pygame.draw.rect(surface, border, panel, 2, border_radius=14)

        title = self._title_font.render("Renderer Error", True, text_main)
        surface.blit(title, title.get_rect(midtop=(panel.centerx, panel.y + 18)))

        summary = self._body_font.render(self._failure.summary, True, text_main)
        surface.blit(summary, summary.get_rect(midtop=(panel.centerx, panel.y + 66)))

        body = pygame.Rect(panel.x + 28, panel.y + 108, panel.w - 56, 170)
        detail_lines = [self._failure.detail]
        if self._failure.diagnostic_code:
            detail_lines.append(f"Report code: {self._failure.diagnostic_code}")
        if self._failure.location:
            detail_lines.append(f"Location: {self._failure.location}")
        detail_lines.append("The interactive app requires the ModernGL renderer.")
        self._draw_wrapped_text(
            surface,
            "\n\n".join(detail_lines),
            body,
            color=text_muted,
            font=self._hint_font,
            max_lines=10,
        )

        rows = self._rows()
        self._selected %= max(1, len(rows))
        self._row_hitboxes = {}
        list_rect = pygame.Rect(panel.x + 28, body.bottom + 10, panel.w - 56, panel.bottom - body.bottom - 58)
        gap = 10
        row_h = 54
        y = list_rect.y
        for idx, (_action, label, detail, enabled) in enumerate(rows):
            row = pygame.Rect(list_rect.x, y, list_rect.w, row_h)
            self._row_hitboxes[idx] = row.copy()
            selected = idx == self._selected
            if selected:
                pygame.draw.rect(surface, active_bg, row, border_radius=8)
                pygame.draw.rect(surface, border, row, 2, border_radius=8)
            else:
                pygame.draw.rect(surface, (38, 34, 64), row, border_radius=8)
                pygame.draw.rect(surface, (138, 118, 106), row, 1, border_radius=8)
            label_color = active_text if selected else text_main
            detail_color = (120, 78, 52) if selected else text_muted
            if not enabled:
                label_color = (150, 132, 120)
                detail_color = (132, 118, 108)
            title_surf = self._item_font.render(label, True, label_color)
            surface.blit(title_surf, (row.x + 14, row.y + 8))
            detail_surf = self._hint_font.render(detail, True, detail_color)
            surface.blit(detail_surf, (row.x + 14, row.y + 30))
            y += row_h + gap

        footer = self._hint_font.render("Enter or Esc quits the app.", True, text_muted)
        surface.blit(footer, footer.get_rect(midbottom=(panel.centerx, panel.bottom - 16)))

    def _draw_wrapped_text(
        self,
        surface: pygame.Surface,
        text: str,
        rect: pygame.Rect,
        *,
        color: tuple[int, int, int],
        font: pygame.font.Font,
        max_lines: int,
    ) -> None:
        lines = []
        for paragraph in str(text).splitlines():
            words = paragraph.split()
            if not words:
                lines.append("")
                continue
            current = words[0]
            for word in words[1:]:
                candidate = f"{current} {word}"
                if font.size(candidate)[0] <= rect.w:
                    current = candidate
                else:
                    lines.append(current)
                    current = word
            lines.append(current)
        y = rect.y
        for line in lines[:max_lines]:
            surf = font.render(line, True, color)
            surface.blit(surf, (rect.x, y))
            y += font.get_linesize() + 2

    def poll_bound_input(self) -> None:
        while self._app.consume_bound_action("menu_up"):
            self.handle_event(pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_UP, "unicode": ""}))
        while self._app.consume_bound_action("menu_down"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_DOWN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_select"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_RETURN, "unicode": ""})
            )
        while self._app.consume_bound_action("menu_back"):
            self.handle_event(
                pygame.event.Event(pygame.KEYDOWN, {"key": pygame.K_ESCAPE, "unicode": ""})
            )


class _AdaptiveRuntimeTracker:
    _WINDOW_INTERVAL_MS = 25_000

    def __init__(
        self,
        *,
        engine: object,
        test_code: str,
        activity_kind: str,
        context: ResolvedDifficultyContext,
    ) -> None:
        self._engine = engine
        self._test_code = str(test_code)
        self._activity_kind = str(activity_kind)
        self._context = context
        self._controller = (
            AdaptiveDifficultyController(
                launch_level=int(context.launch_level),
                policy=policy_for_activity_kind(
                    self._activity_kind,
                    intended_use=getattr(engine, "_mode", None),
                ),
            )
            if context.adaptive_enabled
            else None
        )
        self._last_event_count = 0
        self._last_window_tick_ms = pygame.time.get_ticks()
        self._last_summary_attempted = 0
        self._last_summary_correct = 0
        self._last_summary_timeouts = 0

        setattr(self._engine, "_difficulty_code", self._test_code)
        setattr(self._engine, "_adaptive_start_level", int(context.launch_level))
        setattr(self._engine, "_adaptive_end_level", int(context.launch_level))
        setattr(self._engine, "_adaptive_change_count", 0)
        setattr(self._engine, "_difficulty_changes", [])
        apply_level_to_engine(self._engine, test_code=self._test_code, level=context.launch_level)
        self._disable_builtin_adaptation()
        self._refresh_metric_overrides()

    def sync(self) -> None:
        if self._controller is None:
            return
        if getattr(self._engine, "phase", None) is not Phase.SCORED:
            return
        if not self._consume_new_scored_events():
            self._consume_summary_window()

    def _disable_builtin_adaptation(self) -> None:
        adaptive_config = getattr(self._engine, "_adaptive_config", None)
        if adaptive_config is None or not hasattr(adaptive_config, "enabled"):
            return
        try:
            setattr(adaptive_config, "enabled", False)
        except Exception:
            return

    def _consume_new_scored_events(self) -> bool:
        getter = getattr(self._engine, "events", None)
        if not callable(getter):
            return False
        try:
            events = getter()
        except Exception:
            return False
        if not isinstance(events, (list, tuple)):
            return False

        saw_scored = False
        start = max(0, int(self._last_event_count))
        self._last_event_count = len(events)
        for event in events[start:]:
            if getattr(event, "phase", None) is not Phase.SCORED:
                continue
            is_correct = bool(getattr(event, "is_correct", False))
            is_timeout = bool(getattr(event, "is_timeout", False))
            score = getattr(event, "score", None)
            max_score = getattr(event, "max_score", None)
            score_ratio = None
            try:
                if score is not None and max_score not in (None, 0, 0.0):
                    score_ratio = float(score) / float(max_score)
            except Exception:
                score_ratio = None
            response_time_ms = None
            try:
                raw_rt = getattr(event, "response_time_s", None)
                if raw_rt is not None:
                    response_time_ms = float(raw_rt) * 1000.0
            except Exception:
                response_time_ms = None
            decision = self._controller.record_item(
                is_correct=is_correct,
                is_timeout=is_timeout,
                score_ratio=score_ratio,
                response_time_ms=response_time_ms,
            )
            saw_scored = True
            if decision is not None:
                self._apply_decision(decision)
        return saw_scored

    def _consume_summary_window(self) -> None:
        scorer = getattr(self._engine, "scored_summary", None)
        if not callable(scorer):
            return
        now_ms = pygame.time.get_ticks()
        try:
            summary = scorer()
        except Exception:
            return
        attempted = int(getattr(summary, "attempted", 0) or 0)
        correct = int(getattr(summary, "correct", 0) or 0)
        timeouts = int(getattr(summary, "timeouts", 0) or 0)
        attempted_delta = attempted - self._last_summary_attempted
        if attempted_delta <= 0:
            return
        if attempted_delta < 3 and (now_ms - self._last_window_tick_ms) < self._WINDOW_INTERVAL_MS:
            return
        correct_delta = max(0, correct - self._last_summary_correct)
        timeout_delta = max(0, timeouts - self._last_summary_timeouts)
        timeout_rate = 0.0 if attempted_delta <= 0 else float(timeout_delta) / float(attempted_delta)
        mean_rt_ms = None
        try:
            mean_rt = getattr(summary, "mean_response_time_s", None)
            if mean_rt is not None:
                mean_rt_ms = float(mean_rt) * 1000.0
        except Exception:
            mean_rt_ms = None
        score_ratio = None
        try:
            raw_score_ratio = getattr(summary, "score_ratio", None)
            if raw_score_ratio is not None:
                score_ratio = float(raw_score_ratio)
        except Exception:
            score_ratio = None

        decision = self._controller.record_window(
            attempted=attempted_delta,
            correct=correct_delta,
            timeout_rate=timeout_rate,
            score_ratio=score_ratio,
            mean_rt_ms=mean_rt_ms,
        )
        self._last_summary_attempted = attempted
        self._last_summary_correct = correct
        self._last_summary_timeouts = timeouts
        self._last_window_tick_ms = now_ms
        if decision is not None:
            self._apply_decision(decision)

    def _apply_decision(self, decision: AdaptiveDifficultyDecision) -> None:
        changes = getattr(self._engine, "_difficulty_changes", None)
        if not isinstance(changes, list):
            changes = []
            setattr(self._engine, "_difficulty_changes", changes)
        changes.append(decision)
        setattr(self._engine, "_adaptive_end_level", int(decision.new_level))
        setattr(self._engine, "_adaptive_change_count", len(changes))
        apply_level_to_engine(self._engine, test_code=self._test_code, level=decision.new_level)
        self._refresh_metric_overrides()

    def _refresh_metric_overrides(self) -> None:
        end_level = int(getattr(self._engine, "_adaptive_end_level", self._context.launch_level))
        change_count = int(getattr(self._engine, "_adaptive_change_count", 0))
        overrides = getattr(self._engine, "_result_metrics_overrides", None)
        if not isinstance(overrides, dict):
            overrides = {}
            setattr(self._engine, "_result_metrics_overrides", overrides)
        overrides.update(
            {
                "adaptive_mode": str(self._context.mode),
                "adaptive_start_level": str(int(self._context.launch_level)),
                "adaptive_end_level": str(int(end_level)),
                "adaptive_change_count": str(int(change_count)),
                "adaptive_scope_code": self._context.code_scope_key,
                "adaptive_scope_family": self._context.family_scope_key,
                "adaptive_scope_primitive": self._context.primitive_scope_key,
            }
        )


