    def _attach_runtime_telemetry(self) -> None:
        runtime = self._cognitive_updating_runtime
        if runtime is None:
            setattr(self._engine, "_telemetry_runtime_events", None)
            return
        setattr(self._engine, "_telemetry_runtime_events", runtime.events())

    def shell_activity_active(self) -> bool:
        return self._test_code is not None and not self._activity_finalized

    def shell_pause_available(self) -> bool:
        snap = self._engine.snapshot()
        return (
            snap.phase in (
                Phase.INSTRUCTIONS,
                Phase.PRACTICE,
                Phase.PRACTICE_DONE,
                Phase.SCORED,
                Phase.RESULTS,
            )
            and not self._loading_modal_active(snap.phase)
        )

    def shell_pause_set_active(self, active: bool) -> None:
        self._set_pause_menu_state(active)

    def shell_pause_restart_with_seed(self, seed_override: int | None = None) -> None:
        self._set_pause_menu_state(False)
        self._activity_close_reason = "back_abort"
        replacement = self._build_restart_screen(seed_override)
        self._app.replace_top(replacement)

    def shell_pause_restart(self) -> None:
        self.shell_pause_restart_with_seed(None)

    def shell_pause_main_menu(self) -> None:
        self._set_pause_menu_state(False)
        self._activity_close_reason = "main_menu_abort"
        self._stop_auditory_audio()
        self._stop_situational_awareness_audio()
        self._app.pop_to_root()

    def shell_emergency_exit(self, reason: str) -> None:
        self._set_pause_menu_state(False)
        self._stop_auditory_audio()
        self._stop_situational_awareness_audio()
        self.abort_activity(reason)
        self._app.pop_to_root()

    def shell_activity_label(self) -> str:
        return self._engine.snapshot().title

    def abort_activity(self, reason: str) -> None:
        if self._activity_finalized or self._test_code is None:
            return
        self._attach_runtime_telemetry()
        self._app.abort_activity_session(
            owner=self,
            engine=self._engine,
            completion_reason=str(reason),
            test_code=self._test_code,
            test_version=self._test_version,
        )
        self._activity_finalized = True

    def close(self) -> None:
        self._clear_review_state()
        snap = self._engine.snapshot()
        if snap.phase is Phase.RESULTS:
            self._persist_results_if_needed(snap)
        elif not self._activity_finalized and self._test_code is not None:
            self.abort_activity(self._activity_close_reason or "back_abort")
        self._stop_auditory_audio()
        self._stop_situational_awareness_audio()
        self._dispose_auditory_panda_renderer()
        self._dispose_rapid_tracking_panda_renderer()
        self._dispose_spatial_integration_panda_renderer()
        self._dispose_trace_test_1_panda_renderer()
        self._dispose_trace_test_2_panda_renderer()
        exit_engine = getattr(self._engine, "exit", None)
        if callable(exit_engine):
            exit_engine()

    def _sync_situational_awareness_audio(
        self,
        *,
        phase: Phase,
        payload: SituationalAwarenessPayload | None,
    ) -> None:
        self._sa_audio.sync(phase=phase, payload=payload)

    def _stop_situational_awareness_audio(self) -> None:
        self._sa_audio.stop()

    def _calibrated_joystick_axis_value(
        self,
        joystick: pygame.joystick.Joystick | None,
        axis_index: int,
    ) -> float | None:
        if joystick is None:
            return None
        try:
            axis_count = int(joystick.get_numaxes())
        except Exception:
            axis_count = 0
        if axis_index < 0 or axis_index >= axis_count:
            return None
        raw = _axis_raw_value(joystick, axis_index)
        profiles = self._app.input_profiles_store()
        if profiles is None:
            return raw
        try:
            profile = profiles.active_profile()
        except Exception:
            return raw
        settings = profiles.get_axis_calibration(
            profile_id=profile.profile_id,
            axis_key=_axis_key(joystick, axis_index),
        )
        return _apply_axis_calibration(raw, settings)

    def _read_rapid_tracking_control(
        self,
        *,
        control_scheme: str,
    ) -> tuple[float, float]:
        joysticks = _iter_connected_joysticks()
        primary = _select_primary_stick(joysticks)
        rudder = _select_rudder_device(joysticks)
        scheme = normalize_rapid_tracking_control_scheme(control_scheme)
        horizontal: float | None = None
        vertical: float | None = None

        if self._app.has_explicit_axis_role_binding("primary_vertical"):
            vertical = self._app.bound_axis_role_value("primary_vertical")
        if vertical is None:
            vertical = self._calibrated_joystick_axis_value(primary, 1)

        if scheme == "rudder_horizontal":
            if self._app.has_explicit_axis_role_binding("rudder_horizontal"):
                horizontal = self._app.bound_axis_role_value("rudder_horizontal")
            if horizontal is None:
                horizontal = _read_preferred_axis_value(
                    joystick=rudder,
                    indices=(3, 2, 0, 1),
                    reader=self._calibrated_joystick_axis_value,
                )
            if horizontal is None:
                horizontal = _read_preferred_axis_value(
                    joystick=primary,
                    indices=(3, 4, 5, 2, 1, 0),
                    reader=self._calibrated_joystick_axis_value,
                )
        else:
            if self._app.has_explicit_axis_role_binding("primary_horizontal"):
                horizontal = self._app.bound_axis_role_value("primary_horizontal")
            if horizontal is None:
                horizontal = self._calibrated_joystick_axis_value(primary, 0)
        if self._app.rapid_tracking_invert_pitch_enabled():
            vertical = -float(vertical or 0.0)

        return (
            max(-1.0, min(1.0, float(horizontal or 0.0))),
            max(-1.0, min(1.0, float(vertical or 0.0))),
        )

    def _read_sensory_motor_control(
        self,
        *,
        control_mode: str = "split",
        axis_focus: str = "both",
        allow_keyboard_fallback: bool = True,
    ) -> tuple[float, float]:
        keys = pygame.key.get_pressed()
        keyboard_state = self._camera_keyboard_state

        def _pressed(key: int) -> bool:
            return bool(keys[key]) or key in keyboard_state

        arrow_horizontal = (1.0 if _pressed(pygame.K_LEFT) else 0.0) - (
            1.0 if _pressed(pygame.K_RIGHT) else 0.0
        )
        ad_horizontal = (1.0 if _pressed(pygame.K_a) else 0.0) - (
            1.0 if _pressed(pygame.K_d) else 0.0
        )
        key_horizontal = max(-1.0, min(1.0, arrow_horizontal + ad_horizontal))
        key_vertical = (1.0 if _pressed(pygame.K_DOWN) or _pressed(pygame.K_s) else 0.0) - (
            1.0 if _pressed(pygame.K_UP) or _pressed(pygame.K_w) else 0.0
        )

        horizontal = 0.0
        vertical = 0.0
        mode = str(control_mode).strip().lower()
        explicit_primary_horizontal = self._app.has_explicit_axis_role_binding("primary_horizontal")
        explicit_primary_vertical = self._app.has_explicit_axis_role_binding("primary_vertical")
        explicit_rudder_horizontal = self._app.has_explicit_axis_role_binding("rudder_horizontal")
        joysticks = _iter_connected_joysticks()
        primary = joysticks[0] if joysticks else None
        primary_axis_count = int(primary.get_numaxes()) if primary is not None else 0

        if explicit_primary_vertical:
            vertical = float(self._app.bound_axis_role_value("primary_vertical") or 0.0)
        elif primary is not None and primary_axis_count > 1:
            vertical = float(self._calibrated_joystick_axis_value(primary, 1) or 0.0)

        if mode == "joystick_only":
            if explicit_primary_horizontal:
                horizontal = float(self._app.bound_axis_role_value("primary_horizontal") or 0.0)
            elif primary is not None and primary_axis_count > 0:
                horizontal = float(self._calibrated_joystick_axis_value(primary, 0) or 0.0)
        else:
            if explicit_rudder_horizontal:
                horizontal = float(self._app.bound_axis_role_value("rudder_horizontal") or 0.0)
            elif primary is not None:
                rudder_value: float | None = None

                # Prefer a separate rudder pedal device by name.
                for device in joysticks:
                    name = str(device.get_name()).lower()
                    if "rudder" not in name and "pedal" not in name:
                        continue
                    device_axis_count = int(device.get_numaxes())
                    if device_axis_count <= 0:
                        continue
                    # Prefer axis 3 for rudder first, then alternate common pedal axes.
                    preferred_indices = (3, 2, 0, 1)
                    for idx in preferred_indices:
                        if idx < device_axis_count:
                            rudder_value = self._calibrated_joystick_axis_value(device, idx)
                            break
                    if rudder_value is not None:
                        break

                # Fallback to primary stick rudder-related axes.
                if rudder_value is None:
                    for idx in (3, 4, 5, 2, 1, 0):
                        if idx < primary_axis_count:
                            rudder_value = self._calibrated_joystick_axis_value(primary, idx)
                            break

                horizontal = 0.0 if rudder_value is None else rudder_value

        if allow_keyboard_fallback:
            out_horizontal = key_horizontal if abs(key_horizontal) > 0.001 else horizontal
            out_vertical = key_vertical if abs(key_vertical) > 0.001 else vertical
        else:
            out_horizontal = horizontal
            out_vertical = vertical
        focus = str(axis_focus).strip().lower()
        if focus == "horizontal":
            out_vertical = 0.0
        elif focus == "vertical":
            out_horizontal = 0.0
        return (
            max(-1.0, min(1.0, out_horizontal)),
            max(-1.0, min(1.0, out_vertical)),
        )

    def _render_sensory_motor_apparatus_screen(
        self,
        surface: pygame.Surface,
        snap: TestSnapshot,
        payload: SensoryMotorApparatusPayload | None,
    ) -> None:
        w, h = surface.get_size()
        bg = (4, 10, 74)
        panel_bg = (7, 16, 99)
        border = (226, 236, 255)
        text_main = (238, 245, 255)
        text_muted = (188, 204, 228)
        accent = (255, 52, 70)

        surface.fill(bg)
        frame = pygame.Rect(10, 10, w - 20, h - 20)
        pygame.draw.rect(surface, panel_bg, frame)
        pygame.draw.rect(surface, border, frame, 2)

        header = pygame.Rect(frame.x + 2, frame.y + 2, frame.w - 4, 42)
        pygame.draw.rect(surface, (16, 28, 118), header)
        pygame.draw.line(
            surface, border, (header.x, header.bottom), (header.right, header.bottom), 1
        )

        if snap.phase is Phase.PRACTICE_DONE:
            if payload is None:
                phase_label = "Timed Test Ready"
            elif payload.block_kind == "scored" and snap.attempted_scored > 0:
                phase_label = "Timed Segment Complete"
            else:
                phase_label = "Practice Complete"
        else:
            phase_label = {
                Phase.INSTRUCTIONS: "Instructions",
                Phase.PRACTICE: "Practice",
                Phase.SCORED: "Timed Test",
                Phase.RESULTS: "Results",
            }.get(snap.phase, "Task")
        title_text = f"Sensory Motor Apparatus - {phase_label}"
        title = self._small_font.render(title_text, True, text_main)
        surface.blit(title, (header.x + 12, header.y + 8))

        if payload is not None and payload.segment_label.strip():
            segment_line = self._tiny_font.render(payload.segment_label, True, text_muted)
            surface.blit(segment_line, (header.x + 12, header.y + 24))

        if runtime_visible_timers_enabled() and snap.time_remaining_s is not None:
            rem = int(round(snap.time_remaining_s))
            mm = rem // 60
            ss = rem % 60
            timer = self._small_font.render(f"{mm:02d}:{ss:02d}", True, text_main)
            surface.blit(timer, timer.get_rect(topright=(frame.right - 12, header.bottom + 6)))
            if (
                runtime_visible_timers_enabled()
                and payload is not None
                and payload.segment_total > 1
            ):
                seg_rem = int(round(payload.segment_time_remaining_s))
                seg_mm = seg_rem // 60
                seg_ss = seg_rem % 60
                segment_timer = self._tiny_font.render(
                    f"Segment {seg_mm:02d}:{seg_ss:02d}",
                    True,
                    text_muted,
                )
                surface.blit(
                    segment_timer,
                    segment_timer.get_rect(topright=(frame.right - 12, header.bottom + 26)),
                )

        body = pygame.Rect(
            frame.x + 8,
            header.bottom + 8,
            frame.w - 16,
            frame.bottom - header.bottom - 44,
        )
        track_margin = max(4, min(10, min(body.w, body.h) // 60))
        track = body.inflate(-track_margin * 2, -track_margin * 2)

        pygame.draw.rect(surface, (0, 0, 0), track)
        pygame.draw.rect(surface, (96, 108, 140), track, 1)

        cx = track.centerx
        cy = track.centery
        if payload is not None and payload.axis_focus != "both" and payload.guide_band_half_width > 0.0:
            x_scale = (track.w // 2) - 12
            y_scale = (track.h // 2) - 12
            band_alpha = pygame.Surface(track.size, pygame.SRCALPHA)
            if payload.axis_focus == "horizontal":
                band_half = max(6, int(round(payload.guide_band_half_width * y_scale)))
                pygame.draw.rect(
                    band_alpha,
                    (84, 182, 255, 34),
                    pygame.Rect(0, (track.h // 2) - band_half, track.w, band_half * 2),
                )
            else:
                band_half = max(6, int(round(payload.guide_band_half_width * x_scale)))
                pygame.draw.rect(
                    band_alpha,
                    (84, 182, 255, 34),
                    pygame.Rect((track.w // 2) - band_half, 0, band_half * 2, track.h),
                )
            surface.blit(band_alpha, track.topleft)

        line_len = max(18, min(track.w, track.h) // 14)
        pygame.draw.line(surface, accent, (cx - line_len, cy), (cx + line_len, cy), 2)
        pygame.draw.line(surface, accent, (cx, cy - line_len), (cx, cy + line_len), 2)

        if payload is not None:
            x_scale = (track.w // 2) - 12
            y_scale = (track.h // 2) - 12
            dot_x = int(round(cx + (payload.dot_x * x_scale)))
            dot_y = int(round(cy + (payload.dot_y * y_scale)))
            radius = max(4, min(9, track.w // 34))
            pygame.draw.circle(surface, accent, (dot_x, dot_y), radius)

        if payload is not None:
            metrics_bg = pygame.Rect(track.x + 8, track.y + 8, track.w - 16, 24)
            pygame.draw.rect(surface, (8, 18, 104), metrics_bg)
            pygame.draw.rect(surface, (78, 102, 170), metrics_bg, 1)
            on_target_pct = payload.on_target_ratio * 100.0
            left_text = self._tiny_font.render(
                f"Err {payload.mean_error:.3f}  RMS {payload.rms_error:.3f}  "
                f"On {on_target_pct:.1f}%",
                True,
                text_main,
            )
            right_text = self._tiny_font.render(
                f"Ctrl {payload.control_x:+.2f},{payload.control_y:+.2f}  "
                f"Drift {payload.disturbance_x:+.2f},{payload.disturbance_y:+.2f}",
                True,
                text_muted,
            )
            surface.blit(left_text, (metrics_bg.x + 8, metrics_bg.y + 4))
            surface.blit(
                right_text,
                right_text.get_rect(midright=(metrics_bg.right - 8, metrics_bg.centery)),
            )

        if snap.phase in (Phase.INSTRUCTIONS, Phase.PRACTICE_DONE, Phase.RESULTS):
            prompt_bg = pygame.Rect(track.x + 10, track.bottom - 92, track.w - 20, 82)
            pygame.draw.rect(surface, (8, 18, 104), prompt_bg)
            pygame.draw.rect(surface, (78, 102, 170), prompt_bg, 1)
            self._draw_wrapped_text(
                surface,
                str(snap.prompt),
                prompt_bg.inflate(-10, -8),
                color=text_muted,
                font=self._tiny_font,
                max_lines=6,
            )

        if snap.phase is Phase.INSTRUCTIONS:
            footer = "Enter: Continue  |  Esc/Backspace: Pause"
        elif snap.phase is Phase.PRACTICE_DONE:
            if payload is None:
                footer = "Enter: Begin Timed Test  |  Esc/Backspace: Pause"
            elif payload.block_kind == "scored":
                if snap.attempted_scored > 0:
                    footer = "Enter: Continue Timed Test  |  Esc/Backspace: Pause"
                else:
                    footer = "Enter: Begin Timed Test  |  Esc/Backspace: Pause"
            else:
                footer = "Enter: Continue  |  Esc/Backspace: Pause"
        elif snap.phase in (Phase.PRACTICE, Phase.SCORED):
            if payload is not None and payload.control_mode == "joystick_only":
                footer = "Joystick X controls left/right; joystick axis 1 controls up/down."
            else:
                footer = "Rudder controls left/right; joystick axis 1 controls up/down."
            if payload is not None and payload.axis_focus == "horizontal":
                footer = f"{footer} Vertical input ignored."
            elif payload is not None and payload.axis_focus == "vertical":
                footer = f"{footer} Horizontal input ignored."
            footer = f"{footer}  |  Esc/Backspace: Pause"
        else:
            footer = "Enter: Return to Tests  |  Esc/Backspace: Pause"
        foot = self._tiny_font.render(footer, True, text_muted)
        surface.blit(foot, foot.get_rect(midbottom=(frame.centerx, frame.bottom - 10)))

    def _render_rapid_tracking_panda_view(
        self,
        *,
        surface: pygame.Surface,
        world: pygame.Rect,
        payload: RapidTrackingPayload | None,
        renderer: RapidTrackingPanda3DRenderer,
        active_phase: bool,
    ) -> bool:
        try:
            view = renderer.render(payload=payload)
        except Exception as exc:
            detail = str(exc).strip()
            suffix = f": {detail}" if detail else ""
            self._fail_scene_panda_requirement(
                "rapid_tracking",
                scene_label="Rapid Tracking",
                category="renderer_render_failed",
                summary=f"Panda3D renderer failed while drawing Rapid Tracking with {type(exc).__name__}{suffix}",
            )
            return False

        if view.get_size() != world.size:
            view = pygame.transform.smoothscale(view, world.size)
        surface.blit(view, world.topleft)

        vignette = pygame.Surface(world.size, pygame.SRCALPHA)
        pygame.draw.rect(vignette, (4, 10, 8, 42), vignette.get_rect(), 14)
        surface.blit(vignette, world.topleft)

        if active_phase:
            edge_alpha = 24 + int(round(12.0 * (0.5 + (0.5 * math.sin(pygame.time.get_ticks() / 160.0)))))
            left_band = pygame.Surface((16, world.h), pygame.SRCALPHA)
            right_band = pygame.Surface((16, world.h), pygame.SRCALPHA)
            left_band.fill((68, 194, 156, edge_alpha))
            right_band.fill((196, 130, 74, edge_alpha))
            surface.blit(left_band, (world.x, world.y))
            surface.blit(right_band, (world.right - 16, world.y))

        return True

